window.ROLLCALL_DATA = {"gameName": "Yea or Nay", "epoch": "2026-07-08", "puzzles": [{"id": "obama-wave", "title": "The Obama Wave", "era": "111th Congress \u00b7 2009\u20132010", "intro": "Barack Obama arrives with a filibuster-proof majority, a financial crisis on every desk, and an agenda the size of the New Deal. Every big vote comes down to a handful of independent minds.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "A Maine moderate and one of the last New England Republicans. She prides herself on bipartisan deal-making \u2014 she helped write down the 2009 stimulus \u2014 but guards her independence on social issues.", "photo": "photos/C001035.jpg"}, {"key": "bnelson", "name": "Ben Nelson", "party": "D", "state": "NE", "blurb": "Perhaps the most conservative Democrat in the chamber, from deep-red Nebraska. He haggles for home-state concessions and agonizes publicly before every big vote.", "photo": "photos/N000180.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "The Senate's democratic socialist, caucusing with Democrats under his own flag. He wants Medicare-for-all and blames Wall Street for most of America's ills \u2014 the question is whether half-measures earn his vote.", "photo": "photos/S000033.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "Fresh off losing the presidency to Obama, the old maverick has turned partisan brawler, opposing most of the new administration's agenda while keeping his hawkish, reform-minded reputation.", "photo": "photos/M000303.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "A civil-libertarian progressive from Wisconsin who treats principle as non-negotiable. He'll vote against his own party when a bill doesn't go far enough, and he's famous for casting lonely no votes.", "photo": "photos/F000061.jpg"}], "bills": [{"name": "The Affordable Care Act", "desc": "December 24, 2009, 7 a.m. \u2014 the Senate's first Christmas Eve vote in 114 years. Obama's health-care overhaul: an individual mandate to buy insurance, subsidized exchanges, a Medicaid expansion, and a ban on denying coverage for pre-existing conditions. After a year of town-hall fury, Democrats need all 60 caucus votes to break the filibuster.", "votes": {"collins": "nay", "bnelson": "yea", "sanders": "yea", "mccain": "nay", "feingold": "yea"}, "notes": {}, "date": "December 24, 2009", "question": "On Passage of the Bill H.R. 3590", "result": "Bill Passed", "yeas": 60, "nays": 39}, {"name": "Dodd-Frank Wall Street Reform", "desc": "July 2010. The answer to the financial crisis: a new consumer-protection bureau, derivatives regulation, and authority to wind down 'too big to fail' banks. Wall Street hates it \u2014 and some progressives say it's still far too soft on the megabanks.", "votes": {"collins": "yea", "bnelson": "yea", "sanders": "yea", "mccain": "nay", "feingold": "nay"}, "notes": {}, "date": "July 15, 2010", "question": "On the Conference Report H.R. 4173", "result": "Conference Report Agreed to", "yeas": 60, "nays": 39}, {"name": "Repeal of Don't Ask, Don't Tell", "desc": "December 2010, the lame-duck session. A standalone bill to end the 17-year ban on gay and lesbian troops serving openly, after a Pentagon study found repeal would not harm military readiness.", "votes": {"collins": "yea", "bnelson": "yea", "sanders": "yea", "mccain": "nay", "feingold": "yea"}, "notes": {}, "date": "December 18, 2010", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.R. 2965)", "result": "Motion Agreed to", "yeas": 65, "nays": 31}]}, {"id": "after-september", "title": "After September 11", "era": "107th Congress \u00b7 2001\u20132002", "intro": "Anthrax in the mailroom, troops mobilizing, flags on every lapel. A Senate under pressure to move fast \u2014 on surveillance, on schools, and finally on war.", "senators": [{"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "Wisconsin's civil-libertarian conscience \u2014 deeply skeptical of government surveillance and of blank-check war powers, even when the whole country is demanding action.", "photo": "photos/F000061.jpg"}, {"key": "clinton", "name": "Hillary Clinton", "party": "D", "state": "NY", "blurb": "The former First Lady, ten months into her Senate career, representing the state that was attacked. She is building a hawkish, centrist national-security profile \u2014 with an eye, everyone assumes, on bigger things.", "photo": "photos/C001041.jpg"}, {"key": "chafee", "name": "Lincoln Chafee", "party": "R", "state": "RI", "blurb": "The Senate's most liberal Republican, an heir to Yankee moderation. He regularly opposes his own party on taxes, the environment, and the use of force.", "photo": "photos/C001040.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Senate's octogenarian institutionalist, a copy of the Constitution in his breast pocket. He defends Congress's war powers against any president, of either party.", "photo": "photos/B001210.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal lion. A master legislator happy to partner with George W. Bush on domestic causes he cares about \u2014 education above all \u2014 while fighting him on nearly everything else.", "photo": "photos/K000105.jpg"}], "bills": [{"name": "The USA PATRIOT Act", "desc": "October 25, 2001 \u2014 six weeks after the attacks. Sweeping new surveillance powers: roving wiretaps, expanded FISA authority, 'sneak and peek' searches, and government access to business records. It is moving so fast that most senators admit they haven't read it.", "votes": {"feingold": "nay", "clinton": "yea", "chafee": "yea", "byrd": "yea", "kennedy": "yea"}, "notes": {}, "date": "October 25, 2001", "question": "On Passage of the Bill H.R. 3162", "result": "Bill Passed", "yeas": 98, "nays": 1}, {"name": "No Child Left Behind", "desc": "December 2001. Bush's signature education law: annual testing, public school report cards, and consequences for failing schools \u2014 negotiated hand-in-hand with leading Democrats and paired with a big increase in federal education spending.", "votes": {"feingold": "nay", "clinton": "yea", "chafee": "yea", "byrd": "yea", "kennedy": "yea"}, "notes": {}, "date": "December 18, 2001", "question": "On the Conference Report H.R. 1", "result": "Conference Report Agreed to", "yeas": 87, "nays": 10}, {"name": "Authorization for War in Iraq", "desc": "October 11, 2002, three weeks before the midterms. The resolution authorizes the President to use the Armed Forces against Saddam Hussein's Iraq at a time of his choosing. Intelligence about weapons of mass destruction is everywhere. So are doubts.", "votes": {"feingold": "nay", "clinton": "yea", "chafee": "nay", "byrd": "nay", "kennedy": "nay"}, "notes": {}, "date": "October 11, 2002", "question": "On the Joint Resolution H.J.Res. 114", "result": "Joint Resolution Passed", "yeas": 77, "nays": 23}]}, {"id": "class-of-2008", "title": "The Class of 2008", "era": "110th Congress \u00b7 2007\u20132008", "intro": "Five senators \u2014 four of whom want the same promotion. Watch how a presidential campaign, and then a financial collapse, shapes a voting record.", "senators": [{"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The freshman phenomenon, running on his early opposition to the Iraq war. Cautious and consensus-minded on most everything else \u2014 he can't afford a vote that reads as radical.", "photo": "photos/O000167.jpg"}, {"key": "clinton", "name": "Hillary Clinton", "party": "D", "state": "NY", "blurb": "The frontrunner, defending the hawkish national-security record she built after 9/11 while a primary electorate pulls her left.", "photo": "photos/C001041.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The Republican nominee-in-waiting: a national-security hawk and deficit scold with a history of party apostasy he's currently trying to live down.", "photo": "photos/M000303.jpg"}, {"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "Chairman of Foreign Relations, blue-collar Democrat from Delaware, long-shot candidate running on judgment and experience.", "photo": "photos/B000444.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "The freshman socialist, not running for anything \u2014 yet. Economics first, and no patience for rescuing the people he blames for the mess.", "photo": "photos/S000033.jpg"}], "bills": [{"name": "Minimum Wage Increase", "desc": "February 2007. The new Democratic majority's first order of business: raising the federal minimum wage from $5.15 to $7.25 over two years, sweetened with small-business tax breaks to bring Republicans along.", "votes": {"obama": "yea", "clinton": "yea", "mccain": "yea", "biden": "yea", "sanders": "yea"}, "notes": {}, "date": "February 1, 2007", "question": "On Passage of the Bill H.R. 2", "result": "Bill Passed", "yeas": 94, "nays": 3}, {"name": "Iraq War Funding \u2014 No Timeline", "desc": "May 24, 2007. Bush has just vetoed a war-funding bill because it included a withdrawal timeline. This is the replacement: $95 billion for the troops with the timeline stripped out. Anti-war groups call voting yes a capitulation; opponents of the bill are accused of defunding troops in the field.", "votes": {"obama": "nay", "clinton": "nay", "mccain": "yea", "biden": "yea", "sanders": "nay"}, "notes": {}, "date": "May 24, 2007", "question": "On the Motion (Motion to Concur in House Amdt. to Senate Amdt to H.R.2206)", "result": "Motion Agreed to", "yeas": 80, "nays": 14}, {"name": "The $700B Bank Bailout (TARP)", "desc": "October 1, 2008. Lehman is dead, credit is frozen, and the Treasury Secretary wants $700 billion to rescue the banking system. Both presidential nominees fly back to Washington for the vote. Main Street is furious.", "votes": {"obama": "yea", "clinton": "yea", "mccain": "yea", "biden": "yea", "sanders": "nay"}, "notes": {}, "date": "October 1, 2008", "question": "On Passage of the Bill H.R. 1424", "result": "Bill Passed", "yeas": 74, "nays": 25}]}, {"id": "guns-and-borders", "title": "Guns & Borders", "era": "113th Congress \u00b7 2013", "intro": "After Sandy Hook, and after an election Republicans lost badly with Hispanic voters, the Senate attempts guns and immigration in one year \u2014 then shuts the government down arguing about health care.", "senators": [{"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "A gun-owning, coal-country Democrat from a state Obama just lost by 27 points. He holds an NRA 'A' rating and protects his centrist brand fiercely \u2014 but Sandy Hook shook him.", "photo": "photos/M001183.jpg"}, {"key": "toomey", "name": "Pat Toomey", "party": "R", "state": "PA", "blurb": "A former Club for Growth president \u2014 about as fiscally conservative as they come \u2014 now representing purple Pennsylvania, which expects the occasional pragmatic turn.", "photo": "photos/T000461.jpg"}, {"key": "cruz", "name": "Ted Cruz", "party": "R", "state": "TX", "blurb": "Three months into his first term and already the Senate's chief insurgent. He came to Washington to fight the establishments of both parties, not to make deals.", "photo": "photos/C001098.jpg"}, {"key": "warren", "name": "Elizabeth Warren", "party": "D", "state": "MA", "blurb": "The consumer-protection professor turned senator \u2014 the new standard-bearer of the party's progressive wing.", "photo": "photos/W000817.jpg"}, {"key": "kirk", "name": "Mark Kirk", "party": "R", "state": "IL", "blurb": "A moderate, socially liberal Republican from deep-blue Illinois, recently back from a stroke, facing voters who just backed Obama twice.", "photo": "photos/K000360.jpg"}], "bills": [{"name": "Manchin-Toomey Background Checks", "desc": "April 17, 2013 \u2014 four months after Sandy Hook. A bipartisan compromise extending background checks to gun shows and internet sales, far short of an assault-weapons ban, polling near 90% support. Under the deal in force, it needs 60 votes.", "votes": {"manchin": "yea", "toomey": "yea", "cruz": "nay", "warren": "yea", "kirk": "yea"}, "notes": {}, "date": "April 17, 2013", "question": "On the Amendment S.Amdt. 715 to S. 649 (Safe Communities, Safe Schools Act of2013)", "result": "Amendment Rejected", "yeas": 54, "nays": 46}, {"name": "The Gang of Eight Immigration Bill", "desc": "June 2013. Comprehensive immigration reform: a 13-year path to citizenship for 11 million undocumented immigrants, a doubling of the Border Patrol, 700 miles of fencing, and mandatory E-Verify.", "votes": {"manchin": "yea", "toomey": "nay", "cruz": "nay", "warren": "yea", "kirk": "yea"}, "notes": {}, "date": "June 27, 2013", "question": "On Passage of the Bill S. 744", "result": "Bill Passed", "yeas": 68, "nays": 32}, {"name": "Reopening the Government", "desc": "October 16, 2013 \u2014 day 16 of the shutdown, hours from a debt default. The deal reopens the government and raises the debt ceiling with essentially nothing given to the defund-Obamacare campaign that started it.", "votes": {"manchin": "yea", "toomey": "nay", "cruz": "nay", "warren": "yea", "kirk": "yea"}, "notes": {}, "date": "October 16, 2013", "question": "On Passage of the Bill H.R. 2775", "result": "Bill Passed", "yeas": 81, "nays": 18}]}, {"id": "fifty-one-forty-nine", "title": "Three Votes to Lose", "era": "115th Congress \u00b7 2017\u20132018", "intro": "Unified Republican government and a razor-thin Senate. With almost no margin for error, every landmark vote hangs on a handful of senators who answer to no one.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Twenty years in, the chamber's definitive swing vote: pro-choice, deficit-conscious, protective of Maine's rural hospitals, and increasingly willing to buck her party's new president.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's senator owes her seat to a write-in campaign, not the party \u2014 she once lost her own primary and won anyway. Energy development and Alaska's native healthcare systems outrank party loyalty.", "photo": "photos/M001153.jpg"}, {"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "Still the reddest-state Democrat, now facing re-election in a state Trump carried by 42 points. He votes with the President more than any other Democrat \u2014 when he thinks West Virginia wants it.", "photo": "photos/M001183.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "The libertarian: wants government out of health care, taxes near zero, and deficits actually shrinking. Happily votes against Republican bills for being insufficiently conservative.", "photo": "photos/P000603.jpg"}, {"key": "heitkamp", "name": "Heidi Heitkamp", "party": "D", "state": "ND", "blurb": "A North Dakota Democrat holding the Senate's most endangered seat, balancing her party's base against a state Trump won by 36. Every vote is a re-election calculation.", "photo": "photos/H001069.jpg"}], "bills": [{"name": "'Skinny' Obamacare Repeal", "desc": "July 28, 2017, 1:30 a.m. After full repeal has already failed, Republicans try 'skinny repeal' \u2014 killing the individual mandate and a few taxes \u2014 as a vehicle to keep the repeal effort alive in conference. Leadership swears it will never become law as written. Fifty votes will do it, and the floor is thick with rumors.", "votes": {"collins": "nay", "murkowski": "nay", "manchin": "nay", "rpaul": "yea", "heitkamp": "nay"}, "notes": {}, "date": "July 28, 2017", "question": "On the Amendment S.Amdt. 667 to S.Amdt. 267 to H.R. 1628 (American Health Care Act of 2017)", "result": "Amendment Rejected", "yeas": 49, "nays": 51}, {"name": "The Trump Tax Cuts", "desc": "December 2, 2017, nearly 2 a.m. The Tax Cuts and Jobs Act: the corporate rate slashed from 35% to 20%, individual cuts that expire after 2025, the ACA's mandate penalty zeroed out, and roughly $1.4 trillion added to the deficit. Handwritten amendments are still being scribbled in the margins.", "votes": {"collins": "yea", "murkowski": "yea", "manchin": "nay", "rpaul": "yea", "heitkamp": "nay"}, "notes": {}, "date": "December 2, 2017", "question": "On Passage of the Bill H.R. 1", "result": "Bill Passed", "yeas": 51, "nays": 49}, {"name": "Confirming Brett Kavanaugh", "desc": "October 6, 2018. After Christine Blasey Ford's testimony and a supplemental FBI investigation, the Supreme Court confirmation comes to the floor with the chamber \u2014 and the country \u2014 at a boil. A simple majority confirms.", "votes": {"collins": "yea", "murkowski": "nay", "manchin": "yea", "rpaul": "yea", "heitkamp": "nay"}, "notes": {"murkowski": "Murkowski's declared vote was No. She withdrew it and voted 'present' as a courtesy 'live pair' with Steve Daines (R-MT), a Kavanaugh supporter away at his daughter's wedding \u2014 old Senate custom, same effect as a Nay."}, "date": "October 6, 2018", "question": "On the Nomination PN2259", "result": "Nomination Confirmed", "yeas": 50, "nays": 48}]}, {"id": "clinton-years", "title": "November 1993", "era": "103rd Congress \u00b7 1993", "intro": "A young President Clinton, a Democratic Congress full of Southern conservatives, and one extraordinary week in November: trade, guns, and crime, back to back.", "senators": [{"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "Two decades in, chairman of the Judiciary Committee: a deal-making Delaware Democrat, tough-on-crime by design and trade-friendly by instinct.", "photo": "photos/B000444.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Appropriations king and guardian of West Virginia's mines and mills. Suspicious of anything that might ship jobs overseas; devoted to the working man as he defines him.", "photo": "photos/B001210.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "An Arizona conservative with a westerner's view of government: pro-trade, pro-military, and as skeptical of gun laws as his voters are.", "photo": "photos/M000303.jpg"}, {"key": "feinstein", "name": "Dianne Feinstein", "party": "D", "state": "CA", "blurb": "San Francisco's former mayor, in the Senate less than a year. She became mayor the day a colleague was assassinated at City Hall \u2014 gun violence is personal, and she has chosen it as her first great fight.", "photo": "photos/F000062.jpg"}, {"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "'Senator No.' The hard-right anchor of the chamber: anti-communist, protectionist where tobacco and textiles are concerned, and against nearly anything with 'new' in the name.", "photo": "photos/H000463.jpg"}], "bills": [{"name": "The Assault Weapons Ban", "desc": "November 17, 1993. An amendment to the crime bill banning the manufacture of 19 named semiautomatic 'assault weapons' and high-capacity magazines for ten years. Even many Democrats from rural states are queasy.", "votes": {"biden": "yea", "byrd": "yea", "mccain": "nay", "feinstein": "yea", "helms": "nay"}, "notes": {}, "date": "November 17, 1993", "question": "On the Amendment S.Amdt. 1152 to S.Amdt. 1151 to S. 1607 (Violent Crime Control and Law Enforcement Act of 1993)", "result": "Amendment Agreed to", "yeas": 56, "nays": 43}, {"name": "The Brady Bill", "desc": "November 20, 1993. A five-day waiting period and background check for handgun purchases, named for Reagan's press secretary, shot and paralyzed in 1981. The NRA has fought it for seven years straight.", "votes": {"biden": "yea", "byrd": "yea", "mccain": "nay", "feinstein": "yea", "helms": "nay"}, "notes": {}, "date": "November 20, 1993", "question": "On Passage of the Bill H.R. 1025", "result": "Bill Passed", "yeas": 63, "nays": 36}, {"name": "NAFTA", "desc": "Also November 20, 1993. The North American Free Trade Agreement \u2014 negotiated by Bush, embraced by Clinton over his own party's objections and organized labor's fury. Ross Perot says you can already hear a 'giant sucking sound' of jobs going south.", "votes": {"biden": "yea", "byrd": "nay", "mccain": "yea", "feinstein": "nay", "helms": "nay"}, "notes": {}, "date": "November 20, 1993", "question": "On Passage of the Bill H.R. 3450", "result": "Bill Passed", "yeas": 61, "nays": 38}]}, {"id": "line-in-the-sand", "title": "Line in the Sand", "era": "102nd Congress \u00b7 1991", "intro": "Half a million American troops sit in the Saudi desert while Congress holds its first real war debate since Vietnam. Nine months later, a Supreme Court nomination ends in the most explosive hearings ever held.", "senators": [{"key": "gore", "name": "Al Gore", "party": "D", "state": "TN", "blurb": "A cerebral Tennessee moderate with presidential ambitions and a hawkish streak rare in his party's rising generation. He agonizes over big votes \u2014 and enjoys telling you so.", "photo": "photos/G000321.jpg"}, {"key": "nunn", "name": "Sam Nunn", "party": "D", "state": "GA", "blurb": "Chairman of Armed Services and the Democrats' most trusted voice on the military. A Georgia conservative \u2014 but a believer that sanctions and patience can win wars cheaper than blood.", "photo": "photos/N000171.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Republican leader: a wounded World War II veteran, sharp-tongued dealmaker, and reliable soldier for the Bush White House.", "photo": "photos/D000401.jpg"}, {"key": "kerry", "name": "John Kerry", "party": "D", "state": "MA", "blurb": "A decorated Vietnam veteran who came home to protest the war. Two decades later, deeply wary of committing American troops before every alternative is exhausted.", "photo": "photos/K000148.jpg"}, {"key": "kassebaum", "name": "Nancy Kassebaum", "party": "R", "state": "KS", "blurb": "A plainspoken Kansas internationalist, budget-minded and independent \u2014 one of only two women in the chamber.", "photo": "photos/K000017.jpg"}], "bills": [{"name": "Authorizing the Gulf War", "desc": "January 12, 1991. Saddam Hussein has occupied Kuwait for five months, and the UN deadline expires in three days. The resolution authorizes the President to drive Iraq out by force. The debate is somber and the outcome genuinely in doubt \u2014 the closest vote to authorize war in American history.", "votes": {"gore": "yea", "nunn": "nay", "dole": "yea", "kerry": "nay", "kassebaum": "yea"}, "notes": {}, "date": "January 12, 1991", "question": "On the Joint Resolution S.J.Res. 2", "result": "Joint Resolution Passed", "yeas": 52, "nays": 47}, {"name": "Confirming Clarence Thomas", "desc": "October 15, 1991. Clarence Thomas's Supreme Court nomination reaches the floor days after Anita Hill's testimony transfixed the country. He would fill Thurgood Marshall's seat \u2014 and shift the Court for a generation.", "votes": {"gore": "nay", "nunn": "yea", "dole": "yea", "kerry": "nay", "kassebaum": "yea"}, "notes": {}, "date": "October 15, 1991", "question": "On the Nomination PN456", "result": "Nomination Confirmed", "yeas": 52, "nays": 48}, {"name": "The Civil Rights Act of 1991", "desc": "October 30, 1991. After two years of veto fights over 'quotas,' a compromise civil-rights bill restoring workers' power to sue for discrimination \u2014 finally pre-cleared with the White House.", "votes": {"gore": "yea", "nunn": "yea", "dole": "yea", "kerry": "yea", "kassebaum": "yea"}, "notes": {}, "date": "October 30, 1991", "question": "On Passage of the Bill S. 1745", "result": "Bill Passed", "yeas": 93, "nays": 5}]}, {"id": "republican-revolution", "title": "The Republican Revolution", "era": "104th Congress \u00b7 1996", "intro": "Two years after Gingrich's landslide, a Democratic president runs toward the center with an election looming. Welfare, marriage, wages \u2014 1996 is one long argument about what the parties are for.", "senators": [{"key": "moynihan", "name": "Daniel Patrick Moynihan", "party": "D", "state": "NY", "blurb": "The Senate's scholar \u2014 a Harvard sociologist who wrote the book on poverty policy, literally. Party loyalty means little when he believes a bill will hurt the poor.", "photo": "photos/M001054.jpg"}, {"key": "lieberman", "name": "Joe Lieberman", "party": "D", "state": "CT", "blurb": "A moralist Connecticut Democrat comfortable scolding his own party: pro-business, hawkish, and outspoken about family values.", "photo": "photos/L000304.jpg"}, {"key": "boxer", "name": "Barbara Boxer", "party": "D", "state": "CA", "blurb": "A Marin County liberal and one of the chamber's most reliable progressive votes, especially where civil rights are concerned.", "photo": "photos/B000711.jpg"}, {"key": "santorum", "name": "Rick Santorum", "party": "R", "state": "PA", "blurb": "The youngest Republican senator: a combative Pennsylvania culture warrior who courts blue-collar Catholics with the occasional populist economic vote.", "photo": "photos/S000059.jpg"}, {"key": "gramm", "name": "Phil Gramm", "party": "R", "state": "TX", "blurb": "A Texas economics professor turned budget hawk, fresh off a presidential run about slashing government. If a bill spends money or regulates business, count him out.", "photo": "photos/G000365.jpg"}], "bills": [{"name": "Welfare Reform", "desc": "August 1, 1996. 'The end of welfare as we know it': time limits, work requirements, and block grants replacing a six-decade federal guarantee for poor families. Clinton has vetoed two versions and promised to sign this one. Half his party feels betrayed.", "votes": {"moynihan": "nay", "lieberman": "yea", "boxer": "nay", "santorum": "yea", "gramm": "yea"}, "notes": {}, "date": "August 1, 1996", "question": "On the Conference Report H.R. 3734", "result": "Conference Report Agreed to", "yeas": 78, "nays": 21}, {"name": "The Defense of Marriage Act", "desc": "September 10, 1996. DOMA: no federal recognition of same-sex marriages, and no state required to honor another state's. Clinton says he'll sign it. Only a handful of senators are willing to be counted against it.", "votes": {"moynihan": "nay", "lieberman": "yea", "boxer": "nay", "santorum": "yea", "gramm": "yea"}, "notes": {}, "date": "September 10, 1996", "question": "On Passage of the Bill H.R. 3396", "result": "Bill Passed", "yeas": 85, "nays": 14}, {"name": "Minimum Wage Increase", "desc": "July 9, 1996. A 90-cent raise in the minimum wage \u2014 $4.25 to $5.15 \u2014 riding on a package of small-business tax breaks. Election-year pressure has cracked the Republican leadership's resistance.", "votes": {"moynihan": "yea", "lieberman": "yea", "boxer": "yea", "santorum": "yea", "gramm": "nay"}, "notes": {}, "date": "July 9, 1996", "question": "On Passage of the Bill H.R. 3448", "result": "Bill Passed", "yeas": 74, "nays": 24}]}, {"id": "america-and-the-world", "title": "America & the World", "era": "105th\u2013106th Congress \u00b7 1997\u20132000", "intro": "With the Cold War won, Washington argues about what comes next: disarmament treaties, an expanding NATO, and whether to bet the future on trade with China.", "senators": [{"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "Chairman of Foreign Relations and scourge of the striped-pants set. Treaties, foreign aid, the UN \u2014 he distrusts them all, and buries what he distrusts.", "photo": "photos/H000463.jpg"}, {"key": "lugar", "name": "Richard Lugar", "party": "R", "state": "IN", "blurb": "The Republicans' soft-spoken foreign-policy intellectual, co-author of the program dismantling loose Soviet nukes. An internationalist to his fingertips.", "photo": "photos/L000504.jpg"}, {"key": "moynihan", "name": "Daniel Patrick Moynihan", "party": "D", "state": "NY", "blurb": "The Senate's contrarian scholar \u2014 a former UN ambassador with his own theories about secrecy, ethnicity, and international law, cheerfully immune to conventional wisdom.", "photo": "photos/M001054.jpg"}, {"key": "wellstone", "name": "Paul Wellstone", "party": "D", "state": "MN", "blurb": "The happiest warrior of the left: a former wrestling coach and campus organizer who votes his conscience on labor and human rights, popularity be damned.", "photo": "photos/W000288.jpg"}, {"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "The Democrats' garrulous front man on Foreign Relations \u2014 an institutionalist who believes in American alliances and American engagement, almost anywhere.", "photo": "photos/B000444.jpg"}], "bills": [{"name": "The Chemical Weapons Treaty", "desc": "April 24, 1997. The Chemical Weapons Convention: a global ban on producing and stockpiling chemical arms, signed by the first President Bush. Ratification needs 67 votes, and conservatives warn it is unverifiable and toothless.", "votes": {"helms": "nay", "lugar": "yea", "moynihan": "yea", "wellstone": "yea", "biden": "yea"}, "notes": {}, "date": "April 24, 1997", "question": "On the Resolution of Ratification S.Res. 75", "result": "Resolution of Ratification Agreed to", "yeas": 74, "nays": 26}, {"name": "Expanding NATO Eastward", "desc": "April 30, 1998. Admitting Poland, Hungary, and the Czech Republic to NATO \u2014 extending America's defense umbrella to Russia's old doorstep. Critics ask what the alliance is now for, and whom it might provoke. Treaties need 67 votes.", "votes": {"helms": "yea", "lugar": "yea", "moynihan": "nay", "wellstone": "nay", "biden": "yea"}, "notes": {}, "date": "April 30, 1998", "question": "On the Resolution of Ratification Treaty Doc. 105-36", "result": "Resolution of Ratification Agreed to", "yeas": 80, "nays": 19}, {"name": "Permanent Trade with China", "desc": "September 19, 2000. Permanent normal trade relations with China, clearing its path into the World Trade Organization. Business is euphoric. Labor and human-rights advocates call it a historic sellout.", "votes": {"helms": "nay", "lugar": "yea", "moynihan": "yea", "wellstone": "nay", "biden": "yea"}, "notes": {}, "date": "September 19, 2000", "question": "On Passage of the Bill H.R. 4444", "result": "Bill Passed", "yeas": 83, "nays": 15}]}, {"id": "bush-majority", "title": "The Bush Majority", "era": "108th Congress \u00b7 2003", "intro": "War in Iraq, tax cuts at home, and a Republican Party at high tide. For Democrats, every vote is a choice between conviction and survival.", "senators": [{"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The maverick restored: hawkish on the war, but a deficit scold who has rediscovered his taste for bucking his own White House on spending.", "photo": "photos/M000303.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "Forty years in and pugnacious as ever \u2014 he calls the Iraq war a 'fraud cooked up in Texas,' while still cutting domestic deals with this White House when it serves his causes.", "photo": "photos/K000105.jpg"}, {"key": "daschle", "name": "Tom Daschle", "party": "D", "state": "SD", "blurb": "The Democratic leader: a soft-spoken South Dakotan balancing a liberal caucus against a state Bush carried by 22 points \u2014 with his own re-election looming.", "photo": "photos/D000064.jpg"}, {"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "Pennsylvania's cranky Republican moderate: pro-choice, pro-labor by his party's standards, and facing a bruising primary from his right next spring.", "photo": "photos/S000709.jpg"}, {"key": "zmiller", "name": "Zell Miller", "party": "D", "state": "GA", "blurb": "A Georgia Democrat in name only by now: he keynoted for Clinton in '92, but has embraced Bush's agenda nearly wholesale \u2014 and relishes infuriating his own party.", "photo": "photos/M001141.jpg"}], "bills": [{"name": "The Partial-Birth Abortion Ban", "desc": "March 13, 2003. A federal ban on the late-term procedure opponents call partial-birth abortion \u2014 the first federal criminal prohibition of an abortion method since Roe, with an exception for the mother's life but not her health.", "votes": {"mccain": "yea", "kennedy": "nay", "daschle": "yea", "specter": "yea", "zmiller": "yea"}, "notes": {}, "date": "March 13, 2003", "question": "On Passage of the Bill S. 3", "result": "Bill Passed", "yeas": 64, "nays": 33}, {"name": "$87 Billion for Iraq", "desc": "October 17, 2003. Eighty-seven billion dollars for the occupations of Iraq and Afghanistan \u2014 six months after 'Mission Accomplished,' with no weapons found and the insurgency growing. Voting no reads as abandoning the troops; voting yes as endorsing the war.", "votes": {"mccain": "yea", "kennedy": "nay", "daschle": "yea", "specter": "yea", "zmiller": "yea"}, "notes": {}, "date": "October 17, 2003", "question": "On Passage of the Bill S. 1689", "result": "Bill Passed", "yeas": 87, "nays": 12}, {"name": "Medicare Prescription Drugs", "desc": "November 25, 2003. The biggest Medicare expansion in history: a prescription-drug benefit delivered through private insurers, with the government barred from negotiating prices. Liberals call it a giveaway to industry; conservatives call it a budget-buster.", "votes": {"mccain": "nay", "kennedy": "nay", "daschle": "nay", "specter": "yea", "zmiller": "yea"}, "notes": {}, "date": "November 25, 2003", "question": "On the Conference Report H.R. 1", "result": "Conference Report Agreed to", "yeas": 54, "nays": 44}]}, {"id": "second-term-blues", "title": "Second-Term Blues", "era": "109th Congress \u00b7 2005\u20132006", "intro": "A re-elected George W. Bush spends his political capital fast: bankruptcy law for the banks, a fence for the border, and military tribunals for the age of terror.", "senators": [{"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The celebrity freshman, two years from announcing for president: a constitutional-law lecturer's instincts inside a cautious legislator's record.", "photo": "photos/O000167.jpg"}, {"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "Foreign Relations' top Democrat \u2014 and Delaware's senator, which means the credit-card industry's senator, as his critics never tire of noting.", "photo": "photos/B000444.jpg"}, {"key": "chafee", "name": "Lincoln Chafee", "party": "R", "state": "RI", "blurb": "The chamber's loneliest Republican: anti-war, pro-environment, pro-civil-liberties, and fighting for his political life in deep-blue Rhode Island this November.", "photo": "photos/C001040.jpg"}, {"key": "coburn", "name": "Tom Coburn", "party": "R", "state": "OK", "blurb": "'Dr. No.' An Oklahoma obstetrician who hunts wasteful spending for sport and votes against nearly anything that grows the government.", "photo": "photos/C000560.jpg"}, {"key": "feinstein", "name": "Dianne Feinstein", "party": "D", "state": "CA", "blurb": "California's businesslike centrist: tough on crime and terrorism by her party's standards, a dealmaker on the Judiciary Committee.", "photo": "photos/F000062.jpg"}], "bills": [{"name": "The Bankruptcy Bill", "desc": "March 10, 2005. The credit-card industry's decade-long dream: means tests and new hurdles making it far harder for consumers to erase debts in bankruptcy. Banks say it targets abuse; consumer advocates say it punishes the sick, the divorced, and the broke.", "votes": {"obama": "nay", "biden": "yea", "chafee": "yea", "coburn": "yea", "feinstein": "nay"}, "notes": {}, "date": "March 10, 2005", "question": "On Passage of the Bill S. 256", "result": "Bill Passed", "yeas": 74, "nays": 25}, {"name": "The Secure Fence Act", "desc": "September 29, 2006. Seven hundred miles of double-layer fencing along the Mexican border, voted weeks before the midterms \u2014 the enforcement-only answer after comprehensive immigration reform collapsed.", "votes": {"obama": "yea", "biden": "yea", "chafee": "nay", "coburn": "yea", "feinstein": "yea"}, "notes": {}, "date": "September 29, 2006", "question": "On Passage of the Bill H.R. 6061", "result": "Bill Passed", "yeas": 80, "nays": 19}, {"name": "The Military Commissions Act", "desc": "September 28, 2006. Military tribunals for Guant\u00e1namo detainees, stripped of habeas corpus review, with the CIA's interrogation program written into law \u2014 rushed through in the September dash to adjourn and campaign.", "votes": {"obama": "nay", "biden": "nay", "chafee": "nay", "coburn": "yea", "feinstein": "nay"}, "notes": {}, "date": "September 28, 2006", "question": "On Passage of the Bill S. 3930", "result": "Bill Passed", "yeas": 65, "nays": 34}]}, {"id": "tea-party-senate", "title": "The Tea Party Senate", "era": "112th Congress \u00b7 2011\u20132012", "intro": "A debt-ceiling standoff brings the country within days of default, and the parties' new wings \u2014 Tea Party right, progressive left \u2014 treat every compromise as surrender.", "senators": [{"key": "rubio", "name": "Marco Rubio", "party": "R", "state": "FL", "blurb": "The Tea Party's polished new star from Florida, elected over the establishment's pick: young, ambitious, and allergic to anything that smells like business as usual.", "photo": "photos/R000595.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "The movement's ideologist: an eye doctor who reads deficits as theft and most federal programs as unconstitutional. Compromise is what he came to Washington to stop.", "photo": "photos/P000603.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "Vermont's socialist, now a national voice against austerity \u2014 he recently held the floor for eight and a half hours against extending the Bush tax cuts.", "photo": "photos/S000033.jpg"}, {"key": "sbrown", "name": "Scott Brown", "party": "R", "state": "MA", "blurb": "The Massachusetts surprise: a Republican in Ted Kennedy's old seat, driving a pickup truck and hugging the center line for dear life before 2012.", "photo": "photos/B001268.jpg"}, {"key": "mccaskill", "name": "Claire McCaskill", "party": "D", "state": "MO", "blurb": "A Missouri Democrat with an auditor's temperament, hunting earmarks and waste to survive in a state drifting steadily redder.", "photo": "photos/M001170.jpg"}], "bills": [{"name": "The Debt-Ceiling Deal", "desc": "August 2, 2011 \u2014 default is hours away. The Budget Control Act raises the debt ceiling in exchange for a decade of spending caps and an automatic 'sequester' guillotine. Nobody loves it, and leadership is begging for votes from the middle outward.", "votes": {"rubio": "nay", "rpaul": "nay", "sanders": "nay", "sbrown": "yea", "mccaskill": "yea"}, "notes": {}, "date": "August 2, 2011", "question": "On the Motion (Motion to Concur in the House Amendment to S. 365)", "result": "Motion Agreed to", "yeas": 74, "nays": 26}, {"name": "Violence Against Women Act", "desc": "April 26, 2012. Reauthorizing the Violence Against Women Act \u2014 routine for eighteen years, now a fight over newly added protections for Native American, immigrant, and LGBT victims.", "votes": {"rubio": "nay", "rpaul": "nay", "sanders": "yea", "sbrown": "yea", "mccaskill": "yea"}, "notes": {}, "date": "April 26, 2012", "question": "On Passage of the Bill S. 1925", "result": "Bill Passed", "yeas": 68, "nays": 31}, {"name": "The Buffett Rule", "desc": "April 16, 2012. A minimum 30% tax rate on incomes over $1 million, named for the billionaire who pays a lower rate than his secretary. It needs 60 votes to advance and everyone knows it won't get them \u2014 this vote is for the campaign ads.", "votes": {"rubio": "nay", "rpaul": "nay", "sanders": "yea", "sbrown": "nay", "mccaskill": "yea"}, "notes": {}, "date": "April 16, 2012", "question": "On Cloture on the Motion to Proceed S. 2230", "result": "Cloture on the Motion to Proceed Rejected", "yeas": 51, "nays": 45}]}, {"id": "election-year-fever", "title": "Election Year Fever", "era": "116th Congress \u00b7 2020", "intro": "An impeachment ends, a pandemic begins, and a Supreme Court seat opens six weeks before the election. 2020 asks every senator exactly one question: how brave are you feeling?", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The last New England Republican, defending a seat in a state Trump lost. Her approval has cratered since the Kavanaugh vote, and every roll call is scrutinized for daylight from the President.", "photo": "photos/C001035.jpg"}, {"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "The party's 2012 nominee, reborn as its most conspicuous internal critic \u2014 the first senator in history to vote to remove a president of his own party.", "photo": "photos/R000615.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "Running for president again as the progressive standard-bearer, against the trade deals and foreign wars of both parties' establishments.", "photo": "photos/S000033.jpg"}, {"key": "sinema", "name": "Kyrsten Sinema", "party": "D", "state": "AZ", "blurb": "Arizona's unpredictable first-termer: a former Green Party activist turned proud centrist who prizes her bipartisan brand above her party's agenda.", "photo": "photos/S001191.jpg"}, {"key": "cotton", "name": "Tom Cotton", "party": "R", "state": "AR", "blurb": "An Army veteran of Iraq and Afghanistan and the Senate's most disciplined hawk: maximum pressure abroad, maximum loyalty to the President at home.", "photo": "photos/C001095.jpg"}], "bills": [{"name": "The USMCA Trade Deal", "desc": "January 16, 2020. NAFTA's replacement: modernized rules, tougher labor enforcement in Mexico, and the rare blessing of both the AFL-CIO and the Chamber of Commerce \u2014 the last major bill before the impeachment trial consumes the chamber.", "votes": {"collins": "yea", "romney": "yea", "sanders": "nay", "sinema": "yea", "cotton": "yea"}, "notes": {}, "date": "January 16, 2020", "question": "On Passage of the Bill H.R. 5430", "result": "Bill Passed", "yeas": 89, "nays": 10}, {"name": "Iran War Powers Resolution", "desc": "February 13, 2020. Weeks after the drone strike killing Qassem Soleimani brought the U.S. and Iran to the brink, a resolution ordering the President to halt hostilities against Iran absent congressional authorization. A veto is certain; the vote is about the principle.", "votes": {"collins": "yea", "romney": "nay", "sanders": "yea", "sinema": "yea", "cotton": "nay"}, "notes": {}, "date": "February 13, 2020", "question": "On the Joint Resolution S.J.Res. 68", "result": "Joint Resolution Passed", "yeas": 55, "nays": 45}, {"name": "Confirming Amy Coney Barrett", "desc": "October 26, 2020 \u2014 eight days before the election, with millions of votes already cast. Amy Coney Barrett's confirmation to Ruth Bader Ginsburg's seat, four years after the majority held Scalia's seat open for ten months on election-year principle.", "votes": {"collins": "nay", "romney": "yea", "sanders": "nay", "sinema": "nay", "cotton": "yea"}, "notes": {}, "date": "October 26, 2020", "question": "On the Nomination PN2252", "result": "Nomination Confirmed", "yeas": 52, "nays": 48}]}, {"id": "fifty-fifty-senate", "title": "The Fifty-Fifty Senate", "era": "117th Congress \u00b7 2021\u20132022", "intro": "A dead-even chamber where the Vice President breaks ties and any single senator holds veto power. Somehow, it becomes the most legislatively productive Congress in a generation.", "senators": [{"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The Republican leader and self-described Grim Reaper of Democratic bills \u2014 but a master tactician who occasionally deals when he judges the party's long-term interest demands it.", "photo": "photos/M000355.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's write-in survivor, openly estranged from Trump and facing his endorsed challenger next year \u2014 as independent as a Republican can be and still keep the label.", "photo": "photos/M001153.jpg"}, {"key": "cruz", "name": "Ted Cruz", "party": "R", "state": "TX", "blurb": "Still the Senate's happiest warrior of the right, with 2024 on his mind and a camera never far away.", "photo": "photos/C001098.jpg"}, {"key": "baldwin", "name": "Tammy Baldwin", "party": "D", "state": "WI", "blurb": "Wisconsin's workmanlike progressive and the first openly gay senator \u2014 a patient vote-counter who prefers quietly assembling coalitions to cable-news combat.", "photo": "photos/B001230.jpg"}, {"key": "sinema", "name": "Kyrsten Sinema", "party": "D", "state": "AZ", "blurb": "Now the Senate's most-watched Democrat alongside Joe Manchin: filibuster defender, dealmaker on infrastructure and guns, and scourge of her own party's left wing.", "photo": "photos/S001191.jpg"}], "bills": [{"name": "The American Rescue Plan", "desc": "March 6, 2021. $1.9 trillion in pandemic relief: $1,400 checks, an expanded child tax credit, and vaccine money, pushed through budget reconciliation after an all-night vote-a-rama. The new President wants it passed before unemployment benefits lapse.", "votes": {"mcconnell": "nay", "murkowski": "nay", "cruz": "nay", "baldwin": "yea", "sinema": "yea"}, "notes": {}, "date": "March 6, 2021", "question": "On Passage of the Bill H.R. 1319", "result": "Bill Passed", "yeas": 50, "nays": 49}, {"name": "The Infrastructure Law", "desc": "August 10, 2021. $550 billion in new money for roads, bridges, broadband, and transit, negotiated by ten senators from the middle. The question isn't whether it passes \u2014 it's which Republicans dare to touch it.", "votes": {"mcconnell": "yea", "murkowski": "yea", "cruz": "nay", "baldwin": "yea", "sinema": "yea"}, "notes": {}, "date": "August 10, 2021", "question": "On Passage of the Bill H.R. 3684", "result": "Bill Passed", "yeas": 69, "nays": 30}, {"name": "The Respect for Marriage Act", "desc": "November 29, 2022. Federal recognition of same-sex and interracial marriages, written as insurance after the Dobbs decision shook faith in precedent. Twenty-six years after DOMA passed this chamber 85\u201314, the Senate votes on marriage again.", "votes": {"mcconnell": "nay", "murkowski": "yea", "cruz": "nay", "baldwin": "yea", "sinema": "yea"}, "notes": {}, "date": "November 29, 2022", "question": "On Passage of the Bill H.R. 8404", "result": "Bill Passed", "yeas": 61, "nays": 36}]}, {"id": "helms-objection", "title": "The Helms Objection", "era": "98th Congress \u00b7 1983", "intro": "A year of repair work \u2014 rescuing Social Security, honoring Dr. King, funding the MX \u2014 with one senator from North Carolina determined to make every consensus as expensive as possible.", "senators": [{"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "The right's parliamentary guerrilla, up for re-election in 1984: he forces recorded votes on school prayer, abortion, and busing that colleagues spend years explaining. Compromise, he likes to say, is how the other side wins slowly.", "photo": "photos/H000463.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "Finance chairman at the height of his dealmaking powers: he brokered the Social Security rescue and has begun nudging his party toward arithmetic \u2014 a habit the supply-siders resent.", "photo": "photos/D000401.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal lion in opposition: fighting Reagan's defense buildup and budget cuts, championing the nuclear freeze, and lending the King holiday campaign three decades of family weight.", "photo": "photos/K000105.jpg"}, {"key": "moynihan", "name": "Daniel Patrick Moynihan", "party": "D", "state": "NY", "blurb": "The scholar-senator who helped save Social Security on the commission that bears no one's name: proudly pro-arms-control, increasingly certain the deficit is an engineered trap.", "photo": "photos/M001054.jpg"}, {"key": "kassebaum", "name": "Nancy Kassebaum", "party": "R", "state": "KS", "blurb": "Kansas's understated Republican \u2014 Alf Landon's daughter \u2014 with an internationalist head and a moderate's voting record she declines to apologize for. Defense votes she takes case by case.", "photo": "photos/K000017.jpg"}], "bills": [{"name": "Rescuing Social Security", "desc": "March 23, 1983. Social Security is months from missing checks. The Greenspan Commission's rescue: accelerate payroll-tax increases, tax benefits for higher incomes, raise the retirement age to 67 over decades, and cover new federal workers. Everyone's sacred cow gets a haircut \u2014 that's the design.", "votes": {"helms": "nay", "dole": "yea", "kennedy": "yea", "moynihan": "yea", "kassebaum": "yea"}, "notes": {}, "date": "March 23, 1983", "question": "On Passage of H.R. 1900", "result": "Bill Passed", "yeas": 88, "nays": 9}, {"name": "Funding the MX Missile", "desc": "May 25, 1983. The resolution releases funds to build and base the MX \u2014 ten warheads per missile, dubbed 'Peacekeeper' \u2014 in existing Minuteman silos. Reagan calls it leverage for arms talks with Moscow; freeze advocates call it a first-strike weapon in a vulnerable hole. The nuclear politics of 1983 in one vote.", "votes": {"helms": "yea", "dole": "yea", "kennedy": "nay", "moynihan": "nay", "kassebaum": "yea"}, "notes": {}, "date": "May 25, 1983", "question": "On Agreeing to S. Con. Res. 26", "result": "Resolution Agreed to", "yeas": 59, "nays": 39}, {"name": "The King Holiday", "desc": "October 19, 1983. A federal holiday for Martin Luther King Jr., 15 years after Memphis. Helms has filibustered, circulated FBI smears, and sued to open the King files \u2014 drawing a public rebuke on the floor even from fellow Republicans. Reagan, once opposed, has agreed to sign.", "votes": {"helms": "nay", "dole": "yea", "kennedy": "yea", "moynihan": "yea", "kassebaum": "yea"}, "notes": {}, "date": "October 19, 1983", "question": "On Passage of H.R. 3706", "result": "Bill Passed", "yeas": 78, "nays": 22}]}, {"id": "sixty-eight", "title": "1968", "era": "90th Congress \u00b7 1968", "intro": "The most convulsive year in postwar politics: King assassinated in April, Kennedy in June, cities burning, a war souring, a president renouncing re-election \u2014 and the Senate voting through all of it.", "senators": [{"key": "fulbright", "name": "J. William Fulbright", "party": "D", "state": "AR", "blurb": "Chairman of Foreign Relations and the war's most prominent critic \u2014 his televised hearings made dissent respectable. But the Rhodes Scholar from Arkansas signed the Southern Manifesto, and his civil rights record reads like his region's.", "photo": "photos/F000401.jpg"}, {"key": "thurmond", "name": "Strom Thurmond", "party": "R", "state": "SC", "blurb": "The South Carolina Republican, this year's kingmaker: he is holding the South for Richard Nixon at the convention and demanding a say on judges in return. Order, he believes, is on the ballot.", "photo": "photos/T000254.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The last Kennedy brother, 36 years old. Robert was murdered in June; Ted has returned to the floor grief-stricken but determined, the family's causes \u2014 the poor, the disenfranchised, gun laws \u2014 now his alone to carry.", "photo": "photos/K000105.jpg"}, {"key": "mcsmith", "name": "Margaret Chase Smith", "party": "R", "state": "ME", "blurb": "Twenty years into her Senate career, Maine's flinty Republican matriarch: hawkish on defense, protective of institutions, and immune to pressure campaigns from any direction.", "photo": "photos/S000590.jpg"}, {"key": "javits", "name": "Jacob Javits", "party": "R", "state": "NY", "blurb": "New York's liberal Republican \u2014 a Lincoln Republican, he'd say \u2014 who votes for civil rights, urban aid, and gun control as readily as any Democrat, and usually earlier.", "photo": "photos/J000064.jpg"}], "bills": [{"name": "The Fair Housing Act", "desc": "March 11, 1968. The last great civil rights bill: a ban on racial discrimination in the sale and rental of most of the nation's housing, attached to protections for civil rights workers. It survived weeks of filibuster on a knife's-edge cloture vote. One month later, King is dead and the House passes it in days.", "votes": {"fulbright": "nay", "thurmond": "nay", "kennedy": "yea", "mcsmith": "yea", "javits": "yea"}, "notes": {}, "date": "March 11, 1968", "question": "On Passage of H.R. 2516", "result": "Bill Passed", "yeas": 71, "nays": 20}, {"name": "The Gun Control Act of 1968", "desc": "September 18, 1968, after a spring and summer of assassination. The bill bans mail-order sales of rifles and shotguns \u2014 the way Oswald bought his carbine \u2014 bars felons from buying guns, and requires dealers to be licensed. The NRA calls it a step toward confiscation; sportsmen's states are restive.", "votes": {"fulbright": "nay", "thurmond": "nay", "kennedy": "yea", "mcsmith": "yea", "javits": "yea"}, "notes": {"fulbright": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Nay.", "mcsmith": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea."}, "date": "September 18, 1968", "question": "On Passage of H.R. 17735", "result": "Bill Passed", "yeas": 70, "nays": 17}, {"name": "Cloture on Abe Fortas", "desc": "October 1, 1968. Johnson has nominated Justice Abe Fortas \u2014 his confidant \u2014 to be Chief Justice, and a coalition of Republicans and Southern Democrats has filibustered a Supreme Court nomination for the first time. Critics cite cronyism, outside fees, and the Warren Court itself. A yea is a vote to end debate and save the nomination.", "votes": {"fulbright": "nay", "thurmond": "nay", "kennedy": "yea", "mcsmith": "nay", "javits": "yea"}, "notes": {"mcsmith": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Nay."}, "date": "October 1, 1968", "question": "On Cloture on the Nomination of Abe Fortas", "result": "Cloture Motion Rejected", "yeas": 45, "nays": 43}]}, {"id": "ford-years", "title": "The Ford Years", "era": "94th Congress \u00b7 1975\u20131976", "intro": "An unelected president, a wrecked economy, and a Congress swollen with post-Watergate reformers \u2014 busy investigating spies, extending the franchise, and arguing about how to revive a stagflated country.", "senators": [{"key": "church", "name": "Frank Church", "party": "D", "state": "ID", "blurb": "Now chairman of the select committee bearing his name, spending 1975 dragging CIA assassination plots and NSA cable-reading into daylight \u2014 convinced secrecy without oversight corrupts everything it touches.", "photo": "photos/C000388.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "A member of the same Church Committee and its in-house dissenter: he thinks airing the agencies' secrets weakens the country, and that most of Washington's post-Watergate penance is theater.", "photo": "photos/G000267.jpg"}, {"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "The Senate's youngest member \u2014 elected at 29, sworn in weeks after losing his wife and daughter. A Delaware Democrat with working-class instincts, a moderate's caution, and a surprising deficit streak.", "photo": "photos/B000444.jpg"}, {"key": "thurmond", "name": "Strom Thurmond", "party": "R", "state": "SC", "blurb": "The South's iron man, past 70 and doing push-ups to prove it: pro-Pentagon, anti-Washington, and unreconciled to federal supervision of Southern elections.", "photo": "photos/T000254.jpg"}, {"key": "humphrey", "name": "Hubert Humphrey", "party": "D", "state": "MN", "blurb": "Back in the Senate after the vice presidency and the heartbreak of 1968: the happy warrior turned elder, still preaching full employment and federal activism as if the New Deal never ended.", "photo": "photos/H000953.jpg"}], "bills": [{"name": "The Tax Cut of 1975", "desc": "March 21, 1975. With unemployment past 8% and the economy in its worst slump since the Depression, a $30 billion emergency tax cut: rebates on 1974 taxes, credits for home-buyers, and relief tilted toward lower incomes. Ford wants a smaller bill; deficit hawks in both parties want none at all.", "votes": {"church": "yea", "goldwater": "nay", "biden": "nay", "thurmond": "nay", "humphrey": "yea"}, "notes": {}, "date": "March 21, 1975", "question": "On Passage of H.R. 2166", "result": "Bill Passed", "yeas": 60, "nays": 29}, {"name": "Extending the Voting Rights Act", "desc": "July 24, 1975. A seven-year extension of the Voting Rights Act, adding permanent protections for 'language minorities' \u2014 Spanish speakers, Native Americans \u2014 and keeping Southern states under federal preclearance. Opponents ask when, if ever, the South will be trusted to run its own elections again.", "votes": {"church": "yea", "goldwater": "yea", "biden": "yea", "thurmond": "nay", "humphrey": "yea"}, "notes": {"goldwater": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea."}, "date": "July 24, 1975", "question": "On Passage of H.R. 6219", "result": "Bill Passed", "yeas": 77, "nays": 12}, {"name": "Creating the Intelligence Committee", "desc": "May 19, 1976. After a year of revelations \u2014 assassination plots, mail-opening, surveillance of Americans \u2014 the Senate votes to create a permanent Select Committee on Intelligence with power over the agencies' budgets and secrets. Defenders of the old order call it a standing leak waiting to happen.", "votes": {"church": "yea", "goldwater": "nay", "biden": "yea", "thurmond": "nay", "humphrey": "yea"}, "notes": {}, "date": "May 19, 1976", "question": "On Agreeing to S. Res. 400", "result": "Resolution Agreed to", "yeas": 72, "nays": 22}]}, {"id": "railroad", "title": "Working on the Railroad", "era": "117th Congress \u00b7 2022", "intro": "A national rail strike is nine days away, and Congress reaches for a 1926 law to impose a contract on 115,000 workers. Suddenly nobody's party label predicts anything.", "senators": [{"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "The Vermont socialist and self-appointed shop steward of the Senate. He's spent months hammering the railroads' record profits and stock buybacks \u2014 and a contract without sick days is exactly his kind of fight.", "photo": "photos/S000033.jpg"}, {"key": "rubio", "name": "Marco Rubio", "party": "R", "state": "FL", "blurb": "Florida's senator has been rebranding as a 'common-good' conservative \u2014 pro-worker, anti-woke-capital. He announced he won't vote to impose a deal the rail workers themselves rejected. The AFL-CIO is watching with one eyebrow raised.", "photo": "photos/R000595.jpg"}, {"key": "hawley", "name": "Josh Hawley", "party": "R", "state": "MO", "blurb": "Missouri's populist, courting the union rank-and-file for a post-Trump GOP. He relishes votes where he can side with workers against management and his own party's donor class in a single afternoon.", "photo": "photos/H001089.jpg"}, {"key": "baldwin", "name": "Tammy Baldwin", "party": "D", "state": "WI", "blurb": "Wisconsin's workmanlike progressive, from a state built on railroads and factory floors. A reliable labor vote \u2014 but also a Democrat weighing what a freight shutdown would do to dairy farms and drinking-water plants.", "photo": "photos/B001230.jpg"}, {"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "Utah's businessman-senator, who ran Bain Capital and believes in negotiated settlements \u2014 and in not letting a strike subtract two billion dollars a day from the economy three weeks before Christmas.", "photo": "photos/R000615.jpg"}], "bills": [{"name": "Imposing the Rail Agreement", "desc": "December 1, 2022. Under the Railway Labor Act, Congress forces the White House-brokered contract on the freight railroads and their unions: a 24% raise over five years, but just one added personal day \u2014 the deal four of twelve unions voted down. A strike would halt 30% of U.S. freight within days. Labor calls the vote a betrayal; shippers call it a rescue.", "votes": {"sanders": "nay", "rubio": "nay", "hawley": "nay", "baldwin": "yea", "romney": "yea"}, "notes": {}, "date": "December 1, 2022", "question": "On the Resolution H.J.Res. 100", "result": "Resolution Agreed to", "yeas": 80, "nays": 15}, {"name": "Seven Days of Paid Sick Leave", "desc": "The companion vote, moments earlier: adding seven paid sick days to the imposed contract. Rail workers currently get zero \u2014 scheduling systems penalize them for doctor's appointments. The House passed it separately so the rescue could survive without it. It needs 60 votes here, and the whip count is genuinely strange.", "votes": {"sanders": "yea", "rubio": "yea", "hawley": "yea", "baldwin": "yea", "romney": "nay"}, "notes": {}, "date": "December 1, 2022", "question": "On the Concurrent Resolution H.Con.Res. 119", "result": "Concurrent Resolution Rejected", "yeas": 52, "nays": 43}, {"name": "The Year-End Omnibus", "desc": "December 22, 2022. The $1.7 trillion everything bill, racing a Christmas blizzard out of town: full-year funding for the government, $45 billion for Ukraine, an overhaul of the Electoral Count Act, and 7,200 earmarks. Retiring appropriators call it Congress doing its job; conservatives call it 4,155 pages nobody has read.", "votes": {"sanders": "yea", "rubio": "nay", "hawley": "nay", "baldwin": "yea", "romney": "yea"}, "notes": {}, "date": "December 22, 2022", "question": "On the Motion (Motion to Concur in the House Amendment to Senate Amendment No. 4 with an Amendment No. 6552)", "result": "Motion Agreed to", "yeas": 68, "nays": 29}]}, {"id": "jeffords-spring", "title": "Jeffords Spring", "era": "107th Congress \u00b7 2001", "intro": "A president who lost the popular vote meets a Senate split exactly 50-50, with Dick Cheney breaking ties and committees shared like a divorced couple's kitchen. Every senator matters \u2014 and one mild Vermonter is about to matter most.", "senators": [{"key": "jeffords", "name": "Jim Jeffords", "party": "R", "state": "VT", "blurb": "Vermont's soft-spoken Republican, a moderate the party's Texas ascendancy keeps forgetting to consult. He wants full funding for special education and a smaller tax cut \u2014 grievances piling up faster than leadership has noticed.", "photo": "photos/J000072.jpg"}, {"key": "zmiller", "name": "Zell Miller", "party": "D", "state": "GA", "blurb": "Georgia's new Democrat, an old-school Southern populist who keynoted for Clinton in '92 \u2014 and signed on as an original cosponsor of Bush's tax cut before the ink on his own oath was dry.", "photo": "photos/M001141.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The maverick, months past a bitter primary loss to Bush. He came back with scores to settle and a signature cause: driving unregulated 'soft money' out of American politics.", "photo": "photos/M000303.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "McCain's Democratic partner in the campaign-finance crusade and the chamber's resident purist \u2014 he polices his own side's loopholes too, and votes against Democratic comforts as readily as Republican ones.", "photo": "photos/F000061.jpg"}, {"key": "clinton", "name": "Hillary Clinton", "party": "D", "state": "NY", "blurb": "The freshman from New York by way of the White House: studiously humble, diligently briefed, voting with her caucus while an entire press corps waits for her to do something interesting.", "photo": "photos/C001041.jpg"}], "bills": [{"name": "The Bankruptcy Bill", "desc": "March 15, 2001. The credit-card industry's bill is back: means tests to push filers from Chapter 7 into repayment plans, new paperwork, fewer exits. Clinton pocket-vetoed the last version in December; the new President is eager to sign. Consumer advocates call it a collections agency with a gavel.", "votes": {"jeffords": "yea", "zmiller": "yea", "mccain": "yea", "feingold": "nay", "clinton": "yea"}, "notes": {}, "date": "March 15, 2001", "question": "On Passage of the Bill S. 420", "result": "Bill Passed", "yeas": 83, "nays": 15}, {"name": "McCain-Feingold", "desc": "April 2, 2001. After six years of filibusters, campaign finance reform finally passes something: a ban on unlimited 'soft money' donations to the parties and limits on sham 'issue ads' before elections. Opponents call it an assault on the First Amendment; supporters call it plumbing repair for democracy.", "votes": {"jeffords": "yea", "zmiller": "yea", "mccain": "yea", "feingold": "yea", "clinton": "yea"}, "notes": {}, "date": "April 2, 2001", "question": "On Passage of the Bill S. 27", "result": "Bill Passed", "yeas": 59, "nays": 41}, {"name": "The Bush Tax Cut", "desc": "May 26, 2001. $1.35 trillion over eleven years: lower rates in every bracket, rebate checks this summer, the estate tax phased toward zero \u2014 all sunsetting in 2010 to squeeze under budget rules. Two days earlier, Jim Jeffords announced he was leaving the Republican Party, handing Democrats the Senate; this is the old majority's parting gift to itself.", "votes": {"jeffords": "yea", "zmiller": "yea", "mccain": "nay", "feingold": "nay", "clinton": "nay"}, "notes": {}, "date": "May 26, 2001", "question": "On the Conference Report H.R. 1836", "result": "Conference Report Agreed to", "yeas": 58, "nays": 33}]}, {"id": "hundred-days-93", "title": "The Hundred Days of 1993", "era": "103rd Congress \u00b7 1993", "intro": "Bill Clinton arrives with a Democratic Congress and a to-do list Bush's vetoes kept frozen for years. By August, the honeymoon is down to a single vote.", "senators": [{"key": "bkerrey", "name": "Bob Kerrey", "party": "D", "state": "NE", "blurb": "Nebraska's Medal of Honor recipient, who ran against Clinton in the '92 primaries and hasn't warmed to him since. A deficit hawk with a philosopher's temperament, he treats every big vote as a crisis of conscience \u2014 and lets everyone watch.", "photo": "photos/K000146.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Republican leader, freshly demoted to the minority and plotting the road back. With Bush gone, discipline is his product: make Clinton's majority carry every hard vote alone.", "photo": "photos/D000401.jpg"}, {"key": "boxer", "name": "Barbara Boxer", "party": "D", "state": "CA", "blurb": "A Marin County liberal swept in with the Year of the Woman class. She campaigned on exactly this agenda and sees no reason to hesitate now.", "photo": "photos/B000711.jpg"}, {"key": "nunn", "name": "Sam Nunn", "party": "D", "state": "GA", "blurb": "Armed Services' Georgia conservative, openly at odds with the new White House over gays in the military. Fiscally orthodox, socially cautious, and unimpressed by the young administration.", "photo": "photos/N000171.jpg"}, {"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "Pennsylvania's Republican moderate, back from a bruising re-election. Labor-friendly enough to cross the aisle on workplace bills \u2014 and orthodox enough to hold the line where taxes are concerned.", "photo": "photos/S000709.jpg"}], "bills": [{"name": "The Family and Medical Leave Act", "desc": "February 4, 1993 \u2014 week two of the new administration. The same twelve weeks of unpaid leave Bush vetoed twice, back for a president who has promised to make it the first bill he signs. For Republicans, the question is whether to keep fighting a war that's already lost.", "votes": {"bkerrey": "yea", "dole": "nay", "boxer": "yea", "nunn": "yea", "specter": "yea"}, "notes": {}, "date": "February 4, 1993", "question": "On Passage of the Bill H.R. 1", "result": "Bill Passed", "yeas": 71, "nays": 27}, {"name": "The Motor Voter Act", "desc": "May 11, 1993. Register to vote at the DMV and the welfare office. Democrats call it democracy's plumbing; Republicans call it an invitation to fraud and a thumb on the partisan scale. Bush vetoed it last year \u2014 this time the conference report is headed to a signature.", "votes": {"bkerrey": "yea", "dole": "nay", "boxer": "yea", "nunn": "yea", "specter": "yea"}, "notes": {}, "date": "May 11, 1993", "question": "On the Conference Report H.R. 2", "result": "Conference Report Agreed to", "yeas": 62, "nays": 36}, {"name": "Clinton's First Budget", "desc": "August 6, 1993, nearly 10 p.m. The deficit plan: a 39.6% top rate, a 4.3-cent gas tax, an expanded credit for the working poor \u2014 $496 billion in deficit reduction with not one Republican vote for it, anywhere. The chamber is so tightly deadlocked that the Vice President waits in the chair to break a tie.", "votes": {"bkerrey": "yea", "dole": "nay", "boxer": "yea", "nunn": "nay", "specter": "nay"}, "notes": {}, "date": "August 6, 1993", "question": "On the Conference Report H.R. 2264", "result": "Conference Report Agreed to", "yeas": 50, "nays": 50}]}, {"id": "daca-day", "title": "Four Bills in One Day", "era": "115th Congress \u00b7 February 2018", "intro": "September 2017: the President cancels DACA and gives Congress six months to act. February 15, 2018: deadline week arrives, and the Senate burns through four rival immigration plans in a single afternoon. None will reach 60 \u2014 but the roll calls tell the story.", "senators": [{"key": "harris", "name": "Kamala Harris", "party": "D", "state": "CA", "blurb": "California's freshman and former state attorney general, a national progressive star within a year of arriving. Protecting Dreamers is non-negotiable for her \u2014 but so is her refusal to pay what she considers a $25 billion ransom for a border wall.", "photo": "photos/H001075.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's dealmaker, hosting the bipartisan 'Common Sense Coalition' in her office \u2014 complete with a Masai talking stick to keep senators from interrupting one another. She still believes the center can pass things.", "photo": "photos/C001035.jpg"}, {"key": "flake", "name": "Jeff Flake", "party": "R", "state": "AZ", "blurb": "Arizona's lame duck, retiring rather than face a primary he cannot win in Trump's party. Freed from the electorate, he has made a Dreamer fix his personal parting crusade.", "photo": "photos/F000444.jpg"}, {"key": "cotton", "name": "Tom Cotton", "party": "R", "state": "AR", "blurb": "The President's favorite immigration ally in the chamber, co-author of a bill to cut legal immigration in half. He regards 'comprehensive reform' as a euphemism for amnesty, and the White House framework as the only deal on the table.", "photo": "photos/C001095.jpg"}, {"key": "king", "name": "Angus King", "party": "I", "state": "ME", "blurb": "Maine's independent, a fleece-vested former governor who caucuses with Democrats and negotiates with everyone. He co-brokered the centrist compromise on today's ballot \u2014 the one with money for the wall and mercy for the Dreamers.", "photo": "photos/K000383.jpg"}], "bills": [{"name": "The McCain-Coons Plan", "desc": "February 15, 2018, 2:33 p.m. The narrowest fix on the menu: a path to citizenship for Dreamers plus a study of border-security needs \u2014 and not a dollar for the wall. Named in part for John McCain, absent in Arizona battling cancer. The White House has promised a veto of anything arriving without wall money. Cloture requires 60 votes.", "votes": {"harris": "yea", "collins": "nay", "flake": "yea", "cotton": "nay", "king": "yea"}, "notes": {}, "date": "February 15, 2018", "question": "On the Cloture Motion S.Amdt. 1955 to S.Amdt. 1958 to H.R. 2579 (Broader Options for Americans Act)", "result": "Cloture Motion Rejected", "yeas": 52, "nays": 47}, {"name": "The Rounds-King Compromise", "desc": "3:28 p.m. The centrists' grand bargain, hatched in Susan Collins's office: citizenship for 1.8 million Dreamers, the President's full $25 billion for border security and the wall, and limits on sponsoring parents \u2014 but no cuts to the diversity lottery. The Department of Homeland Security denounces it in a blistering midday statement. It is the only plan with a real shot at 60.", "votes": {"harris": "nay", "collins": "yea", "flake": "yea", "cotton": "nay", "king": "yea"}, "notes": {}, "date": "February 15, 2018", "question": "On the Cloture Motion S.Amdt. 1958 to H.R. 2579 (Broader Options for Americans Act)", "result": "Cloture Motion Rejected", "yeas": 54, "nays": 45}, {"name": "The Grassley Bill \u2014 Trump's Four Pillars", "desc": "3:49 p.m. The White House plan, carried by Chuck Grassley: citizenship for 1.8 million Dreamers in exchange for the full wall, an end to the diversity visa lottery, and family sponsorship cut to spouses and minor children \u2014 the largest legal-immigration reduction in decades. The President endorses only this bill. It goes last, and it too needs 60.", "votes": {"harris": "nay", "collins": "nay", "flake": "nay", "cotton": "yea", "king": "nay"}, "notes": {}, "date": "February 15, 2018", "question": "On the Cloture Motion S.Amdt. 1959 to H.R. 2579 (Broader Options for Americans Act)", "result": "Cloture Motion Rejected", "yeas": 39, "nays": 60}]}, {"id": "longest-shutdown", "title": "The Longest Shutdown", "era": "116th Congress \u00b7 2019", "intro": "Thirty-five days, 800,000 unpaid federal workers, and a $5.7 billion wall demand nobody will blink on. On day 34, the Senate finally votes on both parties' offers, back to back \u2014 with a brand-new senator from Utah choosing his footing.", "senators": [{"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "Three weeks into the job, the party's 2012 presidential nominee arrived via a Washington Post op-ed scolding the President's character. Utah elected a Republican, though \u2014 and he insists he will vote with Trump whenever the policy warrants it.", "photo": "photos/R000615.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's institutionalist, the loudest Republican voice for reopening the government first and arguing about the wall second. She has been rallying colleagues to sign bipartisan letters; letters have not worked.", "photo": "photos/C001035.jpg"}, {"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "West Virginia's Democrat, fresh off surviving 2018 in a state Trump carried by 42 points. Federal workers \u2014 prison guards, TSA screeners \u2014 are a bigger constituency for him than either party's base, and he has voted for wall money before.", "photo": "photos/M001183.jpg"}, {"key": "cruz", "name": "Ted Cruz", "party": "R", "state": "TX", "blurb": "Texas's border hawk, all-in on the President's demand. He blames Democrats for holding paychecks hostage to deny Trump a win \u2014 and has proposed paying for the wall with El Chapo's seized drug fortune.", "photo": "photos/C001098.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's independent Republican, with thousands of federal workers at home and a long list of frozen services. She has said publicly that shutting the government down was a mistake; the question is what she will do about it.", "photo": "photos/M001153.jpg"}], "bills": [{"name": "The President's Offer", "desc": "January 24, 2019 \u2014 day 34. The White House package: $5.7 billion for the wall, three years of protection for DACA recipients and TPS holders, asylum changes \u2014 and the government reopened. Democrats call the immigration relief a hostage payment that recycles protections the President himself canceled. Sixty votes needed.", "votes": {"romney": "yea", "collins": "yea", "manchin": "yea", "cruz": "yea", "murkowski": "yea"}, "notes": {}, "date": "January 24, 2019", "question": "On the Cloture Motion S.Amdt. 5 to H.R. 268 (Supplemental Appropriations Act, 2019)", "result": "Cloture Motion Rejected", "yeas": 50, "nays": 47}, {"name": "The Democrats' Offer", "desc": "Minutes later: the Democratic alternative, already passed by the House \u2014 reopen the government through February 8 with disaster aid attached, no wall money, and negotiate border security afterward. It is essentially the bill the Senate approved without objection in December, before the President changed his mind. Sixty votes needed, and all eyes on Republican defectors.", "votes": {"romney": "yea", "collins": "yea", "manchin": "yea", "cruz": "nay", "murkowski": "yea"}, "notes": {}, "date": "January 24, 2019", "question": "On the Cloture Motion S.Amdt. 6 to H.R. 268 (Supplemental Appropriations Act, 2019)", "result": "Cloture Motion Rejected", "yeas": 52, "nays": 44}, {"name": "The Deal That Ended It", "desc": "February 14, 2019. Three weeks after the shutdown ended in a temporary truce, the conference committee's verdict: $1.375 billion for 55 miles of border fencing \u2014 less than the Senate offered the President in December \u2014 plus full-year funding for nine departments. He will sign it, then declare a national emergency to build more. Nobody calls it victory.", "votes": {"romney": "yea", "collins": "yea", "manchin": "yea", "cruz": "nay", "murkowski": "yea"}, "notes": {}, "date": "February 14, 2019", "question": "On the Conference Report H.J.Res. 31", "result": "Conference Report Agreed to", "yeas": 83, "nays": 16}]}, {"id": "mandate-of-84", "title": "The Second Term", "era": "99th Congress \u00b7 1985\u20131986", "intro": "Re-elected in a 49-state landslide, Reagan meets a Senate ready to legislate around him: automatic deficit cuts, a once-a-generation tax code rewrite \u2014 and, on South Africa, an open revolt.", "senators": [{"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "Majority Leader now, running the chamber with a legislator's cunning and a compulsive candidate's calendar: 1988 is coming, and every vote is a general-election exhibit.", "photo": "photos/D000401.jpg"}, {"key": "lugar", "name": "Richard Lugar", "party": "R", "state": "IN", "blurb": "Chairman of Foreign Relations at his careful, unflashy best \u2014 a Reagan loyalist on most things who has concluded, after Manila and Johannesburg, that loyalty and foreign policy are different subjects.", "photo": "photos/L000504.jpg"}, {"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "The hard right's anchor, defending the Pretoria government as an anti-communist ally and the tax code's sanctities selectively \u2014 tobacco's above all.", "photo": "photos/H000463.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "Fresh from visiting Soweto and Winnie Mandela: he has made apartheid a moral cause of the American left and intends to make Republicans vote on it repeatedly.", "photo": "photos/K000105.jpg"}, {"key": "gramm", "name": "Phil Gramm", "party": "R", "state": "TX", "blurb": "The Texas economist who switched parties mid-career and arrived in the Senate with an algorithm: if the deficit is the disease, make the cuts automatic and let no appropriator escape.", "photo": "photos/G000365.jpg"}], "bills": [{"name": "Gramm-Rudman-Hollings", "desc": "December 11, 1985. The deficit doomsday machine: fixed annual deficit targets reaching balance by 1991, enforced by automatic across-the-board cuts \u2014 'sequestration' \u2014 if Congress misses. Attached to a must-pass debt-limit increase. Critics in both parties call it government by autopilot; it passes anyway.", "votes": {"dole": "yea", "lugar": "yea", "helms": "yea", "kennedy": "yea", "gramm": "yea"}, "notes": {}, "date": "December 11, 1985", "question": "On the Conference Report on H.J. Res. 372", "result": "Conference Report Agreed to", "yeas": 61, "nays": 31}, {"name": "The Tax Reform Act of 1986", "desc": "September 27, 1986. The improbable grand bargain: the top individual rate falls from 50% to 28%, corporate loopholes close by the hundreds, and six million working poor drop off the income tax rolls entirely. Lobbyists filled Gucci Gulch for two years and lost. Purists on both flanks still object.", "votes": {"dole": "yea", "lugar": "yea", "helms": "nay", "kennedy": "yea", "gramm": "yea"}, "notes": {}, "date": "September 27, 1986", "question": "On the Conference Report on H.R. 3838", "result": "Conference Report Agreed to", "yeas": 74, "nays": 23}, {"name": "South Africa Sanctions Override", "desc": "October 2, 1986. Reagan has vetoed the Comprehensive Anti-Apartheid Act \u2014 bans on new investment, South African imports, and airport landing rights. His own party's Senate must decide whether 'constructive engagement' with Pretoria has failed. A yea overrides a president's foreign-policy veto \u2014 the first since War Powers.", "votes": {"dole": "nay", "lugar": "yea", "helms": "nay", "kennedy": "yea", "gramm": "yea"}, "notes": {}, "date": "October 2, 1986", "question": "On Overriding the Veto of H.R. 4868", "result": "Veto Overridden", "yeas": 78, "nays": 21}]}, {"id": "the-watchers", "title": "The Watchers", "era": "114th\u2013116th Congress \u00b7 2015\u20132020", "intro": "Five years of votes on how much the government may see: server logs, phone records, browsing histories. The coalitions ignore every party label \u2014 privacy hawks of the left and right against the security establishment of both.", "senators": [{"key": "wyden", "name": "Ron Wyden", "party": "D", "state": "OR", "blurb": "Oregon's senior Democrat and the Intelligence Committee's designated dissenter. He asks the questions that make NSA directors squirm \u2014 his cryptic warnings about 'secret law' predate the Snowden leaks by years.", "photo": "photos/W000779.jpg"}, {"key": "cotton", "name": "Tom Cotton", "party": "R", "state": "AR", "blurb": "Arkansas's Army veteran and the Senate's most unapologetic defender of the surveillance state. He would renew every expiring authority permanently, without amendment, and says so at every opportunity.", "photo": "photos/C001095.jpg"}, {"key": "mlee", "name": "Mike Lee", "party": "R", "state": "UT", "blurb": "Utah's constitutional conservative, who reads the Fourth Amendment the way he reads the rest of the founding text: literally. A persistent negotiator for warrant requirements and reforms of the secret surveillance court.", "photo": "photos/L000577.jpg"}, {"key": "feinstein", "name": "Dianne Feinstein", "party": "D", "state": "CA", "blurb": "California's Democrat and longtime Intelligence Committee leader \u2014 author of the CIA torture report, yet one of the NSA's steadiest defenders. Security first is not a contradiction in her book; it is the book.", "photo": "photos/F000062.jpg"}, {"key": "warren", "name": "Elizabeth Warren", "party": "D", "state": "MA", "blurb": "Massachusetts's progressive: no seat on the Intelligence Committee and no deference to it either. She votes with the civil-liberties bloc \u2014 surveillance being, in her telling, one more unaccountable concentration of power.", "photo": "photos/W000817.jpg"}], "bills": [{"name": "The Cybersecurity Information Sharing Act", "desc": "October 27, 2015. Months after the OPM hack exposed 21 million security-clearance files, a bill inviting companies to share 'cyber threat indicators' with the government \u2014 with liability protection, and with the data flowing on to the NSA and FBI. Apple and Twitter oppose it; the Chamber of Commerce and the intelligence agencies want it badly.", "votes": {"wyden": "nay", "cotton": "yea", "mlee": "nay", "feinstein": "yea", "warren": "nay"}, "notes": {}, "date": "October 27, 2015", "question": "On Passage of the Bill S. 754", "result": "Bill Passed", "yeas": 74, "nays": 21}, {"name": "FISA Section 702 Reauthorization", "desc": "January 18, 2018. Six more years for the NSA's crown-jewel authority: warrantless collection of foreigners' communications \u2014 which also sweeps in the Americans on the other end of the line, searchable later by the FBI. An unlikely left-right alliance demanded warrants for those searches, and lost. Defenders call the program the most valuable intelligence tool America has.", "votes": {"wyden": "nay", "cotton": "yea", "mlee": "nay", "feinstein": "yea", "warren": "nay"}, "notes": {}, "date": "January 18, 2018", "question": "On the Motion (Motion to Concur in the House Amendment to S. 139)", "result": "Motion Agreed to", "yeas": 65, "nays": 34}, {"name": "USA FREEDOM Reauthorization", "desc": "May 14, 2020. Expired FISA authorities meet the post-Carter Page moment: an inspector general found 17 errors and omissions in the surveillance applications against the former Trump campaign aide, scrambling the politics of the entire apparatus. The bill adds legal safeguards \u2014 an amendment to shield browsing histories from warrantless collection has just failed by a single vote.", "votes": {"wyden": "nay", "cotton": "yea", "mlee": "yea", "feinstein": "yea", "warren": "nay"}, "notes": {}, "date": "May 14, 2020", "question": "On Passage of the Bill H.R. 6172", "result": "Bill Passed", "yeas": 80, "nays": 16}]}, {"id": "the-leaders", "title": "The Leaders", "era": "114th Congress \u00b7 2015\u20132016", "intro": "Harry Reid and Mitch McConnell have run the Senate between them for a decade \u2014 now one is retiring and the other consolidating. Around them, the chamber's biggest names pick their last fights of the Obama era.", "senators": [{"key": "reid", "name": "Harry Reid", "party": "D", "state": "NV", "blurb": "The Democratic leader, an ex-boxer from Searchlight, Nevada, serving his final Congress. Freed from re-election, he fights on pure instinct \u2014 and his instincts have never once included backing down.", "photo": "photos/R000146.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The majority leader at last, running the chamber with a technician's patience. His priorities: confirm judges, protect his majority, and never take a vote that divides his conference \u2014 unless it truly must be taken.", "photo": "photos/M000355.jpg"}, {"key": "mlee", "name": "Mike Lee", "party": "R", "state": "UT", "blurb": "Utah's constitutional purist, the man the leaders schedule around: he reads every bill against the Tenth Amendment and the national debt, and no leadership favor has ever changed his arithmetic.", "photo": "photos/L000577.jpg"}, {"key": "warren", "name": "Elizabeth Warren", "party": "D", "state": "MA", "blurb": "The party's self-appointed sheriff of Wall Street, wielding hearings and floor speeches like subpoenas. Her latest target: drug-industry provisions dressed up, as she sees it, in the language of medical progress.", "photo": "photos/W000817.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The chamber's most reliable bipartisan and, by the rankings, its most moderate member. If a bill gets 90 votes, odds are she helped write the compromise that got it there.", "photo": "photos/C001035.jpg"}], "bills": [{"name": "Confirming Loretta Lynch", "desc": "April 23, 2015. The Brooklyn federal prosecutor nominated \u2014 five months ago \u2014 to become the first Black woman attorney general. Her confirmation sat in limbo while the leaders feuded over an unrelated human-trafficking bill, the longest wait for any attorney general nominee in three decades. Even senators voting no concede she is qualified; the question is who ends the standoff.", "votes": {"reid": "yea", "mcconnell": "yea", "mlee": "nay", "warren": "yea", "collins": "yea"}, "notes": {}, "date": "April 23, 2015", "question": "On the Nomination PN4", "result": "Nomination Confirmed", "yeas": 56, "nays": 43}, {"name": "The 9/11 Lawsuits Bill (JASTA)", "desc": "September 28, 2016. JASTA lets the families of 9/11 victims sue Saudi Arabia in American courts. Obama vetoed it, warning it will expose U.S. troops and diplomats to reciprocal lawsuits abroad \u2014 and no president has been overridden in his eight years. Six weeks before an election, almost no one wants to face the families. Overriding takes two-thirds.", "votes": {"reid": "nay", "mcconnell": "yea", "mlee": "yea", "warren": "yea", "collins": "yea"}, "notes": {}, "date": "September 28, 2016", "question": "On Overriding the Veto S. 2040", "result": "Veto Overridden", "yeas": 97, "nays": 1}, {"name": "The 21st Century Cures Act", "desc": "December 7, 2016. A $6.3 billion medical-research bill: cancer 'moonshot' money, opioid-crisis funding, NIH increases, and faster FDA approvals for drugs and devices. Patient groups adore it. A small band of progressive holdouts calls the approval provisions a gift to the pharmaceutical lobbyists \u2014 hundreds of whom worked on the text.", "votes": {"reid": "yea", "mcconnell": "yea", "mlee": "nay", "warren": "nay", "collins": "yea"}, "notes": {}, "date": "December 7, 2016", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.R. 34)", "result": "Motion Agreed to", "yeas": 94, "nays": 5}]}, {"id": "institutionalists", "title": "The Institutionalists", "era": "117th Congress \u00b7 2021\u20132022", "intro": "After January 6th, a handful of Republicans stop worrying about primaries \u2014 several by leaving politics altogether. Freed from the base, what do they actually vote for?", "senators": [{"key": "toomey", "name": "Pat Toomey", "party": "R", "state": "PA", "blurb": "Pennsylvania's flinty fiscal conservative, retiring rather than run again in a Trump party. A Club for Growth alumnus to the end: he'll defy Trump on principle and still vote against almost anything that spends money.", "photo": "photos/T000461.jpg"}, {"key": "burr", "name": "Richard Burr", "party": "R", "state": "NC", "blurb": "North Carolina's laconic three-termer, also retiring. As Intelligence chairman he ran the Senate's Russia investigation straight down the middle and shrugged off the censure his own state party passed against him.", "photo": "photos/B001135.jpg"}, {"key": "cassidy", "name": "Bill Cassidy", "party": "R", "state": "LA", "blurb": "A Baton Rouge liver doctor who worked charity hospitals for 25 years. He reads bills like charts \u2014 wonkish, blunt, and newly re-elected, which buys him six years of not caring what Louisiana's party committees think.", "photo": "photos/C001075.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's write-in survivor, the only Republican in this group actually facing voters in 2022 \u2014 with a Trump-endorsed challenger already in the race and a new ranked-choice system that just might save her.", "photo": "photos/M001153.jpg"}, {"key": "warnock", "name": "Raphael Warnock", "party": "D", "state": "GA", "blurb": "The pastor of Ebenezer Baptist, months into the seat he won in a runoff that flipped the Senate \u2014 and already running again in purple Georgia, preaching bipartisanship while voting mostly with his party.", "photo": "photos/W000790.jpg"}], "bills": [{"name": "The Second Impeachment Trial", "desc": "February 13, 2021. Donald Trump's second impeachment trial \u2014 the first ever of a former president \u2014 ends with a verdict on a single article: incitement of insurrection for January 6th. He is out of office; conviction would clear the way to disqualify him from ever holding office again. Two-thirds to convict, and every Republican Yea is a career risk.", "votes": {"toomey": "yea", "burr": "yea", "cassidy": "yea", "murkowski": "yea", "warnock": "yea"}, "notes": {}, "labels": ["GUILTY", "NOT GUILTY"], "date": "February 13, 2021", "question": "Guilty or Not Guilty H.Res. 24", "result": "Not Guilty", "yeas": 57, "nays": 43}, {"name": "Advancing the CHIPS Act", "desc": "July 19, 2022. The make-or-break test vote on $52 billion in subsidies for domestic semiconductor manufacturing, plus a 25% investment tax credit \u2014 industrial policy on a scale unseen in decades, sold as keeping chip fabs out of China's shadow. Free-market conservatives call it corporate welfare; the Commerce Department calls it national security.", "votes": {"toomey": "nay", "burr": "nay", "cassidy": "yea", "murkowski": "yea", "warnock": "yea"}, "notes": {}, "date": "July 19, 2022", "question": "On the Motion to Proceed H.R. 4346", "result": "Motion to Proceed Agreed to", "yeas": 64, "nays": 34}, {"name": "The PACT Act", "desc": "August 2, 2022. Health care and disability benefits for veterans exposed to toxic burn pits in Iraq and Afghanistan \u2014 roughly $280 billion over a decade, the largest expansion of veterans' benefits in a generation. A procedural blockade days earlier left veterans' groups camped on the Capitol steps with Jon Stewart. Now the final vote.", "votes": {"toomey": "nay", "burr": "yea", "cassidy": "yea", "murkowski": "yea", "warnock": "yea"}, "notes": {}, "date": "August 2, 2022", "question": "On the Motion (Motion to Concur in the House Amendment to S.3373)", "result": "Motion Agreed to", "yeas": 86, "nays": 11}]}, {"id": "nuclear-autumn", "title": "The Nuclear Autumn", "era": "113th Congress \u00b7 2013\u20132014", "intro": "Years of blockaded nominees come to a head on a November morning when the Senate votes to change itself. The fallout \u2014 procedural and political \u2014 lands on everyone, especially a Louisiana Democrat running out of time.", "senators": [{"key": "landrieu", "name": "Mary Landrieu", "party": "D", "state": "LA", "blurb": "Louisiana's three-term Democrat, chair of the Energy Committee and the most endangered incumbent in the country. Her survival strategy: deliver for oil and gas, loudly, and keep daylight between herself and her party's leadership.", "photo": "photos/L000550.jpg"}, {"key": "merkley", "name": "Jeff Merkley", "party": "D", "state": "OR", "blurb": "Oregon's methodical progressive and the Senate's leading crusader for filibuster reform \u2014 he has spent five years writing white papers on why the chamber is broken and precisely how to fix it.", "photo": "photos/M001176.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The institutionalist's institutionalist: she has never missed a roll-call vote and believes the Senate's rules are what separate it from the House. Changing them by brute majority strikes her as vandalism.", "photo": "photos/C001035.jpg"}, {"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "West Virginia's Democrat, who thinks the Senate's problem is people refusing to talk to each other, not the rulebook. Reflexively suspicious of anything that concentrates power in either party's leadership.", "photo": "photos/M001183.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The Republican leader and master of the procedural blockade. He warns Democrats they will regret weakening the filibuster 'a lot sooner than you think' \u2014 a prophecy he is unusually well positioned to fulfill.", "photo": "photos/M000355.jpg"}], "bills": [{"name": "The Nuclear Option", "desc": "November 21, 2013. After Republicans block three D.C. Circuit nominees in a row, Harry Reid pulls the trigger. The chair has ruled, per decades of precedent, that nominees still need 60 votes; Reid appeals the ruling. Voting yea upholds the old 60-vote Senate. Voting nay detonates the 'nuclear option' \u2014 letting a bare majority confirm every nominee short of the Supreme Court.", "votes": {"landrieu": "nay", "merkley": "nay", "collins": "yea", "manchin": "yea", "mcconnell": "yea"}, "notes": {}, "date": "November 21, 2013", "question": "On the Decision of the Chair PN527", "result": "Decision of Chair Not Sustained", "yeas": 48, "nays": 52}, {"name": "The Murray-Ryan Budget", "desc": "December 18, 2013. Two months after the shutdown, the two parties' budget chairs \u2014 liberal Patty Murray and conservative Paul Ryan \u2014 produce a modest truce: sequester cuts eased by $63 billion, paid for with fees and federal-pension trims, no new taxes, no entitlement changes. Its ambition is its lack of ambition: two years without a budget crisis.", "votes": {"landrieu": "yea", "merkley": "yea", "collins": "yea", "manchin": "yea", "mcconnell": "nay"}, "notes": {}, "date": "December 18, 2013", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.J.Res. 59)", "result": "Motion Agreed to", "yeas": 64, "nays": 36}, {"name": "The Keystone XL Pipeline", "desc": "November 18, 2014. Mary Landrieu, forced into a December runoff she is losing, finally gets the vote she has demanded for years: approval of the Keystone XL pipeline from Alberta's oil sands to the Gulf, over the President's objections. Every Republican is aboard; the question is whether enough Democrats will help her reach 60 and save her seat.", "votes": {"landrieu": "yea", "merkley": "nay", "collins": "yea", "manchin": "yea", "mcconnell": "yea"}, "notes": {}, "date": "November 18, 2014", "question": "On Passage of the Bill S. 2280", "result": "Bill Defeated", "yeas": 59, "nays": 41}]}, {"id": "one-vote-short", "title": "One Vote Short", "era": "104th Congress \u00b7 1995\u20131996", "intro": "The Gingrich Congress means to rewire the government itself: a balanced-budget amendment that died by a single vote in 1995, a line-item veto \u2014 and, mid-revolution, a president sending troops to the Balkans.", "senators": [{"key": "hatfield", "name": "Mark Hatfield", "party": "R", "state": "OR", "blurb": "Oregon's gentle Republican heretic: a World War II veteran who walked the ruins of Hiroshima, an appropriator who believes in government, a pacifist in the party of peace through strength. Conservatives tried to strip his chairmanship after he defied them on the budget amendment last year.", "photo": "photos/H000343.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Leader and nominee-in-waiting, trying to run for president from the majority leader's desk. He needs accomplishments to campaign on \u2014 and his restless right flank takes his measurements daily.", "photo": "photos/D000401.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Senate's constitutional conscience, armored in Article I. To Byrd, the appropriations power is the people's leash on presidents, and anyone proposing to lend it out is proposing vandalism.", "photo": "photos/B001210.jpg"}, {"key": "boxer", "name": "Barbara Boxer", "party": "D", "state": "CA", "blurb": "California's unapologetic liberal: she calls the balanced-budget craze a slow-motion raid on Social Security and the line-item veto a power grab. Her loyalty runs to the Democratic White House, not to Senate custom.", "photo": "photos/B000711.jpg"}, {"key": "nunn", "name": "Sam Nunn", "party": "D", "state": "GA", "blurb": "Georgia's defense eminence, headed for retirement and freer by the month. A deficit hawk from the party's vanishing conservative wing \u2014 but on troops and treaties, the chamber waits to hear him first.", "photo": "photos/N000171.jpg"}], "bills": [{"name": "Troops to Bosnia", "desc": "December 13, 1995. The Dayton accords are signed, and Clinton is sending 20,000 Americans to enforce the peace in Bosnia \u2014 with or without Congress. The resolution backs the troops and their mission while registering deep reservations about the policy. Somalia's ghosts hang over the debate.", "votes": {"hatfield": "nay", "dole": "yea", "byrd": "yea", "boxer": "yea", "nunn": "yea"}, "notes": {}, "date": "December 13, 1995", "question": "On the Joint Resolution S.J.Res. 44", "result": "Joint Resolution Passed", "yeas": 69, "nays": 30}, {"name": "The Line-Item Veto", "desc": "March 27, 1996. A Contract with America plank handing presidents the power to strike individual spending items from bills they sign \u2014 a power governors have long held and presidents have coveted since Grant. Its loudest opponent has delivered fourteen floor speeches on the Roman Republic to explain what happens next.", "votes": {"hatfield": "nay", "dole": "yea", "byrd": "nay", "boxer": "nay", "nunn": "nay"}, "notes": {}, "date": "March 27, 1996", "question": "On the Conference Report S. 4", "result": "Conference Report Agreed to", "yeas": 69, "nays": 31}, {"name": "The Balanced Budget Amendment, Again", "desc": "June 6, 1996. Fifteen months after the constitutional amendment to balance the budget died a single vote short, Dole brings it back for an encore \u2014 five days before he leaves the Senate for good to run full-time. Two-thirds required, and nobody's arithmetic has changed.", "votes": {"hatfield": "nay", "dole": "yea", "byrd": "nay", "boxer": "nay", "nunn": "yea"}, "notes": {}, "date": "June 6, 1996", "question": "On the Joint Resolution H.J.Res. 1", "result": "Joint Resolution Defeated", "yeas": 64, "nays": 35}]}, {"id": "loyalty-tests", "title": "The Loyalty Tests", "era": "119th Congress \u00b7 2025", "intro": "A re-elected Donald Trump sends the Senate his most unconventional cabinet yet, daring Republicans to object. For three weeks, every confirmation is a loyalty test with a two-vote margin.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Five terms in and chairing Appropriations at last, the Maine moderate is one of the few Republicans left who publicly weighs nominees one by one \u2014 knowing every 'no' now invites a primary threat from Mar-a-Lago.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's independent-minded survivor, re-elected under ranked-choice voting and openly unafraid of Trump. She scrutinizes qualifications the old-fashioned way and shrugs at the consequences.", "photo": "photos/M001153.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The longest-serving Senate leader in history is a leader no more \u2014 a backbencher at 82, a polio survivor with hawkish convictions and, suddenly, nothing left to protect but his own judgment.", "photo": "photos/M000355.jpg"}, {"key": "fetterman", "name": "John Fetterman", "party": "D", "state": "PA", "blurb": "Pennsylvania's hoodie-wearing Democrat, who flew to Mar-a-Lago to meet the president-elect and says some nominees deserve a fair look. His party's activists are furious; he appears to enjoy that.", "photo": "photos/F000479.jpg"}, {"key": "curtis", "name": "John Curtis", "party": "R", "state": "UT", "blurb": "Utah's freshman, who won Mitt Romney's old seat promising civility and climate conservatism. A former Provo mayor with an institutional streak \u2014 but a Republican freshman still, with a base watching his first big votes.", "photo": "photos/C001114.jpg"}], "bills": [{"name": "Confirming Pete Hegseth", "desc": "January 24, 2025. Secretary of Defense: a decorated Army National Guard veteran and Fox News weekend host who has never run anything close to a three-million-person department. The hearings churn through allegations about his drinking and personal conduct \u2014 all denied \u2014 and his past opposition to women in combat. The tally hangs at 50-50, and the Vice President is standing by.", "votes": {"collins": "nay", "murkowski": "nay", "mcconnell": "nay", "fetterman": "nay", "curtis": "yea"}, "notes": {}, "date": "January 24, 2025", "question": "On the Nomination PN11-7", "result": "Nomination Confirmed", "yeas": 50, "nays": 50}, {"name": "Confirming Robert F. Kennedy Jr.", "desc": "February 13, 2025. Health and Human Services: America's most famous vaccine skeptic, bearer of its most famous Democratic name, atop a $1.7 trillion health apparatus. He promises senators he won't touch the childhood vaccine schedule and pitches a war on chronic disease. The chamber's doctors face the hardest choice of the season.", "votes": {"collins": "yea", "murkowski": "yea", "mcconnell": "nay", "fetterman": "nay", "curtis": "yea"}, "notes": {}, "date": "February 13, 2025", "question": "On the Nomination PN11-8", "result": "Nomination Confirmed", "yeas": 52, "nays": 48}, {"name": "Confirming Kash Patel", "desc": "February 20, 2025. FBI director: a former public defender and Trump-administration aide who wrote a book naming 'deep state' officials and has vowed to overhaul the bureau top to bottom. Supporters call the FBI overdue for it; critics hear an enemies list. The ten-year term is designed to outlast presidents \u2014 this one starts with a two-vote margin.", "votes": {"collins": "nay", "murkowski": "nay", "mcconnell": "yea", "fetterman": "nay", "curtis": "yea"}, "notes": {}, "date": "February 20, 2025", "question": "On the Nomination PN12-35", "result": "Nomination Confirmed", "yeas": 51, "nays": 49}]}, {"id": "this-congress", "title": "This Congress", "era": "119th Congress \u00b7 2025", "intro": "Unified Republican government moves at reconciliation speed: an immigration bill in January, a megabill by July, and a test of whether Congress will claw back its own appropriations.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Chairing Appropriations in a year the White House treats spending laws as suggestions, Maine's moderate is defending both her committee's power and a 2026 re-election in a state that votes blue for president.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's dealmaker drives the hardest bargains of the year \u2014 carve-outs for her state are her price, and she describes her biggest vote of the summer as 'agonizing.' Nobody works a 50-50 chamber better.", "photo": "photos/M001153.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "Kentucky's libertarian is the loneliest kind of consistent: for the spending cuts, against the debt- ceiling increases, and immune to pressure from a White House he often votes against and never stops praising.", "photo": "photos/P000603.jpg"}, {"key": "fetterman", "name": "John Fetterman", "party": "D", "state": "PA", "blurb": "The Senate's most unpredictable Democrat: pro-border- enforcement, pro-Israel, and openly bored by his party's orthodoxies \u2014 but a Medicaid vote is a different animal in a state with 3 million enrollees.", "photo": "photos/F000479.jpg"}, {"key": "tillis", "name": "Thom Tillis", "party": "R", "state": "NC", "blurb": "North Carolina's pragmatist announced he won't seek re-election \u2014 one day after the President threatened to primary him over the megabill. A lame duck now, with eighteen months left and nothing to lose.", "photo": "photos/T000476.jpg"}], "bills": [{"name": "The Laken Riley Act", "desc": "January 20, 2025 \u2014 inauguration day. The new Congress's first bill: mandatory federal detention for undocumented immigrants charged with theft, burglary, or assaulting a police officer, and standing for state attorneys general to sue federal immigration authorities. Named for the Georgia nursing student murdered by a Venezuelan man in the country illegally. A dozen Democrats are ready to sign on.", "votes": {"collins": "yea", "murkowski": "yea", "rpaul": "yea", "fetterman": "yea", "tillis": "yea"}, "notes": {}, "date": "January 20, 2025", "question": "On Passage of the Bill S. 5", "result": "Bill Passed", "yeas": 64, "nays": 35}, {"name": "The One Big Beautiful Bill", "desc": "July 1, 2025, after a 27-hour vote-a-rama. The reconciliation megabill: the 2017 tax cuts made permanent, no taxes on tips and overtime, a huge border and defense buildup \u2014 paid for in part by Medicaid work requirements and provider-tax cuts projected to leave millions uninsured, plus a $5 trillion debt-limit increase. The tally stands at 50-50; the Vice President is in the chair.", "votes": {"collins": "nay", "murkowski": "yea", "rpaul": "nay", "fetterman": "nay", "tillis": "nay"}, "notes": {}, "date": "July 1, 2025", "question": "On Passage of the Bill H.R. 1", "result": "Bill Passed", "yeas": 50, "nays": 50}, {"name": "The $9 Billion Clawback", "desc": "July 17, 2025, 2:18 a.m. A rescissions package canceling money Congress already appropriated: roughly $8 billion in foreign aid and $1.1 billion for the Corporation for Public Broadcasting \u2014 the funding stream behind NPR and PBS stations. The White House calls it a down payment on DOGE's cuts; appropriators in both parties call it a dangerous precedent.", "votes": {"collins": "nay", "murkowski": "nay", "rpaul": "yea", "fetterman": "nay", "tillis": "yea"}, "notes": {}, "date": "July 17, 2025", "question": "On Passage of the Bill H.R. 4", "result": "Bill Passed", "yeas": 51, "nays": 48}]}, {"id": "the-trial", "title": "The Trial of the President", "era": "106th Congress \u00b7 1999", "intro": "For the first time in 131 years, the Senate convenes as a court of impeachment: one hundred senators sworn to impartial justice, the Chief Justice presiding, sixty-seven votes needed to remove a president.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's junior senator, two years in: methodical, moderate, and visibly uncomfortable with both the President's conduct and the House managers' case. She spent the trial drafting compromise 'findings of fact' that went nowhere.", "photo": "photos/C001035.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "Arizona's hawk, weeks from announcing a presidential run built on candor and character. He has kept his counsel through the trial while his party splinters between constitutional duty and political survival.", "photo": "photos/M000303.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Senate's institutional memory, treating the trial with liturgical seriousness. He moved to dismiss the case in January \u2014 while pronouncing the President's conduct indefensible. Both sides claim him; neither is sure.", "photo": "photos/B001210.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "Wisconsin's civil-libertarian contrarian \u2014 the only Democrat to vote against dismissing the charges, on the theory that the Constitution was owed a full trial. Where the verdict is concerned, the theory guarantees nothing.", "photo": "photos/F000061.jpg"}, {"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "The former Philadelphia district attorney, a juror with his own jurisprudence: unimpressed by the House managers' evidence, unwilling to bless the White House's conduct, and muttering about verdicts American law doesn't offer.", "photo": "photos/S000709.jpg"}], "bills": [{"name": "Article I: Perjury", "desc": "February 12, 1999. The first article charges President Clinton with lying to a federal grand jury about his relationship with Monica Lewinsky. A vote of GUILTY is a vote to convict and remove the 42nd President; two-thirds \u2014 67 senators \u2014 are required. The public's verdict is already in: his approval sits near 65 percent.", "votes": {"collins": "nay", "mccain": "yea", "byrd": "nay", "feingold": "nay", "specter": "nay"}, "notes": {}, "labels": ["GUILTY", "NOT GUILTY"], "date": "February 12, 1999", "question": "Article I of the Articles of Impeachment \u2014 Guilty or Not Guilty", "result": "Acquitted", "yeas": 45, "nays": 55}, {"name": "Article II: Obstruction of Justice", "desc": "The second article charges a scheme to conceal the affair: coaching witnesses, hiding gifts under subpoena, job-hunting for a grand-jury witness. It drew more votes in the House than perjury and is considered the managers' stronger case. GUILTY convicts and removes; sixty-seven still required.", "votes": {"collins": "nay", "mccain": "yea", "byrd": "nay", "feingold": "nay", "specter": "nay"}, "notes": {}, "labels": ["GUILTY", "NOT GUILTY"], "date": "February 12, 1999", "question": "Article II of the Articles of Impeachment \u2014 Guilty or Not Guilty", "result": "Acquitted", "yeas": 50, "nays": 50}, {"name": "Air War Over Kosovo", "desc": "March 23, 1999 \u2014 six weeks after the trial ends. Slobodan Milosevic's forces are purging Kosovo's Albanians, and NATO's bombers are hours from launching. The resolution authorizes air and missile operations against Yugoslavia: the same senators who just judged this president now decide whether to follow him to war.", "votes": {"collins": "nay", "mccain": "yea", "byrd": "yea", "feingold": "nay", "specter": "yea"}, "notes": {}, "date": "March 23, 1999", "question": "On the Concurrent Resolution S.Con.Res. 21", "result": "Concurrent Resolution Agreed to", "yeas": 58, "nays": 41}]}, {"id": "values-election", "title": "The Values Election", "era": "108th Congress \u00b7 2004", "intro": "San Francisco is issuing marriage licenses, Massachusetts courts have legalized same-sex marriage, and the assault-weapons ban is expiring \u2014 all in a presidential year. Karl Rove has done the math; the Senate does the voting.", "senators": [{"key": "santorum", "name": "Rick Santorum", "party": "R", "state": "PA", "blurb": "The Senate's third-ranking Republican and its most fervent culture warrior, floor general for the marriage amendment. Pennsylvania is purple, but Santorum has never trimmed a conviction to fit a state.", "photo": "photos/S000059.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "A conservative with a constitutionalist's allergy to amending the founding document for politics \u2014 and a westerner's suspicion of gun laws. In a wedge-issue year, he is nobody's reliable wedge.", "photo": "photos/M000303.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's moderate: pro-choice, supportive of gay rights by her party's standards, and no friend of the gun lobby's scorecard. Election-year social policy is exactly the terrain she least enjoys.", "photo": "photos/C001035.jpg"}, {"key": "boxer", "name": "Barbara Boxer", "party": "D", "state": "CA", "blurb": "California's liberal warhorse, happy to lose culture-war votes loudly if losing sharpens the contrast for November.", "photo": "photos/B000711.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "West Virginia's patriarch: a traditionalist on marriage and faith, a skeptic of constitutional tinkering, and harder to handicap on guns than the scorecards assume. He answers to the Constitution and to West Virginia, in that order.", "photo": "photos/B001210.jpg"}], "bills": [{"name": "Renewing the Assault Weapons Ban", "desc": "March 2, 2004. Feinstein's amendment extends the 1994 assault-weapons ban for ten more years, ahead of its September expiration \u2014 attached to a bill shielding gunmakers from lawsuits. The NRA has already passed word that if the amendment sticks, the whole bill should die.", "votes": {"santorum": "nay", "mccain": "nay", "collins": "yea", "boxer": "yea", "byrd": "yea"}, "notes": {}, "date": "March 2, 2004", "question": "On the Amendment S.Amdt. 2637 to S. 1805 (Protection of Lawful Commerce in Arms Act)", "result": "Amendment Agreed to", "yeas": 52, "nays": 47}, {"name": "The Unborn Victims of Violence Act", "desc": "March 25, 2004. Laci Peterson's name is on the news and on this bill: harming a fetus during a federal crime becomes a separate offense, with 'child in utero' defined in federal law for the first time. Abortion-rights groups see a foundation stone being laid; supporters say it simply names a second victim.", "votes": {"santorum": "yea", "mccain": "yea", "collins": "yea", "boxer": "nay", "byrd": "nay"}, "notes": {}, "date": "March 25, 2004", "question": "On Passage of the Bill H.R. 1997", "result": "Bill Passed", "yeas": 61, "nays": 38}, {"name": "The Federal Marriage Amendment", "desc": "July 14, 2004. A constitutional amendment defining marriage as the union of one man and one woman, scheduled four months before the election. Sixty votes are needed just to take it up, and nobody pretends the count is close \u2014 the roll call itself is the point. A yea advances the amendment.", "votes": {"santorum": "yea", "mccain": "nay", "collins": "nay", "boxer": "nay", "byrd": "yea"}, "notes": {}, "date": "July 14, 2004", "question": "On the Cloture Motion S.J.Res. 40", "result": "Cloture Motion Rejected", "yeas": 48, "nays": 50}]}, {"id": "lame-duck-miracle", "title": "The Lame-Duck Miracle", "era": "111th Congress \u00b7 December 2010", "intro": "After a midterm 'shellacking,' everyone expected the 111th Congress to limp home. Instead, three frantic December weeks produce a tax deal, a nuclear treaty, and one heartbreak \u2014 sometimes in the same afternoon.", "senators": [{"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "Vermont's socialist, fresh off an eight-and-a-half-hour floor speech against the President's tax compromise \u2014 instantly dubbed a filibuster, instantly a folk legend on the left. Compromise, he argues, is how the rich keep winning.", "photo": "photos/S000033.jpg"}, {"key": "lugar", "name": "Richard Lugar", "party": "R", "state": "IN", "blurb": "The Republicans' elder statesman on arms control, co-author of the program that dismantled loose Soviet warheads. Increasingly out of step with his party's new insurgent wing \u2014 and increasingly untroubled by it.", "photo": "photos/L000504.jpg"}, {"key": "kyl", "name": "Jon Kyl", "party": "R", "state": "AZ", "blurb": "The Republican whip and the man the White House must satisfy on the nuclear treaty. He has spent months extracting billions for modernizing the weapons labs \u2014 and the administration still isn't sure it has his vote.", "photo": "photos/K000352.jpg"}, {"key": "tester", "name": "Jon Tester", "party": "D", "state": "MT", "blurb": "A flat-topped organic farmer from Big Sandy, Montana, facing re-election in 2012 in a state swinging hard against his party. Every vote this month gets weighed against a general election two years out.", "photo": "photos/T000464.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's Republican, who lost her primary to a Tea Party challenger and then won in November anyway on write-in ballots \u2014 the first senator to manage it since 1954. She now owes the party establishment exactly nothing.", "photo": "photos/M001153.jpg"}], "bills": [{"name": "The Obama-McConnell Tax Deal", "desc": "December 15, 2010. The grand bargain nobody loves: every Bush tax cut extended two years \u2014 top earners included \u2014 in exchange for 13 months of unemployment benefits, a payroll-tax holiday, and an estate tax with a $5 million exemption. The left calls it capitulation; the White House calls it the only deal on offer.", "votes": {"sanders": "nay", "lugar": "yea", "kyl": "yea", "tester": "yea", "murkowski": "yea"}, "notes": {}, "date": "December 15, 2010", "question": "On the Motion (Motion to Concur in the House Amdt. to the Senate Amdt. with Amdt. No. 4753 to H.R. 4853)", "result": "Motion Agreed to", "yeas": 81, "nays": 19}, {"name": "The DREAM Act", "desc": "December 18, 2010, a Saturday morning. Cloture on the DREAM Act: legal status for young immigrants brought to the country as children who finish college or enlist in the military. It has majority support and the Pentagon's blessing \u2014 what it needs is 60 votes, and the outcome turns on a handful of red-state Democrats.", "votes": {"sanders": "yea", "lugar": "yea", "kyl": "nay", "tester": "nay", "murkowski": "yea"}, "notes": {}, "date": "December 18, 2010", "question": "On the Cloture Motion H.R. 5281", "result": "Cloture Motion Rejected", "yeas": 55, "nays": 41}, {"name": "The New START Treaty", "desc": "December 22, 2010. A U.S.\u2013Russia treaty cutting deployed strategic warheads to 1,550 apiece, with inspections restored after a year's lapse. Every living Republican former secretary of state endorses it; the party's Senate leadership does not. Ratification takes 67 votes, and the Vice President is working the cloakroom personally.", "votes": {"sanders": "yea", "lugar": "yea", "kyl": "nay", "tester": "yea", "murkowski": "yea"}, "notes": {}, "date": "December 22, 2010", "question": "On the Resolution of Ratification Treaty Doc. 111-5", "result": "Resolution of Ratification Agreed to", "yeas": 71, "nays": 26}]}, {"id": "surge", "title": "The Surge Debates", "era": "110th Congress \u00b7 2007", "intro": "Voters have just handed Congress to the Democrats to end the Iraq war; Bush answers with 21,500 more troops. Every few months the Senate takes up the same question \u2014 can sixty votes stop a war? \u2014 and the arithmetic never quite works.", "senators": [{"key": "jwarner", "name": "John Warner", "party": "R", "state": "VA", "blurb": "Virginia's courtly elder statesman: five terms, a former Navy Secretary, the Republican whose doubts about the surge carry the most weight. He wrote a resolution against it \u2014 and hates handing Democrats procedural victories almost as much.", "photo": "photos/W000154.jpg"}, {"key": "hagel", "name": "Chuck Hagel", "party": "R", "state": "NE", "blurb": "A Vietnam infantry sergeant with two Purple Hearts, now the Republicans' fiercest Iraq apostate \u2014 he has called the surge the most dangerous foreign-policy blunder since Vietnam, out loud, in committee.", "photo": "photos/H001028.jpg"}, {"key": "lieberman_i", "name": "Joe Lieberman", "party": "I", "state": "CT", "blurb": "Re-elected as an independent after Democrats primaried him over the war, and freer than ever: the surge's most devoted Senate defender, caucusing with a party that can barely look at him.", "photo": "photos/L000304.jpg"}, {"key": "clinton", "name": "Hillary Clinton", "party": "D", "state": "NY", "blurb": "The Democratic frontrunner, whose 2002 war vote shadows every primary event. She is walking backward out of Iraq \u2014 deliberately, vote by vote, without ever quite saying the word 'mistake.'", "photo": "photos/C001041.jpg"}, {"key": "webb", "name": "Jim Webb", "party": "D", "state": "VA", "blurb": "Virginia's freshman: decorated Marine, novelist, Reagan's Navy Secretary, elected on opposition to the war his son is fighting as a lance corporal. Subtle as an ambush, and about as friendly to the White House.", "photo": "photos/W000803.jpg"}], "bills": [{"name": "Debating the Surge", "desc": "February 17, 2007 \u2014 a rare Saturday session. The House has passed a resolution disapproving the 21,500-troop escalation; this cloture vote decides whether the Senate may even take it up. Sixty votes needed. A yea advances the rebuke of the surge; a nay keeps it off the floor.", "votes": {"jwarner": "yea", "hagel": "yea", "lieberman_i": "nay", "clinton": "yea", "webb": "yea"}, "notes": {}, "date": "February 17, 2007", "question": "On the Cloture Motion S. 574", "result": "Cloture Motion Rejected", "yeas": 56, "nays": 34}, {"name": "The Levin-Reed Withdrawal Plan", "desc": "July 18, 2007, after an all-night session complete with cots in the cloakrooms. Levin-Reed would order withdrawal to begin within 120 days, with most troops out by April 2008. Sixty votes to advance \u2014 and 'wait for General Petraeus's September report' has become the Republican refrain.", "votes": {"jwarner": "nay", "hagel": "yea", "lieberman_i": "nay", "clinton": "yea", "webb": "yea"}, "notes": {}, "date": "July 18, 2007", "question": "On the Motion (Motion to Invoke Cloture on the Levin Amdt. No. 2087)", "result": "Motion Rejected", "yeas": 52, "nays": 47}, {"name": "The Kyl-Lieberman Iran Amendment", "desc": "September 26, 2007. A sense-of-the-Senate measure urging that Iran's Revolutionary Guard be designated a terrorist organization for arming Shiite militias in Iraq. Supporters call it pressure; opponents hear the opening argument for the next war. For the candidates in the room, this vote will be quoted back for years.", "votes": {"jwarner": "yea", "hagel": "nay", "lieberman_i": "yea", "clinton": "yea", "webb": "nay"}, "notes": {}, "date": "September 26, 2007", "question": "On the Amendment S.Amdt. 3017 to S.Amdt. 2011 to H.R. 1585 (National Defense Authorization Act for Fiscal Year 2008)", "result": "Amendment Agreed to", "yeas": 76, "nays": 22}]}, {"id": "divided-2019", "title": "Divided Government", "era": "116th Congress \u00b7 2019", "intro": "A record 35-day shutdown ends, a national emergency begins, and an odd-couple coalition tries to end a war. In 2019 the interesting line isn't between the parties \u2014 it's inside them.", "senators": [{"key": "mlee", "name": "Mike Lee", "party": "R", "state": "UT", "blurb": "Utah's constitutional obsessive: a Federalist Society conservative who backs Trump on judges and taxes but treats executive overreach as original sin \u2014 whichever president is doing the reaching. He co-sponsors the Yemen resolution with Bernie Sanders.", "photo": "photos/L000577.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "The Vermont socialist, weeks into his second presidential campaign, using the Senate floor to force votes on ending American support for the Saudi war in Yemen.", "photo": "photos/S000033.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Twenty-two years in and staring down a brutal 2020 race, the Maine moderate is the first name on every whip list \u2014 praised as an institutionalist at home, pilloried as a fence-sitter everywhere else.", "photo": "photos/C001035.jpg"}, {"key": "rubio", "name": "Marco Rubio", "party": "R", "state": "FL", "blurb": "Florida's hawk: a believer in American power abroad and the Saudi alliance, but also a Cuban-American with long memories about presidents who rule by decree.", "photo": "photos/R000595.jpg"}, {"key": "tester", "name": "Jon Tester", "party": "D", "state": "MT", "blurb": "A flat-topped dirt farmer from Big Sandy, Montana \u2014 a seven-fingered Democrat who won three times in Trump country by voting like Montana and sounding like it too.", "photo": "photos/T000464.jpg"}], "bills": [{"name": "Ending the Shutdown Fight", "desc": "February 14, 2019. After the longest government shutdown in history \u2014 35 days over border-wall money \u2014 the conference deal funds the government through September with $1.375 billion for 55 miles of fencing, a fraction of the $5.7 billion the President demanded. Trump will sign it the next day \u2014 and, the same morning, declare a national emergency to get the rest.", "votes": {"mlee": "nay", "sanders": "yea", "collins": "yea", "rubio": "nay", "tester": "yea"}, "notes": {}, "date": "February 14, 2019", "question": "On the Conference Report H.J.Res. 31", "result": "Conference Report Agreed to", "yeas": 83, "nays": 16}, {"name": "Yemen War Powers Resolution", "desc": "March 13, 2019. The Sanders-Lee resolution directs the removal of U.S. forces from hostilities in Yemen's civil war \u2014 the refueling, targeting help, and intelligence sustaining the Saudi bombing campaign \u2014 invoking the 1973 War Powers Act against a sitting president for the first time. The White House promises a veto.", "votes": {"mlee": "yea", "sanders": "yea", "collins": "yea", "rubio": "nay", "tester": "yea"}, "notes": {}, "date": "March 13, 2019", "question": "On the Joint Resolution S.J.Res. 7", "result": "Joint Resolution Passed", "yeas": 54, "nays": 46}, {"name": "Terminating the Border Emergency", "desc": "March 14, 2019. One day later: a resolution terminating the national emergency Trump declared to move military construction money to the border wall after Congress refused to appropriate it. The question splits constitutional conservatives from the White House: can a president spend what Congress declined to give him?", "votes": {"mlee": "yea", "sanders": "yea", "collins": "yea", "rubio": "yea", "tester": "yea"}, "notes": {}, "date": "March 14, 2019", "question": "On the Joint Resolution H.J.Res. 46", "result": "Joint Resolution Passed", "yeas": 59, "nays": 41}]}, {"id": "after-the-storm", "title": "After the Storm", "era": "113th\u2013115th Congress \u00b7 2013\u20132017", "intro": "When catastrophe strikes someone else's state, is disaster aid basic duty or a budget-busting grab bag? Watch the storms move around the map \u2014 from the Jersey Shore to San Juan to Houston \u2014 and watch the answers move with them.", "senators": [{"key": "cruz", "name": "Ted Cruz", "party": "R", "state": "TX", "blurb": "Texas's constitutionalist firebrand, sworn in this month promising to fight spending wherever he finds it. Emergency bills, he argues, have become Christmas trees for unrelated pork \u2014 a principle that will be tested repeatedly from here.", "photo": "photos/C001098.jpg"}, {"key": "rubio", "name": "Marco Rubio", "party": "R", "state": "FL", "blurb": "Florida's Republican, a hurricane-state senator with national ambitions, caught between Tea Party fiscal doctrine and the certainty that his own coastline's turn is always coming.", "photo": "photos/R000595.jpg"}, {"key": "schumer", "name": "Chuck Schumer", "party": "D", "state": "NY", "blurb": "New York's champion appropriator, whose city just watched the ocean pour into its subway tunnels. He keeps a long and precise memory of who voted for his state in its emergency \u2014 and who did not.", "photo": "photos/S000148.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's pragmatist, a senior appropriator who treats disaster relief as the federal government doing its most basic job. She has little patience for turning emergencies into budget seminars.", "photo": "photos/C001035.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "Kentucky's libertarian deficit absolutist: every dollar of emergency aid, he insists, should be offset by cuts somewhere else. Debt restructuring that costs taxpayers nothing, though \u2014 that can be a different question.", "photo": "photos/P000603.jpg"}], "bills": [{"name": "Superstorm Sandy Relief", "desc": "January 28, 2013 \u2014 three months after Sandy drowned the Northeast, killing more than 100 Americans and doing roughly $65 billion in damage. A $50.5 billion aid package for New York and New Jersey, none of it offset, after House conservatives already stalled it once. Northeastern Republicans are livid at their own party; fiscal hawks call parts of it pork.", "votes": {"cruz": "nay", "rubio": "nay", "schumer": "yea", "collins": "yea", "rpaul": "nay"}, "notes": {}, "date": "January 28, 2013", "question": "On Passage of the Bill H.R. 152", "result": "Bill Passed", "yeas": 62, "nays": 36}, {"name": "PROMESA \u2014 The Puerto Rico Rescue", "desc": "June 29, 2016. Puerto Rico owes $70 billion it cannot pay, and a $2 billion default arrives July 1. PROMESA: no taxpayer bailout, but a federal oversight board with power to restructure the island's debt \u2014 and, critics note, to overrule its elected government. Bondholders object; so do Puerto Ricans who see a colonial junta in all but name.", "votes": {"cruz": "nay", "rubio": "yea", "schumer": "yea", "collins": "yea", "rpaul": "yea"}, "notes": {}, "date": "June 29, 2016", "question": "On the Motion (Motion to Concur in the House Amendment to S. 2328)", "result": "Motion Agreed to", "yeas": 68, "nays": 30}, {"name": "Harvey, Irma & Maria \u2014 the Disaster Bill", "desc": "October 24, 2017. After a season that flooded Houston, flattened the Florida Keys, and left Puerto Rico's grid dark, a $36.5 billion package: hurricane and wildfire relief, and debt forgiveness for the drowning federal flood-insurance program. For two senators who voted no on Sandy aid, the storms now sit in their own backyards.", "votes": {"cruz": "yea", "rubio": "yea", "schumer": "yea", "collins": "yea", "rpaul": "nay"}, "notes": {}, "date": "October 24, 2017", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.R. 2266)", "result": "Motion Agreed to", "yeas": 82, "nays": 17}]}, {"id": "first-trial", "title": "The First Trial", "era": "116th Congress \u00b7 2019\u20132020", "intro": "A president stands trial in the Senate for the third time in American history. For the senators who might break ranks, every vote \u2014 on his war powers, on his removal \u2014 is a test of how much defiance costs.", "senators": [{"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "Utah's freshman is also the party's 2012 presidential nominee \u2014 a devout institutionalist who announced his Senate run with an essay condemning Trump's character. He talks about his oath, his conscience, and his father's example. Constantly.", "photo": "photos/R000615.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The Maine moderate faces the toughest re-election of her life in a state Trump lost. She voted to force witness testimony at the trial, and says the President has learned 'a pretty big lesson' from impeachment itself.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's write-in survivor answers to no party machine. She called the House process rushed and the Senate trial 'shameful' on all sides \u2014 while leaving everyone guessing where that leaves her.", "photo": "photos/M001153.jpg"}, {"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "A West Virginia Democrat in a state Trump carried by 42 points, personally friendly with the President and publicly agonized. He spends the trial's final week floating a censure resolution instead.", "photo": "photos/M001183.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The majority leader, who has said plainly he is 'not an impartial juror' and is coordinating trial strategy with the White House. His priority is protecting his majority \u2014 and ending this quickly.", "photo": "photos/M000355.jpg"}], "bills": [{"name": "Yemen War Powers \u2014 Veto Override", "desc": "May 2, 2019. Congress passed a resolution ordering an end to U.S. military support for the Saudi-led war in Yemen \u2014 the first war-powers resolution ever to reach a president's desk \u2014 and Trump vetoed it. Now the override vote: a two-thirds majority to reclaim Congress's war power over the President's objection, with the humanitarian toll in Yemen mounting.", "votes": {"romney": "nay", "collins": "yea", "murkowski": "yea", "manchin": "yea", "mcconnell": "nay"}, "notes": {}, "date": "May 2, 2019", "question": "On Overriding the Veto S.J.Res. 7", "result": "Veto Sustained", "yeas": 53, "nays": 45}, {"name": "Article I: Abuse of Power", "desc": "February 5, 2020. The first article of impeachment charges the President with pressuring Ukraine to investigate the Bidens while withholding $391 million in military aid. Each senator stands at their desk to pronounce him guilty or not guilty; a two-thirds vote convicts and removes him from office. No senator has ever voted to remove a president of his own party.", "votes": {"romney": "yea", "collins": "nay", "murkowski": "nay", "manchin": "yea", "mcconnell": "nay"}, "notes": {}, "labels": ["GUILTY", "NOT GUILTY"], "date": "February 5, 2020", "question": "Guilty or Not Guilty H.Res. 755", "result": "Not Guilty", "yeas": 48, "nays": 52}, {"name": "Article II: Obstruction of Congress", "desc": "Minutes later, the second article: obstruction of Congress, for the White House's blanket refusal to provide witnesses or documents to the House inquiry. Some senators see a categorical stonewall without precedent; others see a legitimate assertion of executive privilege that the House never tested in court. Again, two-thirds to convict.", "votes": {"romney": "nay", "collins": "nay", "murkowski": "nay", "manchin": "yea", "mcconnell": "nay"}, "notes": {}, "labels": ["GUILTY", "NOT GUILTY"], "date": "February 5, 2020", "question": "Guilty or Not Guilty H.Res. 755", "result": "Not Guilty", "yeas": 47, "nays": 53}]}, {"id": "crime-and-trade", "title": "Crime & Punishment", "era": "103rd Congress \u00b7 1994", "intro": "A midterm year with crime atop every poll. Judiciary sends a justice to the Court and a crime bill to the floor \u2014 then a lame-duck Senate takes up the biggest trade deal in history.", "senators": [{"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "Judiciary's chairman and the crime bill's proud author \u2014 a Delaware dealmaker who has spent years positioning Democrats as the party of cops, prisons, and prevention money alike.", "photo": "photos/B000444.jpg"}, {"key": "hatch", "name": "Orrin Hatch", "party": "R", "state": "UT", "blurb": "Utah's courtly conservative, Judiciary's ranking Republican. He'll bless a qualified nominee of either party \u2014 but he has been savaging the crime bill's prevention spending as social work wearing a badge.", "photo": "photos/H000338.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "A first-term Wisconsin reformer with a contrarian streak: deficit-minded, suspicious of Washington consensus, and unbothered by votes that leave both parties squinting.", "photo": "photos/F000061.jpg"}, {"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "'Senator No.' Law-and-order to his boots, protectionist where tobacco and textiles are concerned, and reflexively against anything blessed by the editorial pages.", "photo": "photos/H000463.jpg"}, {"key": "mikulski", "name": "Barbara Mikulski", "party": "D", "state": "MD", "blurb": "Baltimore's four-foot-eleven force of nature, a former social worker who climbed from the city council to the Appropriations Committee. Practical, blunt, and loyal to the party's working-class base.", "photo": "photos/M000702.jpg"}], "bills": [{"name": "Confirming Stephen Breyer", "desc": "July 29, 1994. Clinton's second Supreme Court pick in two years: a Harvard professor and appeals judge, an antitrust technician praised by both parties' legal establishments. After the Bork and Thomas wars, the hearings were almost soothing.", "votes": {"biden": "yea", "hatch": "yea", "feingold": "yea", "helms": "nay", "mikulski": "yea"}, "notes": {}, "date": "July 29, 1994", "question": "On the Nomination PN1399", "result": "Nomination Confirmed", "yeas": 87, "nays": 9}, {"name": "The 1994 Crime Bill", "desc": "August 25, 1994. The conference report: $30 billion for 100,000 new police officers, new federal death penalties, three-strikes sentencing, and the assault-weapons ban \u2014 plus prevention programs Republicans mock as 'midnight basketball.' After the package nearly died in the House, most of the GOP has turned against a bill many of them helped shape.", "votes": {"biden": "yea", "hatch": "nay", "feingold": "nay", "helms": "nay", "mikulski": "yea"}, "notes": {}, "date": "August 25, 1994", "question": "On the Conference Report H.R. 3355", "result": "Conference Report Agreed to", "yeas": 61, "nays": 38}, {"name": "The GATT World Trade Deal", "desc": "December 1, 1994 \u2014 a lame-duck session weeks after the Republican landslide. The Uruguay Round: tariff cuts across 123 nations and a new World Trade Organization to referee them. Business is united in favor; an odd alliance of labor Democrats, sovereignty conservatives, and Perot voters is not.", "votes": {"biden": "yea", "hatch": "yea", "feingold": "nay", "helms": "nay", "mikulski": "yea"}, "notes": {}, "date": "December 1, 1994", "question": "On Passage of the Bill H.R. 5110", "result": "Bill Passed", "yeas": 76, "nays": 24}]}, {"id": "sending-troops", "title": "Sending the Troops", "era": "103rd\u2013104th Congress \u00b7 1993\u20131995", "intro": "After the Cold War, the question turns strange: when does America send soldiers into other people's wars? Somalia sours everyone; then Bosnia asks the question twice.", "senators": [{"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Republican leader and wounded veteran of the Italian campaign, eyeing the 1996 nomination. He hammers Clinton's foreign policy weekly \u2014 but believes a president's soldiers, once committed, must not be undercut. Bosnia's besieged Muslims have no louder American champion.", "photo": "photos/D000401.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "Vietnam's most famous POW, burned by Beirut and Mogadishu into a hard rule: no troops without a mission, no mission without an exit. He is the Senate's sharpest critic of peacekeeping-by-good-intentions.", "photo": "photos/M000303.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Constitution-pocket institutionalist, Appropriations' master, and the loudest voice demanding Congress \u2014 not presidents \u2014 decide where Americans fight. Nation-building in the Balkans strikes him as folly on stilts.", "photo": "photos/B001210.jpg"}, {"key": "wellstone", "name": "Paul Wellstone", "party": "D", "state": "MN", "blurb": "Minnesota's happy-warrior progressive: a dove by instinct who marched against Vietnam, yet haunted by Bosnia's camps and massacres. Human rights and anti-war principle point in opposite directions here.", "photo": "photos/W000288.jpg"}, {"key": "jwarner", "name": "John Warner", "party": "R", "state": "VA", "blurb": "Virginia's courtly former Navy secretary, the uniformed services' best friend in the chamber. He weighs every deployment like the Pentagon planner he once was \u2014 supportive of soldiers, skeptical of open-ended missions.", "photo": "photos/W000154.jpg"}], "bills": [{"name": "The Somalia Deadline", "desc": "October 15, 1993, after midnight. Twelve days after eighteen Army Rangers died in Mogadishu, the Byrd amendment cuts off funding for the Somalia mission after March 31, 1994, forcing a withdrawal date on the Clinton White House. Some hawks want out even sooner \u2014 this is the compromise between retreat now and staying the course.", "votes": {"dole": "yea", "mccain": "nay", "byrd": "yea", "wellstone": "yea", "jwarner": "yea"}, "notes": {}, "date": "October 15, 1993", "question": "On the Amendment S.Amdt. 1042 to H.R. 3116 (Department of Defense Appropriations Act, 1994)", "result": "Amendment Agreed to", "yeas": 76, "nays": 23}, {"name": "Lifting the Bosnia Arms Embargo", "desc": "July 26, 1995 \u2014 two weeks after Srebrenica, where Serb forces murdered thousands under UN protection. The Dole-Lieberman bill ends U.S. enforcement of the arms embargo so Bosnia's Muslims can arm themselves. Clinton warns it will Americanize the war and promises a veto; supporters answer that the embargo only disarms the victims.", "votes": {"dole": "yea", "mccain": "yea", "byrd": "nay", "wellstone": "yea", "jwarner": "yea"}, "notes": {}, "date": "July 26, 1995", "question": "On Passage of the Bill S. 21", "result": "Bill Passed", "yeas": 69, "nays": 29}, {"name": "Backing the Troops to Bosnia", "desc": "December 13, 1995, 10:44 p.m. The Dayton peace accords are signed, and 20,000 American troops are going to Bosnia to enforce them \u2014 with or without Congress. The Dole-McCain resolution swallows 'reservations' about Clinton's policy but declares support for the soldiers and lets the deployment proceed. Voting no means voting to leave the president's commitment naked.", "votes": {"dole": "yea", "mccain": "yea", "byrd": "yea", "wellstone": "yea", "jwarner": "nay"}, "notes": {}, "date": "December 13, 1995", "question": "On the Joint Resolution S.J.Res. 44", "result": "Joint Resolution Passed", "yeas": 69, "nays": 30}]}, {"id": "coming-out", "title": "The Coming-Out Congress", "era": "113th Congress \u00b7 2013\u20132014", "intro": "In March 2013, Rob Portman becomes the first sitting Republican senator to endorse same-sex marriage \u2014 two years after his son came out to him. That autumn, the Senate votes on workplace discrimination, and the ground visibly shifts.", "senators": [{"key": "portman", "name": "Rob Portman", "party": "R", "state": "OH", "blurb": "Ohio's mild-mannered budget wonk, a former U.S. trade representative and OMB director whose announcement that his son is gay \u2014 and that he now supports same-sex marriage \u2014 made him his party's unlikeliest social pioneer.", "photo": "photos/P000449.jpg"}, {"key": "baldwin", "name": "Tammy Baldwin", "party": "D", "state": "WI", "blurb": "Wisconsin's freshman and the first openly gay person ever elected to the Senate. She has waited a whole career for votes like these \u2014 and still campaigns as a bread-and-butter economic progressive.", "photo": "photos/B001230.jpg"}, {"key": "flake", "name": "Jeff Flake", "party": "R", "state": "AZ", "blurb": "Arizona's new senator, a libertarian-leaning conservative from a Mormon family, genial and hard to predict on social questions \u2014 he backed a version of the gay-rights employment bill as a House member in 2007.", "photo": "photos/F000444.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "Arizona's senior statesman, busier fighting his party's isolationists than its culture warriors. His wife and daughter are outspoken marriage-equality advocates; he is not \u2014 but he bristles at discrimination all the same.", "photo": "photos/M000303.jpg"}, {"key": "pryor", "name": "Mark Pryor", "party": "D", "state": "AR", "blurb": "Arkansas's soft-spoken Democrat, a governor's son and the most vulnerable incumbent of 2014 \u2014 running in a state Obama just lost by 24 points, where every social-issue vote is radioactive.", "photo": "photos/P000590.jpg"}], "bills": [{"name": "The Employment Non-Discrimination Act", "desc": "November 7, 2013. A federal ban on firing workers over sexual orientation or gender identity \u2014 first introduced in 1994, never before passed by either chamber. Religious organizations are exempted. In 29 states it remains legal to fire someone for being gay, and about ten Republicans have signaled they might help make history.", "votes": {"portman": "yea", "baldwin": "yea", "flake": "yea", "mccain": "yea", "pryor": "yea"}, "notes": {}, "date": "November 7, 2013", "question": "On Passage of the Bill S. 815", "result": "Bill Passed", "yeas": 64, "nays": 32}, {"name": "The 2014 Farm Bill", "desc": "February 4, 2014. A five-year, $956 billion farm bill, two years overdue: crop insurance expanded, direct payments abolished, and an $8 billion food-stamp trim that satisfies almost nobody. Rural-state senators of both parties call it survival; fiscal hawks call it logrolling in its purest form.", "votes": {"portman": "yea", "baldwin": "yea", "flake": "nay", "mccain": "nay", "pryor": "yea"}, "notes": {}, "date": "February 4, 2014", "question": "On the Conference Report H.R. 2642", "result": "Conference Report Agreed to", "yeas": 68, "nays": 32}, {"name": "The 'Cromnibus'", "desc": "December 13, 2014, nearing 10 p.m. on a Saturday. A $1.1 trillion package funding the government through September \u2014 negotiated after the midterms, carrying riders that loosen Dodd-Frank's derivatives rules and raise campaign-donation caps. Elizabeth Warren is in open revolt; party leaders on both sides just want to go home.", "votes": {"portman": "nay", "baldwin": "yea", "flake": "nay", "mccain": "nay", "pryor": "yea"}, "notes": {}, "date": "December 13, 2014", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.R. 83)", "result": "Motion Agreed to", "yeas": 56, "nays": 40}]}, {"id": "homeland", "title": "Homeland", "era": "107th Congress \u00b7 2002", "intro": "One year after the attacks: Enron's shredders, WorldCom's restatements, a war debate warming up, and a midterm fought over a new Department of Homeland Security. The Senate spends 2002 deciding how much to trust this president.", "senators": [{"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The octogenarian keeper of Senate prerogative, pocket Constitution at the ready. Speed is the thing he distrusts most in government, and 2002 is a year of nothing but speed.", "photo": "photos/B001210.jpg"}, {"key": "lieberman", "name": "Joe Lieberman", "party": "D", "state": "CT", "blurb": "Connecticut's hawkish moralist \u2014 Gore's former running mate, scourge of corporate misbehavior, and the original author of the homeland-security department the White House opposed for months before embracing it as its own idea.", "photo": "photos/L000304.jpg"}, {"key": "clinton", "name": "Hillary Clinton", "party": "D", "state": "NY", "blurb": "New York's senator, building a national-security r\u00e9sum\u00e9 stone by stone. Her state took the attack; she votes like a senator who intends never to be called soft.", "photo": "photos/C001041.jpg"}, {"key": "gramm", "name": "Phil Gramm", "party": "R", "state": "TX", "blurb": "The free-market economist in his final months before retirement: dismissive of regulatory stampedes, protective of business, and largely past caring what anyone thinks.", "photo": "photos/G000365.jpg"}, {"key": "chafee", "name": "Lincoln Chafee", "party": "R", "state": "RI", "blurb": "The Senate's loneliest Republican: anti-war, pro-environment, wary of executive power. He votes his New England conscience and lets the party fume.", "photo": "photos/C001040.jpg"}], "bills": [{"name": "Sarbanes-Oxley", "desc": "July 25, 2002. Enron evaporated in December; WorldCom confessed to the largest accounting fraud in history three weeks ago. The response: a new audit-oversight board, CEOs personally certifying their books, and prison time for shredding. On final passage, opposition has simply ceased to exist.", "votes": {"byrd": "yea", "lieberman": "yea", "clinton": "yea", "gramm": "yea", "chafee": "yea"}, "notes": {}, "date": "July 25, 2002", "question": "On the Conference Report H.R. 3763", "result": "Conference Report Agreed to", "yeas": 99, "nays": 0}, {"name": "Trade Promotion Authority", "desc": "August 1, 2002. Fast-track returns after an eight-year lapse: Congress binds itself to yes-or-no votes on whatever trade deals the President negotiates. Business calls it essential; labor calls it the NAFTA machine restarted. For Democrats, it's a loyalty test with no comfortable answer.", "votes": {"byrd": "nay", "lieberman": "yea", "clinton": "nay", "gramm": "yea", "chafee": "yea"}, "notes": {}, "date": "August 1, 2002", "question": "On the Conference Report H.R. 3009", "result": "Conference Report Agreed to", "yeas": 64, "nays": 34}, {"name": "The Homeland Security Act", "desc": "November 19, 2002 \u2014 two weeks after a midterm fought largely over this bill. Twenty-two agencies and 170,000 employees fused into the largest new department since the Pentagon, with workforce rules the unions hate and Democrats spent months resisting. The election has settled the argument for most of them.", "votes": {"byrd": "nay", "lieberman": "yea", "clinton": "yea", "gramm": "yea", "chafee": "yea"}, "notes": {}, "date": "November 19, 2002", "question": "On Passage of the Bill H.R. 5005", "result": "Bill Passed", "yeas": 90, "nays": 9}]}, {"id": "border-winter", "title": "The Border Winter", "era": "118th Congress \u00b7 2024", "intro": "Three senators spend four months negotiating the toughest border deal in a generation. It dies in 48 hours. What's left \u2014 foreign aid, surveillance law \u2014 passes at five in the morning.", "senators": [{"key": "lankford", "name": "James Lankford", "party": "R", "state": "OK", "blurb": "Oklahoma's Baptist conservative drew the assignment of a lifetime: negotiate the border deal his party demanded. Then Trump came out against it, the party bolted, and his state GOP censured him. He says he read the bill; he wrote it.", "photo": "photos/L000575.jpg"}, {"key": "cmurphy", "name": "Chris Murphy", "party": "D", "state": "CT", "blurb": "Connecticut's Democratic negotiator, who came up through the gun-safety wars and believes deals with Republicans are still possible \u2014 he traded four months of asylum concessions on that theory.", "photo": "photos/M001169.jpg"}, {"key": "sinema_i", "name": "Kyrsten Sinema", "party": "I", "state": "AZ", "blurb": "The Senate's independent broker completed the negotiating trio. Facing an unwinnable three-way race at home, she'll announce her retirement in March \u2014 freer than ever, and twice as blunt about it.", "photo": "photos/S001191.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "Kentucky's libertarian objector-in-chief: against the border bill's spending, against foreign aid on principle, and willing to hold the floor all night to slow any of it down.", "photo": "photos/P000603.jpg"}, {"key": "fetterman", "name": "John Fetterman", "party": "D", "state": "PA", "blurb": "Pennsylvania's hoodie-clad Democrat has been drifting from the left flank \u2014 blunt about a border 'crisis,' loudly pro-Israel and pro-Ukraine, and openly contemptuous of purity tests from either direction.", "photo": "photos/F000479.jpg"}], "bills": [{"name": "The Border Deal", "desc": "February 7, 2024. Cloture on the $118 billion national security package built around the Lankford-Murphy-Sinema border compromise: a tougher asylum standard, faster removals, and an emergency authority to shut the border when crossings surge \u2014 paired with Ukraine and Israel aid. Trump has denounced it; the Border Patrol union endorsed it. Sixty votes to advance the deal.", "votes": {"lankford": "yea", "cmurphy": "yea", "sinema_i": "yea", "rpaul": "nay", "fetterman": "yea"}, "notes": {}, "date": "February 7, 2024", "question": "On Cloture on the Motion to Proceed H.R. 815", "result": "Cloture on the Motion to Proceed Rejected", "yeas": 49, "nays": 50}, {"name": "The Foreign-Aid Supplemental", "desc": "February 13, 2024, 5:14 a.m. With the border provisions stripped out, the remainder: $60 billion for Ukraine's third year of war, $14 billion for Israel, humanitarian aid for Gaza, and Indo-Pacific deterrence money \u2014 passed at dawn after opponents forced the Senate through a week of all-night sessions.", "votes": {"lankford": "nay", "cmurphy": "yea", "sinema_i": "yea", "rpaul": "nay", "fetterman": "yea"}, "notes": {}, "date": "February 13, 2024", "question": "On Passage of the Bill H.R. 815", "result": "Bill Passed", "yeas": 70, "nays": 29}, {"name": "FISA Section 702 Renewal", "desc": "April 19, 2024, 11:45 p.m. \u2014 fifteen minutes before the government's warrantless-surveillance authority expires. A two-year reauthorization of Section 702, which sweeps up foreigners' communications abroad \u2014 and, incidentally, Americans' messages with them. Civil libertarians in both parties demand a warrant requirement; the intelligence agencies call that unilateral disarmament.", "votes": {"lankford": "yea", "cmurphy": "nay", "sinema_i": "yea", "rpaul": "nay", "fetterman": "yea"}, "notes": {}, "date": "April 19, 2024", "question": "On Passage of the Bill H.R. 7888", "result": "Bill Passed", "yeas": 60, "nays": 34}]}, {"id": "rejected-judges", "title": "The Rejected Judges", "era": "91st Congress \u00b7 1969\u20131970", "intro": "Richard Nixon promised the South a different kind of Supreme Court justice. Twice he sends one up; twice the Senate does something it has not done in decades. Then it kills his airplane, too.", "senators": [{"key": "bayh", "name": "Birch Bayh", "party": "D", "state": "IN", "blurb": "Indiana's boyish second-termer, suddenly the chamber's chief nomination-slayer: he is marshaling the case against Nixon's court picks from the Judiciary Committee while drafting constitutional amendments on the side.", "photo": "photos/B000254.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "Restored to the Senate after his 1964 wipeout and elder statesman of the right: loyal to Nixon's court strategy, contemptuous of federal subsidies \u2014 and of Washington fads of every kind.", "photo": "photos/G000267.jpg"}, {"key": "mcsmith", "name": "Margaret Chase Smith", "party": "R", "state": "ME", "blurb": "The Senate's senior woman, whose vote no leader can take for granted. She weighs nominations like a juror and regards White House pressure as an argument for the other side.", "photo": "photos/S000590.jpg"}, {"key": "fulbright", "name": "J. William Fulbright", "party": "D", "state": "AR", "blurb": "The Arkansas patrician, still running Foreign Relations and still voting Southern on most domestic matters \u2014 though a nominee's competence, he allows, is a separate question from his region.", "photo": "photos/F000401.jpg"}, {"key": "thurmond", "name": "Strom Thurmond", "party": "R", "state": "SC", "blurb": "The architect of Nixon's Southern strategy, now collecting on it: he wants strict constructionists on the Court and considers every rejection a purge of the South.", "photo": "photos/T000254.jpg"}], "bills": [{"name": "Confirming Clement Haynsworth", "desc": "November 13, 1969. Nixon's first try for the Fortas seat: a Fourth Circuit judge from South Carolina. Labor and civil rights groups oppose his record; the fatal wound is ethics \u2014 he sat on cases touching companies in which he held stock. Seventeen Republicans abandon their president.", "votes": {"bayh": "nay", "goldwater": "yea", "mcsmith": "nay", "fulbright": "yea", "thurmond": "yea"}, "notes": {}, "date": "November 13, 1969", "question": "On the Nomination of Clement Haynsworth", "result": "Nomination Rejected", "yeas": 45, "nays": 55}, {"name": "Confirming G. Harrold Carswell", "desc": "April 1970. Nixon's second try: a Florida judge with a 1948 white-supremacy speech in his past and a reversal rate that makes even allies wince \u2014 one defender argues mediocre people deserve representation too. The White House calls opposition an insult to the South and demands party discipline.", "votes": {"bayh": "nay", "goldwater": "yea", "mcsmith": "nay", "fulbright": "nay", "thurmond": "yea"}, "notes": {}, "date": "April 7, 1970", "question": "On the Nomination of G. Harrold Carswell", "result": "Nomination Rejected", "yeas": 45, "nays": 51}, {"name": "Killing the Supersonic Transport", "desc": "December 3, 1970. An amendment striking $290 million for the Boeing SST, America's answer to the Concorde. Backers call it national prestige and 150,000 jobs; a new environmental coalition cites sonic booms, the ozone layer, and a subsidy for businessmen in a hurry. A yea kills the plane.", "votes": {"bayh": "yea", "goldwater": "nay", "mcsmith": "yea", "fulbright": "yea", "thurmond": "nay"}, "notes": {}, "date": "December 3, 1970", "question": "On the Amendment to Strike SST Funding", "result": "Amendment Agreed to", "yeas": 52, "nays": 41}]}, {"id": "overtime", "title": "The Gang of Fourteen", "era": "109th Congress \u00b7 2005", "intro": "The Senate is one vote from the 'nuclear option' \u2014 abolishing judicial filibusters by fiat \u2014 when fourteen senators cut a midnight deal to save the old rules. Two days later, the deal meets John Bolton.", "senators": [{"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The maverick at maximum wattage: chief architect of the Gang of Fourteen compromise, to the fury of conservatives who wanted the filibuster dead. He loves the institution, hates wasteful spending \u2014 and is already running for 2008.", "photo": "photos/M000303.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Senate's 87-year-old constitutional conscience, who gave four floor orations against the nuclear option and joined the Gang to stop it. For him the rules are the republic \u2014 but a deal is a deal.", "photo": "photos/B001210.jpg"}, {"key": "voinovich", "name": "George Voinovich", "party": "R", "state": "OH", "blurb": "Ohio's mild-mannered former governor, a deficit hawk with a stubborn independent streak. He stunned his party by balking at Bolton in committee \u2014 and will plead from the floor, near tears, that the nomination is a mistake.", "photo": "photos/V000126.jpg"}, {"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The freshman phenomenon from Illinois, five months into the job: deferential to Senate customs, wary of looking obstructionist, and taking careful notes on how the chamber's power games are played.", "photo": "photos/O000167.jpg"}, {"key": "graham", "name": "Lindsey Graham", "party": "R", "state": "SC", "blurb": "South Carolina's quick-witted operator, a Gang of Fourteen member who took real heat at home for the deal. A JAG officer and unapologetic hawk: he'll protect the Senate's rules and the President's nominees, in that order \u2014 or is it the other way around?", "photo": "photos/G000359.jpg"}], "bills": [{"name": "The Deal's First Test: Priscilla Owen", "desc": "May 24, 2005 \u2014 twelve hours after the Gang of Fourteen signed its memorandum. Cloture on Priscilla Owen, the Texas justice Democrats have filibustered for four years, now guaranteed a vote as one of the deal's named judges. This roll call measures whether the truce holds: even senators who'll oppose her confirmation must decide whether to let debate end.", "votes": {"mccain": "yea", "byrd": "yea", "voinovich": "yea", "obama": "yea", "graham": "yea"}, "notes": {}, "date": "May 24, 2005", "question": "On the Cloture Motion PN194", "result": "Cloture Motion Agreed to", "yeas": 81, "nays": 18}, {"name": "Ending Debate on John Bolton", "desc": "May 26, 2005. Two days later, the truce meets its limits: cloture on John Bolton, Bush's famously abrasive nominee for UN ambassador, accused of bullying intelligence analysts. Democrats say they're not filibustering \u2014 just demanding documents the White House won't release. Sixty votes ends debate; the Gang's memo covers judges, not ambassadors.", "votes": {"mccain": "yea", "byrd": "nay", "voinovich": "yea", "obama": "nay", "graham": "yea"}, "notes": {}, "date": "May 26, 2005", "question": "On the Cloture Motion PN326", "result": "Cloture Motion Rejected", "yeas": 56, "nays": 42}, {"name": "The Energy Policy Act", "desc": "June 28, 2005. The first big energy law in a decade: loan guarantees for new nuclear plants, subsidies and royalty relief across oil, gas, coal, and ethanol, and daylight-saving time stretched by a month. Critics in both parties call it a grab bag for producers that does nothing about gasoline prices; its authors call it an overdue investment in everything.", "votes": {"mccain": "nay", "byrd": "yea", "voinovich": "yea", "obama": "yea", "graham": "yea"}, "notes": {}, "date": "June 28, 2005", "question": "On Passage of the Bill H.R. 6", "result": "Bill Passed", "yeas": 85, "nays": 12}]}, {"id": "manchin-sinema", "title": "The Manchin-Sinema Show", "era": "117th Congress \u00b7 2021\u20132022", "intro": "In a 50-50 Senate, two Democrats hold the pen on everything \u2014 and three Republican moderates decide what else gets through. Five people, one chamber, and every camera in Washington.", "senators": [{"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "West Virginia's last statewide Democrat, who killed Build Back Better on Fox News Sunday and then spent months secretly negotiating something leaner with Schumer. Coal state, coal portfolio, deciding vote on a climate bill.", "photo": "photos/M001183.jpg"}, {"key": "sinema", "name": "Kyrsten Sinema", "party": "D", "state": "AZ", "blurb": "The Arizonan who curtsied thumbs-down on the minimum wage: a former Green Party activist turned business-friendly enigma who guards the filibuster, loves a bipartisan gang, and negotiates by press blackout.", "photo": "photos/S001191.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The dean of Senate moderates, fresh off a nine-point re-election no pollster predicted. With nothing left to prove, she brokers deals on infrastructure, guns, and marriage \u2014 but taxes and spending are another matter.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's write-in survivor, censured by her state party and running for re-election anyway. Persuadable on nominees, process, and anything that helps Alaska \u2014 immovable when she thinks the base is bluffing.", "photo": "photos/M001153.jpg"}, {"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "Utah's institutionalist, the only Republican who voted to convict Trump twice. He'll join any gang of ten \u2014 and still votes like a Chamber of Commerce Republican on the big-ticket spending.", "photo": "photos/R000615.jpg"}], "bills": [{"name": "Repealing the Vaccine Mandate", "desc": "December 8, 2021. A Congressional Review Act resolution to nullify OSHA's emergency rule requiring vaccination or weekly testing at every employer with 100 or more workers \u2014 84 million people. Under the CRA it needs only a simple majority, which means one or two Democrats decide whether the Senate rebukes the administration's pandemic centerpiece.", "votes": {"manchin": "yea", "sinema": "nay", "collins": "yea", "murkowski": "yea", "romney": "yea"}, "notes": {}, "date": "December 8, 2021", "question": "On the Joint Resolution S.J.Res. 29", "result": "Joint Resolution Passed", "yeas": 52, "nays": 48}, {"name": "Confirming Ketanji Brown Jackson", "desc": "April 7, 2022. The first Black woman nominated to the Supreme Court: a Harvard-trained appellate judge and former federal public defender, replacing the retiring Stephen Breyer. The hearings turned combative over sentencing records, but the outcome hinges on a simple question \u2014 which, if any, Republicans vote yes?", "votes": {"manchin": "yea", "sinema": "yea", "collins": "yea", "murkowski": "yea", "romney": "yea"}, "notes": {}, "date": "April 7, 2022", "question": "On the Nomination PN1783", "result": "Nomination Confirmed", "yeas": 53, "nays": 47}, {"name": "The Inflation Reduction Act", "desc": "August 7, 2022, 3 p.m., after a 27-hour vote-a-rama. The bill nobody saw coming: $369 billion in climate and energy tax credits, Medicare drug-price negotiation, a 15% corporate minimum tax. Built by Manchin and Schumer in secret, rescued when Sinema extracted her final edits \u2014 and passed, if it passes, with zero votes to spare.", "votes": {"manchin": "yea", "sinema": "yea", "collins": "nay", "murkowski": "nay", "romney": "nay"}, "notes": {}, "date": "August 7, 2022", "question": "On Passage of the Bill H.R. 5376", "result": "Bill Passed", "yeas": 50, "nays": 50}]}, {"id": "new-court", "title": "The New Court", "era": "115th Congress \u00b7 2017\u20132018", "intro": "Ten Senate Democrats wake up the morning after the 2016 election representing states Donald Trump just won. For the next two years, every confirmation and every deregulation vote is also a survival decision.", "senators": [{"key": "donnelly", "name": "Joe Donnelly", "party": "D", "state": "IN", "blurb": "Indiana's mild-mannered Democrat, who slipped into the Senate in 2012 past a self-destructing opponent. Trump carried his state by 19 points, and Donnelly's strategy is ostentatious moderation: pro-gun, anti-abortion, and open to the President's judges.", "photo": "photos/D000607.jpg"}, {"key": "tester", "name": "Jon Tester", "party": "D", "state": "MT", "blurb": "Montana's flat-topped dirt farmer, missing three fingers to a childhood meat-grinder accident and proud of the story. Trump won his state by 20; the community banks back home hate Dodd-Frank's paperwork, and Tester listens to his bankers.", "photo": "photos/T000464.jpg"}, {"key": "warren", "name": "Elizabeth Warren", "party": "D", "state": "MA", "blurb": "The resistance's field marshal on economic policy, treating every bank-friendly bill and most Trump nominees as five-alarm fires. Talk of 2020 follows her everywhere, and she does very little to hush it.", "photo": "photos/W000817.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The definitive swing vote, suddenly the most powerful moderate in Washington. She evaluates judicial nominees on qualifications rather than ideology, she insists \u2014 and extracts her price on everything else.", "photo": "photos/C001035.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's independent-minded Republican, fresh off helping sink Obamacare repeal. She answers to Alaska rather than to any leader \u2014 on energy, on courts, and on everything in between.", "photo": "photos/M001153.jpg"}], "bills": [{"name": "Confirming Neil Gorsuch", "desc": "April 7, 2017. The seat held open for 14 months after Antonin Scalia's death \u2014 past Merrick Garland's ignored nomination \u2014 goes to a Colorado appellate judge with impeccable conservative credentials. Democrats mounted the first successful partisan filibuster of a Court nominee in history; Republicans answered by abolishing the filibuster for Supreme Court picks. A simple majority now confirms.", "votes": {"donnelly": "yea", "tester": "nay", "warren": "nay", "collins": "yea", "murkowski": "yea"}, "notes": {}, "date": "April 7, 2017", "question": "On the Nomination PN55", "result": "Nomination Confirmed", "yeas": 54, "nays": 45}, {"name": "Rolling Back Dodd-Frank", "desc": "March 14, 2018. The biggest loosening of bank rules since the financial crisis: the threshold for strictest federal oversight raised from $50 billion in assets to $250 billion, with paperwork relief for community lenders \u2014 written hand-in-hand with a dozen red-state Democrats. Elizabeth Warren brands it the 'Bank Lobbyist Act'; sponsors call it common sense for Main Street.", "votes": {"donnelly": "yea", "tester": "yea", "warren": "nay", "collins": "yea", "murkowski": "yea"}, "notes": {}, "date": "March 14, 2018", "question": "On Passage of the Bill S. 2155", "result": "Bill Passed", "yeas": 67, "nays": 31}, {"name": "Saving Net Neutrality", "desc": "May 16, 2018. A resolution to overturn the FCC's repeal of net-neutrality rules \u2014 the Obama-era ban on internet providers blocking or throttling traffic. It needs only a bare majority, Democrats are unanimous, and the vote is engineered to put Republicans on the record before the midterms. The House will never take it up; everyone votes anyway.", "votes": {"donnelly": "yea", "tester": "yea", "warren": "yea", "collins": "yea", "murkowski": "yea"}, "notes": {}, "date": "May 16, 2018", "question": "On the Joint Resolution S.J.Res. 52", "result": "Joint Resolution Passed", "yeas": 52, "nays": 47}]}, {"id": "pork-and-torture", "title": "Pork, Torture & PATRIOT", "era": "109th Congress \u00b7 2005", "intro": "Autumn 2005: Katrina's bills arriving, Abu Ghraib's photographs unforgotten, the PATRIOT Act expiring at New Year's. Three fights over what the government may spend \u2014 and what it may do.", "senators": [{"key": "coburn", "name": "Tom Coburn", "party": "R", "state": "OK", "blurb": "'Dr. No.' The Oklahoma obstetrician hunts earmarks for sport, reads appropriations bills for pleasure, and has decided a $220 million bridge to an island of fifty people is the perfect specimen.", "photo": "photos/C000560.jpg"}, {"key": "stevens", "name": "Ted Stevens", "party": "R", "state": "AK", "blurb": "Alaska's Appropriations titan \u2014 thirty-seven years of steering federal concrete north. He wears an Incredible Hulk necktie on days of battle, and touching Alaska's earmarks summons exactly that mood.", "photo": "photos/S000888.jpg"}, {"key": "sununu", "name": "John Sununu", "party": "R", "state": "NH", "blurb": "New Hampshire's engineer-Republican, the chamber's youngest member and one of its few genuine civil libertarians. He has spent months demanding rewrites of the surveillance law his party wants renewed untouched.", "photo": "photos/S001078.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "The PATRIOT Act's original lone dissenter, still insisting the question was never whether to fight terrorism but how much liberty to charge for it.", "photo": "photos/F000061.jpg"}, {"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The freshman celebrity, picking his shots carefully: reformist instincts, a cautious record, and a wary eye on how every vote will read in five years.", "photo": "photos/O000167.jpg"}], "bills": [{"name": "The McCain Torture Amendment", "desc": "October 5, 2005. John McCain's amendment: no cruel, inhuman, or degrading treatment of anyone in U.S. custody, and the Army Field Manual as the single interrogation standard. The White House threatens a veto; Vice President Cheney lobbies for a CIA exemption. McCain, who was tortured in Hanoi, is not negotiating.", "votes": {"coburn": "nay", "stevens": "nay", "sununu": "yea", "feingold": "yea", "obama": "yea"}, "notes": {}, "date": "October 5, 2005", "question": "On the Amendment S.Amdt. 1977 to H.R. 2863 (Department of Defense, Emergency Supplemental Appropriations to Address Hurricanes in the Gulf of Mexico, and Pandemic Influenza Act, 2006)", "result": "Amendment Agreed to", "yeas": 90, "nays": 9}, {"name": "The Bridge to Nowhere", "desc": "October 20, 2005. Coburn's amendment would redirect $220 million from Alaska's Gravina Island bridge \u2014 serving an airport and about fifty residents \u2014 to rebuild a Katrina-shattered Interstate 10 bridge outside New Orleans. Stevens threatens to resign on the spot if it passes, and the appropriators of both parties close ranks.", "votes": {"coburn": "yea", "stevens": "nay", "sununu": "yea", "feingold": "yea", "obama": "nay"}, "notes": {}, "date": "October 20, 2005", "question": "On the Amendment S.Amdt. 2165 to H.R. 3058 (Transportation, Treasury, Housing and Urban Development, the Judiciary, the District of Columbia, and Independent Agencies Appropriations Act, 2006)", "result": "Amendment Rejected", "yeas": 15, "nays": 82}, {"name": "Filibustering the PATRIOT Act", "desc": "December 16, 2005. The PATRIOT reauthorization needs sixty votes to advance \u2014 and this very morning the New York Times revealed that the NSA has been wiretapping Americans without warrants. A yea pushes the renewal through as written; a nay joins a filibuster demanding stronger safeguards first.", "votes": {"coburn": "yea", "stevens": "yea", "sununu": "nay", "feingold": "nay", "obama": "nay"}, "notes": {}, "date": "December 16, 2005", "question": "On the Cloture Motion H.R. 3199", "result": "Cloture Motion Rejected", "yeas": 52, "nays": 47}]}, {"id": "change-comes", "title": "Change Comes to Washington", "era": "111th Congress \u00b7 2009", "intro": "A new president sworn in before two million people, a 58-seat majority, and an economy in freefall. For the Senate's last Republican moderates, every vote is now an identity crisis.", "senators": [{"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "Twenty-eight years a Republican from purple Pennsylvania: pro-labor, pro-science, an appropriator to his bones \u2014 now staring at primary polling that reads like an obituary. He is doing arithmetic in public about where he still belongs.", "photo": "photos/S000709.jpg"}, {"key": "snowe", "name": "Olympia Snowe", "party": "R", "state": "ME", "blurb": "Maine's senior Republican, a moderate who sets up shop in the middle of every storm. She frets about deficits and process \u2014 but she has never met a crisis she'd rather filibuster than fix.", "photo": "photos/S000663.jpg"}, {"key": "graham", "name": "Lindsey Graham", "party": "R", "state": "SC", "blurb": "South Carolina's genial hawk and John McCain's best friend, back from a bruising campaign season. A reliable conservative on economics who nonetheless believes elections have consequences \u2014 especially for judicial nominations.", "photo": "photos/G000359.jpg"}, {"key": "sanders", "name": "Bernie Sanders", "party": "I", "state": "VT", "blurb": "Vermont's socialist, delighted the country has finally discovered Wall Street's failings but suspicious the cleanup is being written by the people who caused the wreck. He wants the new administration bolder, faster, and bigger.", "photo": "photos/S000033.jpg"}, {"key": "bnelson", "name": "Ben Nelson", "party": "D", "state": "NE", "blurb": "Nebraska's Democrat, the most conservative member of the caucus. He convenes the moderates' back-room meetings, trims every big number he sees, and votes his state's Republican lean whenever the spotlight allows it.", "photo": "photos/N000180.jpg"}], "bills": [{"name": "The Recovery Act", "desc": "February 13, 2009 \u2014 three weeks into the new presidency. The $787 billion stimulus: infrastructure, aid to states, expanded jobless benefits, and tax cuts, trimmed by a tiny band of moderates whose votes are the difference between law and nothing. Exactly three Republicans are even negotiating. Economists argue over whether it is far too big or far too small.", "votes": {"specter": "yea", "snowe": "yea", "graham": "nay", "sanders": "yea", "bnelson": "yea"}, "notes": {}, "date": "February 13, 2009", "question": "On the Conference Report H.R. 1", "result": "Conference Report Agreed to", "yeas": 60, "nays": 38}, {"name": "Obama's First Budget", "desc": "April 2, 2009, 11:30 p.m. The blueprint for the Obama era: a $3.5 trillion budget with down payments on health-care reform, clean energy, and education \u2014 and a deficit north of a trillion dollars. Republicans call it the most expansionist plan since the Great Society. It needs only 51 votes, which is exactly what makes it a free vote for nervous moderates.", "votes": {"specter": "nay", "snowe": "nay", "graham": "nay", "sanders": "yea", "bnelson": "nay"}, "notes": {}, "date": "April 2, 2009", "question": "On the Concurrent Resolution S.Con.Res. 13", "result": "Concurrent Resolution Agreed to", "yeas": 55, "nays": 43}, {"name": "Confirming Sonia Sotomayor", "desc": "August 6, 2009. The first Hispanic nominee to the Supreme Court \u2014 a Bronx-born federal judge with 17 years on the bench, filling David Souter's seat. Conservative groups have spent the summer on her 'wise Latina' remark; senators doing the math know the seat won't shift the Court's balance either way.", "votes": {"specter": "yea", "snowe": "yea", "graham": "yea", "sanders": "yea", "bnelson": "yea"}, "notes": {}, "date": "August 6, 2009", "question": "On the Nomination PN506", "result": "Nomination Confirmed", "yeas": 68, "nays": 31}]}, {"id": "morning-in-america", "title": "Morning in America", "era": "97th Congress \u00b7 1981", "intro": "Reagan arrives with a mandate, a Republican Senate \u2014 the first in a generation \u2014 and a bullet wound that made him a legend by April. Washington spends 1981 discovering what it can't refuse him.", "senators": [{"key": "hbaker", "name": "Howard Baker", "party": "R", "state": "TN", "blurb": "Majority Leader of a chamber his party hasn't run since 1954, shelving his own presidential ambitions to be Reagan's indispensable man in the Senate \u2014 herding 53 Republicans through an agenda he privately calls a riverboat gamble.", "photo": "photos/B000063.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The new Finance Committee chairman, wry as ever: he'll carry the president's tax bill, but the deficit projections keep him up nights, and he doesn't pretend otherwise.", "photo": "photos/D000401.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "Suddenly in the minority for the first time in his career, the left's anchor against the Reagan tide \u2014 picking which fights can still be won.", "photo": "photos/K000105.jpg"}, {"key": "moynihan", "name": "Daniel Patrick Moynihan", "party": "D", "state": "NY", "blurb": "The Harvard social scientist turned New York Democrat, allergic to orthodoxy in both directions: he likes ideas more than parties, Israel and Social Security more than either.", "photo": "photos/M001054.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "The movement's founding father, watching his revolution finally take power \u2014 chairing Intelligence, guarding the Pentagon, and saying exactly what he thinks about everyone.", "photo": "photos/G000267.jpg"}], "bills": [{"name": "The Reagan Tax Cut", "desc": "July 29, 1981. The Economic Recovery Tax Act: individual rates cut 25% across the board over three years, indexed against inflation, with sweetened depreciation for business. Supply-side economics gets its full-scale national test. Democrats, reading the election returns, largely decline to stand in front of it.", "votes": {"hbaker": "yea", "dole": "yea", "kennedy": "nay", "moynihan": "yea", "goldwater": "yea"}, "notes": {}, "date": "July 29, 1981", "question": "On the Finance Committee Substitute to H.J. Res. 266", "result": "Agreed to", "yeas": 89, "nays": 11}, {"name": "Blocking the AWACS Sale", "desc": "October 28, 1981. A resolution to block Reagan's $8.5 billion sale of AWACS radar planes to Saudi Arabia \u2014 opposed by Israel, AIPAC, and, at the outset, a Senate majority. Reagan works waverers one by one: 'It is not the business of other nations to make American foreign policy.' A yea kills the sale.", "votes": {"hbaker": "nay", "dole": "nay", "kennedy": "yea", "moynihan": "yea", "goldwater": "nay"}, "notes": {}, "date": "October 28, 1981", "question": "On the Resolution of Disapproval", "result": "Resolution Rejected", "yeas": 48, "nays": 52}, {"name": "Confirming Sandra Day O'Connor", "desc": "September 21, 1981. Reagan keeps a campaign promise and names the first woman to the Supreme Court: an Arizona appeals judge and former state senate majority leader. Some anti-abortion groups grumble about her record in Phoenix; the Senate is not in a grumbling mood.", "votes": {"hbaker": "yea", "dole": "yea", "kennedy": "yea", "moynihan": "yea", "goldwater": "yea"}, "notes": {}, "date": "September 21, 1981", "question": "On the Nomination of Sandra Day O'Connor", "result": "Nomination Confirmed", "yeas": 99, "nays": 0}]}, {"id": "bork", "title": "The Bork Fight", "era": "100th Congress \u00b7 1987\u20131988", "intro": "Lewis Powell's retirement leaves the Supreme Court balanced on one seat, and Reagan names the most famous conservative judge in America. Twelve weeks later, confirmation politics has a new verb.", "senators": [{"key": "biden", "name": "Joe Biden", "party": "D", "state": "DE", "blurb": "Judiciary chairman at 44, running the hearings days after his own presidential campaign collapsed in a plagiarism storm \u2014 determined to prove the gavel steadier than the candidate, and to fight the nomination on judicial philosophy, not scandal.", "photo": "photos/B000444.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The opposition's alarm bell: within an hour of the nomination he took the floor to paint 'Robert Bork's America' in the darkest tones \u2014 a speech admirers call mobilization and critics call caricature.", "photo": "photos/K000105.jpg"}, {"key": "thurmond", "name": "Strom Thurmond", "party": "R", "state": "SC", "blurb": "The Judiciary Committee's ancient ranking Republican, shepherd of Reagan's judges: to him Bork is simply the most qualified nominee in decades being punished for candor.", "photo": "photos/T000254.jpg"}, {"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "Pennsylvania's ex-prosecutor, the committee's swing vote: he spent days cross-examining the nominee on original intent like a hostile witness, and half of Washington still can't predict his verdict.", "photo": "photos/S000709.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "Majority Leader again in a recaptured Democratic Senate \u2014 an institution man who thinks the Court, like the Senate, belongs to no president.", "photo": "photos/B001210.jpg"}], "bills": [{"name": "The Highway Bill Override", "desc": "April 2, 1987. Reagan has vetoed an $88 billion highway and transit bill as a budget-buster stuffed with 152 earmarked 'demonstration projects' \u2014 and come to the Capitol personally to hold Republicans, telling them to 'win one more for the Gipper.' The new Democratic Senate, and a few defectors, answer.", "votes": {"biden": "yea", "kennedy": "yea", "thurmond": "nay", "specter": "yea", "byrd": "yea"}, "notes": {}, "date": "April 2, 1987", "question": "On Overriding the Veto of H.R. 2", "result": "Veto Overridden", "yeas": 67, "nays": 33}, {"name": "Confirming Robert Bork", "desc": "October 23, 1987. After 12 days of televised hearings on original intent, privacy, and civil rights, the most exhaustively examined Supreme Court nomination in history reaches the floor, its outcome no longer in doubt \u2014 Bork refused to withdraw, insisting on a recorded vote for history.", "votes": {"biden": "nay", "kennedy": "nay", "thurmond": "yea", "specter": "nay", "byrd": "nay"}, "notes": {}, "date": "October 23, 1987", "question": "On the Nomination of Robert H. Bork", "result": "Nomination Rejected", "yeas": 42, "nays": 58}, {"name": "Confirming Anthony Kennedy", "desc": "February 3, 1988. The third nominee for the Powell seat \u2014 after Bork's defeat and Douglas Ginsburg's marijuana-shortened nine days \u2014 is a mild Sacramento appellate judge who testifies that the Constitution protects a sphere of liberty. An exhausted Senate, and both parties, are ready to say yes.", "votes": {"biden": "yea", "kennedy": "yea", "thurmond": "yea", "specter": "yea", "byrd": "yea"}, "notes": {"biden": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea."}, "date": "February 3, 1988", "question": "On the Nomination of Anthony M. Kennedy", "result": "Nomination Confirmed", "yeas": 97, "nays": 0}]}, {"id": "class-of-2010", "title": "The Class of 2010", "era": "112th Congress \u00b7 2011\u20132013", "intro": "November 2010 sends a wave of new senators to a broken-down Washington: Tea Party insurgents, red-state survivors, and an appointee proving she belongs. Their first Congress lurches from crisis to crisis \u2014 and ends at 2 a.m. on New Year's morning.", "senators": [{"key": "mlee", "name": "Mike Lee", "party": "R", "state": "UT", "blurb": "Utah's constitutional originalist, who took down an 18-year incumbent at a party convention. A former Supreme Court clerk who tests every bill against Article I \u2014 and finds most of them wanting.", "photo": "photos/L000577.jpg"}, {"key": "toomey", "name": "Pat Toomey", "party": "R", "state": "PA", "blurb": "The former Club for Growth president who chased Arlen Specter out of the Republican Party. Pennsylvania expects the occasional moderate turn; his donors expect the fiscal discipline he spent a decade writing op-eds about.", "photo": "photos/T000461.jpg"}, {"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "West Virginia's former governor, who won Robert Byrd's old seat after an ad in which he literally shot the cap-and-trade bill with a rifle. He votes his state, not his caucus.", "photo": "photos/M001183.jpg"}, {"key": "gillibrand", "name": "Kirsten Gillibrand", "party": "D", "state": "NY", "blurb": "Appointed to Hillary Clinton's seat as a Blue Dog from upstate, she has sprinted leftward in statewide politics \u2014 making the 9/11 health bill and the repeal of 'don't ask, don't tell' her calling cards.", "photo": "photos/G000555.jpg"}, {"key": "ayotte", "name": "Kelly Ayotte", "party": "R", "state": "NH", "blurb": "New Hampshire's former attorney general, a Tea Party-year winner with an establishment r\u00e9sum\u00e9. Hawkish on defense in a state that hosts a Navy shipyard, and careful with a swing electorate that watches everything.", "photo": "photos/A000368.jpg"}], "bills": [{"name": "The NDAA \u2014 Indefinite Detention", "desc": "December 15, 2011. The $662 billion defense authorization \u2014 with new provisions affirming that the military may detain terrorism suspects, potentially including Americans, indefinitely and without trial. Civil libertarians in both parties call it a betrayal of the Bill of Rights; the White House drops its veto threat at the last minute.", "votes": {"mlee": "nay", "toomey": "yea", "manchin": "yea", "gillibrand": "yea", "ayotte": "yea"}, "notes": {}, "date": "December 15, 2011", "question": "On the Conference Report H.R. 1540", "result": "Conference Report Agreed to", "yeas": 86, "nays": 13}, {"name": "The JOBS Act", "desc": "March 22, 2012. A rare election-year lovefest: crowdfunding legalized, IPO paperwork slashed for 'emerging growth' companies, and startup investing opened to small investors. Silicon Valley and the White House are for it; securities regulators and many Democrats warn it guts investor protections that date to the Depression.", "votes": {"mlee": "yea", "toomey": "yea", "manchin": "yea", "gillibrand": "nay", "ayotte": "yea"}, "notes": {}, "date": "March 22, 2012", "question": "On Passage of the Bill H.R. 3606", "result": "Bill Passed", "yeas": 73, "nays": 26}, {"name": "The Fiscal Cliff Deal", "desc": "January 1, 2013, 2 a.m. The country went over the fiscal cliff two hours ago. The deal, cut by Joe Biden and Mitch McConnell: Bush tax cuts made permanent below $400,000 and rates up above it \u2014 the first income-tax rate increase Republicans have blessed in two decades \u2014 with the sequester postponed two months.", "votes": {"mlee": "nay", "toomey": "yea", "manchin": "yea", "gillibrand": "yea", "ayotte": "yea"}, "notes": {}, "date": "January 1, 2013", "question": "On Passage of the Bill H.R. 8", "result": "Bill Passed", "yeas": 89, "nays": 8}]}, {"id": "mccain-kennedy", "title": "The McCain-Kennedy Moment", "era": "109th Congress \u00b7 2006", "intro": "Millions march for immigrants in the spring; the flag amendment falls one vote short in June; Bush casts the first veto of his presidency in July. The 109th's last summer tries a little of everything.", "senators": [{"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "Forty-four years in, the liberal lion has found his latest unlikely partner: John McCain, on immigration. He wants a law, not an issue \u2014 and he has traded with harder men than this White House.", "photo": "photos/K000105.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The maverick with 2008 in plain view, co-authoring 'amnesty' \u2014 his enemies' word \u2014 with Ted Kennedy while courting the conservatives who distrust him. The tightrope act of the decade.", "photo": "photos/M000303.jpg"}, {"key": "frist", "name": "Bill Frist", "party": "R", "state": "TN", "blurb": "The Majority Leader, a Nashville transplant surgeon retiring to run for president. He schedules the culture-war votes his base demands \u2014 and has broken with Bush on the one issue where the doctor outranks the politician.", "photo": "photos/F000439.jpg"}, {"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The freshman superstar, notionally focused on Illinois: pro-reform on immigration, deliberate everywhere else, drafting the persona a national run will require.", "photo": "photos/O000167.jpg"}, {"key": "sessions", "name": "Jeff Sessions", "party": "R", "state": "AL", "blurb": "Alabama's former federal prosecutor and the floor's most relentless immigration hardliner: to Sessions, the guest-worker bill is amnesty with paperwork, and no fence provision changes that.", "photo": "photos/S001141.jpg"}], "bills": [{"name": "Comprehensive Immigration Reform", "desc": "May 25, 2006. The McCain-Kennedy framework: a path to citizenship tiered by years in the country, a guest-worker program, 370 miles of new fencing, and English declared the 'national language.' Weeks after millions marched in the streets, the Senate attempts what the House has sworn to bury.", "votes": {"kennedy": "yea", "mccain": "yea", "frist": "yea", "obama": "yea", "sessions": "nay"}, "notes": {}, "date": "May 25, 2006", "question": "On Passage of the Bill S. 2611", "result": "Bill Passed", "yeas": 62, "nays": 36}, {"name": "The Flag Desecration Amendment", "desc": "June 27, 2006. A constitutional amendment letting Congress ban desecration of the American flag, timed for the Fourth of July and the fall campaign. Every count says it will come within a single vote of the 67 needed \u2014 close enough that no senator can hide.", "votes": {"kennedy": "nay", "mccain": "yea", "frist": "yea", "obama": "nay", "sessions": "yea"}, "notes": {}, "date": "June 27, 2006", "question": "On the Joint Resolution S.J.Res. 12", "result": "Joint Resolution Defeated", "yeas": 66, "nays": 34}, {"name": "The Stem Cell Research Act", "desc": "July 18, 2006. Federal funding for research on embryonic stem-cell lines from IVF embryos already slated for disposal. Nancy Reagan is for it; the White House has promised the first veto of Bush's presidency; and the science-versus-sanctity argument splits both parties along unfamiliar seams.", "votes": {"kennedy": "yea", "mccain": "yea", "frist": "yea", "obama": "yea", "sessions": "nay"}, "notes": {}, "date": "July 18, 2006", "question": "On Passage of the Bill H.R. 810", "result": "Bill Passed", "yeas": 63, "nays": 37}]}, {"id": "great-society", "title": "The Great Society", "era": "89th Congress \u00b7 1965", "intro": "Johnson's landslide has delivered a two-to-one Democratic Senate, and he intends to spend every ounce of it \u2014 on the vote, on the old, and on who gets to become an American.", "senators": [{"key": "mansfield", "name": "Mike Mansfield", "party": "D", "state": "MT", "blurb": "The Majority Leader: a laconic Montanan and former history professor who leads by patience where Johnson led by the lapels. He considers every senator's conscience his own business \u2014 including his own.", "photo": "photos/M000113.jpg"}, {"key": "dirksen", "name": "Everett Dirksen", "party": "R", "state": "IL", "blurb": "The Republican leader, fresh from delivering the votes that broke the 1964 filibuster. He calls himself 'not a moss-back' \u2014 but every Great Society bill must survive his theatrical scrutiny first.", "photo": "photos/D000360.jpg"}, {"key": "rfkennedy", "name": "Robert F. Kennedy", "party": "D", "state": "NY", "blurb": "The freshman from New York \u2014 attorney general ten months ago, carrying his brother's unfinished agenda and a following no first-termer has ever had. Liberal, restless, and impatient with the Senate's pace.", "photo": "photos/K000114.jpg"}, {"key": "thurmond", "name": "Strom Thurmond", "party": "R", "state": "SC", "blurb": "South Carolina's converted Republican \u2014 he bolted the Democratic Party last September to campaign for Goldwater. The 1948 Dixiecrat nominee still holds the record for the longest one-man filibuster, set against a civil rights bill.", "photo": "photos/T000254.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "West Virginia's tireless workhorse, a coal-country New Dealer on economics who joined the Southerners' filibuster against last year's civil rights act. He is studying the rulebook \u2014 and playing a longer game than most notice.", "photo": "photos/B001210.jpg"}], "bills": [{"name": "The Voting Rights Act", "desc": "May 26, 1965, ten weeks after state troopers clubbed marchers at the Edmund Pettus Bridge in Selma. The bill suspends literacy tests in states with a history of disenfranchisement and sends federal examiners south to register Black voters directly. Cloture ended the Southern filibuster the day before.", "votes": {"mansfield": "yea", "dirksen": "yea", "rfkennedy": "yea", "thurmond": "nay", "byrd": "nay"}, "notes": {"byrd": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Nay."}, "date": "May 26, 1965", "question": "On Passage of S. 1564", "result": "Bill Passed", "yeas": 77, "nays": 19}, {"name": "Medicare", "desc": "July 9, 1965. Health insurance for every American over 65, funded through Social Security \u2014 the cause organized medicine has fought as 'socialized medicine' since Truman proposed it in 1945. The package adds Medicaid for the poor. The AMA warns of bureaucrats between doctor and patient.", "votes": {"mansfield": "yea", "dirksen": "yea", "rfkennedy": "yea", "thurmond": "nay", "byrd": "yea"}, "notes": {"mansfield": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea.", "dirksen": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea."}, "date": "July 9, 1965", "question": "On Passage of H.R. 6675", "result": "Bill Passed", "yeas": 68, "nays": 21}, {"name": "The Immigration and Nationality Act", "desc": "September 22, 1965. The bill abolishes the national-origins quota system that has favored Northern Europeans since 1924, replacing it with preferences for family reunification and skills. Supporters insist it will barely change the country's demographic mix; opponents call the old system common sense.", "votes": {"mansfield": "yea", "dirksen": "yea", "rfkennedy": "yea", "thurmond": "nay", "byrd": "nay"}, "notes": {}, "date": "September 22, 1965", "question": "On Passage of H.R. 2580", "result": "Bill Passed", "yeas": 76, "nays": 18}]}, {"id": "jan-six", "title": "January 6th, After Midnight", "era": "117th Congress \u00b7 2021", "intro": "A mob has just been cleared from the Capitol. Senators return to a building of broken glass to finish counting the electoral votes \u2014 and five months later, to decide whether anyone should investigate what happened.", "senators": [{"key": "hawley", "name": "Josh Hawley", "party": "R", "state": "MO", "blurb": "Missouri's 41-year-old Yale Law populist was the first senator to announce he'd object to the count \u2014 the raised fist to the crowd outside is already the photo of his career, for better or worse.", "photo": "photos/H001089.jpg"}, {"key": "cruz", "name": "Ted Cruz", "party": "R", "state": "TX", "blurb": "The Texan leads a bloc demanding a ten-day 'election audit' commission, modeled on 1877. Runner-up to Trump in 2016, he has no intention of ceding the Trump lane in 2024.", "photo": "photos/C001098.jpg"}, {"key": "graham", "name": "Lindsey Graham", "party": "R", "state": "SC", "blurb": "Trump's golf partner and most quotable ally \u2014 but a 30-year institutionalist who spent January 6 in the chamber he loves, hearing the mob outside. 'Count me out,' he says that night. How far out?", "photo": "photos/G000359.jpg"}, {"key": "romney", "name": "Mitt Romney", "party": "R", "state": "UT", "blurb": "The party's sharpest internal critic, who marched to the Capitol that morning past heckling crowds and voted to convict Trump once already. His fury on the floor tonight is not performed.", "photo": "photos/R000615.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's independent-minded survivor, first Republican senator to call on Trump to resign after the attack \u2014 and the only one of the objectors' colleagues facing his endorsed challenger next year.", "photo": "photos/M001153.jpg"}], "bills": [{"name": "The Arizona Objection", "desc": "January 6, 2021, 9:58 p.m. The objection to counting Arizona's electoral votes \u2014 filed by Rep. Gosar and Sen. Cruz \u2014 was being debated when rioters stormed the Capitol. Now the Senate, back in its chamber, votes on it. A Yea sustains the objection and throws out Arizona's eleven electoral votes for Biden; a Nay counts them as certified.", "votes": {"hawley": "yea", "cruz": "yea", "graham": "nay", "romney": "nay", "murkowski": "nay"}, "notes": {}, "date": "January 6, 2021", "question": "On the Objection (Shall the Objection Submitted by the Gentleman from Arizona, Mr. Gosar, and the Senator from Texas, Mr. Cruz, and Others Be Sustained?)", "result": "Objection Not Sustained", "yeas": 6, "nays": 93}, {"name": "The Pennsylvania Objection", "desc": "12:30 a.m., January 7. The second and final objection to survive to a Senate vote: Pennsylvania's twenty electoral votes, challenged by Rep. Perry and Sen. Hawley over the state's expanded mail voting. Again, Yea sustains the objection and rejects the state's certified electors. Some who planned to object hours ago have had second thoughts.", "votes": {"hawley": "yea", "cruz": "yea", "graham": "nay", "romney": "nay", "murkowski": "nay"}, "notes": {}, "date": "January 7, 2021", "question": "On the Objection (Shall the Objection Submitted by the Gentleman from Pennsylvania, Mr. Perry, and the Senator from Missouri, Mr. Hawley, Be Sustained?)", "result": "Objection Not Sustained", "yeas": 7, "nays": 92}, {"name": "A January 6th Commission", "desc": "May 28, 2021. A bill creating an independent, 9/11-style commission on the attack: ten commissioners, evenly split between the parties, with bipartisan subpoena power. The House passed it with 35 Republican votes. McConnell calls it 'a purely political exercise'; it needs 60 to advance.", "votes": {"hawley": "nay", "cruz": "nay", "graham": "nay", "romney": "yea", "murkowski": "yea"}, "notes": {}, "date": "May 28, 2021", "question": "On the Cloture Motion H.R. 3233", "result": "Cloture Motion Rejected", "yeas": 54, "nays": 35}]}, {"id": "debt-rerun", "title": "The Debt-Ceiling Rerun", "era": "118th Congress \u00b7 2023", "intro": "Divided government returns, and with it the sequels: a debt-limit standoff, a shutdown countdown, and a Pentagon budget. A freshman class of populists gets its first taste of governing by deadline.", "senators": [{"key": "fetterman", "name": "John Fetterman", "party": "D", "state": "PA", "blurb": "Pennsylvania's 6-foot-8 freshman in gym shorts, back at work after treatment for depression he discussed with unusual candor. A blue-collar populist who measures every deal by what it does to the little guy \u2014 and hates being told something is 'the only option.'", "photo": "photos/F000479.jpg"}, {"key": "vance", "name": "J.D. Vance", "party": "R", "state": "OH", "blurb": "Ohio's freshman wrote Hillbilly Elegy, then remade himself as a Trump-endorsed scourge of the foreign-policy and spending establishments. He didn't come to Washington to vote for grand bargains.", "photo": "photos/V000137.jpg"}, {"key": "sinema_i", "name": "Kyrsten Sinema", "party": "I", "state": "AZ", "blurb": "Now officially an independent, having left the Democratic Party weeks after the midterms. Still caucusing for committee purposes, still the Senate's most relentless dealmaker \u2014 and still keeping Arizona guessing about 2024.", "photo": "photos/S001191.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's senior senator, fresh off beating a Trump-backed challenger under ranked-choice voting. More insulated from the base than any Republican in the chamber, and she votes like it.", "photo": "photos/M001153.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "Kentucky's libertarian: he has voted against every debt- ceiling increase, most spending bills, and any Pentagon budget he deems bloated. Deadlines, in his view, are leverage everyone else keeps wasting.", "photo": "photos/P000603.jpg"}], "bills": [{"name": "The Fiscal Responsibility Act", "desc": "June 1, 2023, 10:37 p.m. \u2014 default is projected in four days. The Biden-McCarthy deal suspends the debt ceiling into 2025 in exchange for two years of spending caps, clawed-back COVID and IRS money, expanded work requirements, and approval of the Mountain Valley Pipeline. Hardliners in both parties hate it \u2014 which is usually how these pass.", "votes": {"fetterman": "nay", "vance": "nay", "sinema_i": "yea", "murkowski": "yea", "rpaul": "nay"}, "notes": {}, "date": "June 1, 2023", "question": "On Passage of the Bill H.R. 3746", "result": "Bill Passed", "yeas": 63, "nays": 36}, {"name": "The FY2024 Defense Bill", "desc": "July 27, 2023. An $886 billion defense authorization: a 5.2% pay raise for the troops \u2014 the largest in two decades \u2014 new submarines and hypersonics money, and another round of aid authorities for Ukraine and Taiwan. The perennial must-pass bill, opposed each year by an odd chorus of doves and deficit hawks.", "votes": {"fetterman": "yea", "vance": "nay", "sinema_i": "yea", "murkowski": "yea", "rpaul": "nay"}, "notes": {}, "date": "July 27, 2023", "question": "On Passage of the Bill S. 2226", "result": "Bill Passed", "yeas": 86, "nays": 11}, {"name": "The 45-Day Stopgap", "desc": "September 30, 2023, 8:10 p.m. \u2014 four hours to a shutdown. A bare-bones continuing resolution keeping the government open 45 days, with disaster relief but no Ukraine aid, jammed through after Speaker McCarthy abandoned his right flank to pass it. Three days later, the House will fire him for it.", "votes": {"fetterman": "yea", "vance": "nay", "sinema_i": "yea", "murkowski": "yea", "rpaul": "nay"}, "notes": {}, "date": "September 30, 2023", "question": "On Passage of the Bill H.R. 5860", "result": "Bill Passed", "yeas": 88, "nays": 9}]}, {"id": "longest-debate", "title": "The Longest Debate", "era": "88th Congress \u00b7 1964", "intro": "An election year like no other: a martyred president's program on the floor, a 60-day filibuster to break, a tax cut to pass \u2014 and, one August morning, a resolution about two destroyers in a distant gulf.", "senators": [{"key": "humphrey", "name": "Hubert Humphrey", "party": "D", "state": "MN", "blurb": "The Senate's happy warrior: Minneapolis's evangelist of liberalism, majority whip, and floor general of the civil rights forces \u2014 while auditioning, everyone knows, to be Lyndon Johnson's running mate.", "photo": "photos/H000953.jpg"}, {"key": "dirksen", "name": "Everett Dirksen", "party": "R", "state": "IL", "blurb": "The Minority Leader from Illinois, a baroque orator with a voice like a pipe organ. He loves the Senate, the Republic, and being indispensable \u2014 his price is being courted, publicly and at length.", "photo": "photos/D000360.jpg"}, {"key": "russell", "name": "Richard Russell", "party": "D", "state": "GA", "blurb": "The courtly Georgian who commands the Southern bloc and knows the rulebook better than the parliamentarian. Johnson's old mentor, a defense hawk to his marrow \u2014 and the general of the longest filibuster in Senate history.", "photo": "photos/R000536.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "Arizona's flinty individualist, weeks from seizing the Republican presidential nomination from the party's Eastern establishment. He reads most federal power as constitutional trespass and votes that way, whatever it costs him in November.", "photo": "photos/G000267.jpg"}, {"key": "mcsmith", "name": "Margaret Chase Smith", "party": "R", "state": "ME", "blurb": "Maine's independent Republican, the first woman ever placed in nomination for president by a major party. She made her name defying Joe McCarthy in 1950 and has answered to no one since.", "photo": "photos/S000590.jpg"}], "bills": [{"name": "The Civil Rights Act of 1964", "desc": "June 19, 1964 \u2014 one year to the day after President Kennedy sent the bill to Congress. It outlaws segregation in restaurants, hotels, and theaters, and discrimination in hiring. The Southern filibuster ran 60 working days before the Senate invoked cloture on a civil rights bill for the first time in its history.", "votes": {"humphrey": "yea", "dirksen": "yea", "russell": "nay", "goldwater": "nay", "mcsmith": "yea"}, "notes": {}, "date": "June 19, 1964", "question": "On Passage of H.R. 7152", "result": "Bill Passed", "yeas": 73, "nays": 27}, {"name": "The Kennedy Tax Cut", "desc": "February 7, 1964. The Revenue Act: the biggest tax cut in American history to date, slashing the top individual rate from 91% to 70% to goose a sluggish economy. Kennedy proposed it; Johnson muscled it through by promising to hold the budget under $100 billion. Deficit-wary conservatives are not soothed.", "votes": {"humphrey": "yea", "dirksen": "yea", "russell": "nay", "goldwater": "nay", "mcsmith": "yea"}, "notes": {"dirksen": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Yea."}, "date": "February 7, 1964", "question": "On Passage of H.R. 8363", "result": "Bill Passed", "yeas": 77, "nays": 21}, {"name": "The Gulf of Tonkin Resolution", "desc": "August 7, 1964, three days after reported North Vietnamese attacks on the destroyers Maddox and Turner Joy. The resolution approves 'all necessary measures' to repel armed attack in Southeast Asia \u2014 no declaration of war, no expiration date. Debate takes less than nine hours; only two senators are opposed.", "votes": {"humphrey": "yea", "dirksen": "yea", "russell": "yea", "goldwater": "yea", "mcsmith": "yea"}, "notes": {}, "date": "August 7, 1964", "question": "On Passage of H.J. Res. 1145", "result": "Resolution Passed", "yeas": 88, "nays": 2}]}, {"id": "culture-wars-open", "title": "The Culture Wars Open", "era": "101st Congress \u00b7 1990", "intro": "AIDS, art, and access: in a single year the Senate writes the federal response to an epidemic, votes on what government may sponsor, and passes the broadest civil rights law in a generation.", "senators": [{"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "North Carolina's happy warrior of the right, mid-way through the ugliest re-election fight of 1990: he sees federal AIDS spending as reward for conduct he condemns, and publicly funded art as subsidized blasphemy. He relishes making colleagues vote on it.", "photo": "photos/H000463.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "Chairman of Labor and Human Resources and the machine behind both the AIDS bill and the disability act \u2014 pairing with whichever Republican will co-sign, and usually finding one.", "photo": "photos/K000105.jpg"}, {"key": "hatch", "name": "Orrin Hatch", "party": "R", "state": "UT", "blurb": "Utah's constitutional conservative with a soft spot for public-health causes: the religious right counts on him, but his unlikely partnership with Kennedy keeps producing legislation that surprises them.", "photo": "photos/H000338.jpg"}, {"key": "metzenbaum", "name": "Howard Metzenbaum", "party": "D", "state": "OH", "blurb": "Ohio's millionaire scourge of business: a combative liberal who reads every unanimous-consent request twice and treats civil rights bills as the reason he's there.", "photo": "photos/M000678.jpg"}, {"key": "danforth", "name": "John Danforth", "party": "R", "state": "MO", "blurb": "Missouri's Republican and an ordained Episcopal priest \u2014 a moralist uncomfortable with obscenity and with censorship alike, which in 1990 is an increasingly crowded corner.", "photo": "photos/D000030.jpg"}], "bills": [{"name": "The Ryan White CARE Act", "desc": "May 16, 1990, five weeks after Ryan White's death at 18. The first comprehensive federal AIDS-care program: emergency relief for the hardest-hit cities and grants for every state, for testing, drugs, and treatment. By now over 120,000 Americans have been diagnosed; the bill's sponsors read the numbers on the floor.", "votes": {"helms": "nay", "kennedy": "yea", "hatch": "yea", "metzenbaum": "yea", "danforth": "yea"}, "notes": {}, "date": "May 16, 1990", "question": "On Passage of the Bill S. 2240", "result": "Bill Passed", "yeas": 95, "nays": 4}, {"name": "The Americans with Disabilities Act", "desc": "July 13, 1990. The 'emancipation proclamation' for 43 million disabled Americans: bans on employment discrimination, accessible buses and trains, ramps and accommodations in every public place. Business groups warn about costs and lawsuits; veterans of the epidemic note it covers people with HIV, too.", "votes": {"helms": "nay", "kennedy": "yea", "hatch": "yea", "metzenbaum": "yea", "danforth": "yea"}, "notes": {}, "date": "July 13, 1990", "question": "On the Conference Report S. 933", "result": "Conference Report Agreed to", "yeas": 91, "nays": 6}, {"name": "The Helms Arts Amendment", "desc": "October 24, 1990. After Mapplethorpe and Serrano made the National Endowment for the Arts a household argument, Helms proposes flatly barring NEA funds for works depicting sexual or excretory activities or organs. A yea writes the content ban into law; a nay leaves obscenity to the courts and the Endowment's new procedures.", "votes": {"helms": "yea", "kennedy": "nay", "hatch": "nay", "metzenbaum": "nay", "danforth": "nay"}, "notes": {}, "date": "October 24, 1990", "question": "On the Amendment S.Amdt. 3119 to H.R. 5769 (Department of the Interior and Related Agencies Appropriations Act, 1991)", "result": "Amendment Rejected", "yeas": 29, "nays": 70}]}, {"id": "millennium", "title": "The Millennium Senate", "era": "106th Congress \u00b7 1999\u20132000", "intro": "Surpluses, dot-com champagne, and a country a month past Columbine. On the way to the recount, the Senate decides who checks gun buyers, what banks may own, and who pays taxes at death.", "senators": [{"key": "gramm", "name": "Phil Gramm", "party": "R", "state": "TX", "blurb": "Banking's chairman, a free-market economics professor who has waited a career to bury Depression-era financial law. He calls the wall between banking and Wall Street a relic; the repeal will carry his name.", "photo": "photos/G000365.jpg"}, {"key": "wellstone", "name": "Paul Wellstone", "party": "D", "state": "MN", "blurb": "Minnesota's professor-organizer, the surest no in the chamber on anything Wall Street wants. He keeps warning that memories of 1929 are shorter than the statutes written after it.", "photo": "photos/W000288.jpg"}, {"key": "schumer", "name": "Chuck Schumer", "party": "D", "state": "NY", "blurb": "Brooklyn's new senator, fresh from toppling Al D'Amato: author of the House's Brady Bill and a ferocious gun-control advocate \u2014 who also represents the financial capital of the world and knows who signs his state's paychecks.", "photo": "photos/S000148.jpg"}, {"key": "snowe", "name": "Olympia Snowe", "party": "R", "state": "ME", "blurb": "Maine's centrist Republican, a charter member of the chamber's shrinking middle. Leadership needs her on close votes and never quite knows which way New England pragmatism will break.", "photo": "photos/S000663.jpg"}, {"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "The old lion of the right, voting as he has since 1973: against gun control and death taxes alike, and against most things with 'modernization' in the title.", "photo": "photos/H000463.jpg"}], "bills": [{"name": "Gun-Show Background Checks", "desc": "May 20, 1999 \u2014 one month after two students murdered thirteen people at Columbine High School. The Lautenberg amendment requires background checks for every gun-show sale, closing the private-sale loophole. The chamber has spent a week seesawing between rival versions \u2014 and this one lands in a dead tie, the Vice President waiting in the chair.", "votes": {"gramm": "nay", "wellstone": "yea", "schumer": "yea", "snowe": "nay", "helms": "nay"}, "notes": {}, "date": "May 20, 1999", "question": "On the Amendment S.Amdt. 362 to S. 254 (School Safety Act of 1999)", "result": "Amendment Agreed to", "yeas": 50, "nays": 50}, {"name": "Repealing Glass-Steagall", "desc": "November 4, 1999. Gramm-Leach-Bliley tears down the Depression-era walls separating banks, brokerages, and insurers \u2014 ratifying, in effect, the Citicorp-Travelers merger that jumped the gun last year. Most of the chamber sees modernization; a few dissenters see the next crash being chartered.", "votes": {"gramm": "yea", "wellstone": "nay", "schumer": "yea", "snowe": "yea", "helms": "yea"}, "notes": {}, "date": "November 4, 1999", "question": "On the Conference Report S. 900", "result": "Conference Report Agreed to", "yeas": 90, "nays": 8}, {"name": "Repealing the Estate Tax", "desc": "July 14, 2000. A phased repeal of the estate tax \u2014 the 'death tax,' in messaging that has turned a levy paid by two percent of estates into a kitchen-table grievance. Clinton has promised a veto, so the vote is really about November. Surpluses make everything look affordable.", "votes": {"gramm": "yea", "wellstone": "nay", "schumer": "nay", "snowe": "yea", "helms": "yea"}, "notes": {}, "date": "July 14, 2000", "question": "On Passage of the Bill H.R. 8", "result": "Bill Passed", "yeas": 59, "nays": 39}]}, {"id": "doles-last-year", "title": "Dole's Last Year", "era": "104th Congress \u00b7 1996", "intro": "Bob Dole tries to run for president without leaving the majority leader's office. While he juggles, the 104th rewires the phone lines, upends sixty years of farm policy, and answers MiGs over the Florida Straits.", "senators": [{"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Leader as candidate: 72 years old, wickedly funny in private, stiff on camera, trying to legislate his way to the nomination. Every floor result is now a campaign story.", "photo": "photos/D000401.jpg"}, {"key": "moynihan", "name": "Daniel Patrick Moynihan", "party": "D", "state": "NY", "blurb": "Finance's ranking sage, armed with more history than the Congressional Research Service. He judges bills by their consequences for the poor and the Republic; party messaging concerns him not at all.", "photo": "photos/M001054.jpg"}, {"key": "bkerrey", "name": "Bob Kerrey", "party": "D", "state": "NE", "blurb": "Nebraska's restless Vietnam hero, running the Democrats' campaign committee while representing a farm state that eyes the Republicans' 'Freedom to Farm' revolution warily. Contrarian enough to surprise anyone.", "photo": "photos/K000146.jpg"}, {"key": "helms", "name": "Jesse Helms", "party": "R", "state": "NC", "blurb": "Foreign Relations' chairman, at the peak of his powers. Cuban MiGs have just shot down two exile aircraft off Havana, and Helms means to make the embargo permanent \u2014 and personal.", "photo": "photos/H000463.jpg"}, {"key": "snowe", "name": "Olympia Snowe", "party": "R", "state": "ME", "blurb": "Maine's freshman Republican, sixteen years in the House behind her: pro-choice, pragmatic, attentive to mill towns and dairy farms that don't love either party's orthodoxies.", "photo": "photos/S000663.jpg"}], "bills": [{"name": "The Telecommunications Act", "desc": "February 1, 1996. The first rewrite of communications law since 1934: local phone companies, long-distance carriers, and cable systems freed to invade one another's markets, ownership caps loosened, and an online 'decency' provision bolted on. Nearly everyone is for it; the dissenters warn of merger mania and censorship.", "votes": {"dole": "yea", "moynihan": "yea", "bkerrey": "yea", "helms": "yea", "snowe": "yea"}, "notes": {}, "date": "February 1, 1996", "question": "On the Conference Report S. 652", "result": "Conference Report Agreed to", "yeas": 91, "nays": 5}, {"name": "Freedom to Farm", "desc": "February 7, 1996. The end of New Deal agriculture: price supports and planting controls replaced by seven years of fixed, declining payments and the freedom \u2014 or the risk \u2014 of the open market. Grain prices are high today, which makes the deal look better than skeptics think it will feel in a bust.", "votes": {"dole": "yea", "moynihan": "yea", "bkerrey": "nay", "helms": "yea", "snowe": "nay"}, "notes": {}, "date": "February 7, 1996", "question": "On Passage of the Bill S. 1541", "result": "Bill Passed", "yeas": 64, "nays": 32}, {"name": "The Helms-Burton Act", "desc": "March 5, 1996. Ten days after Cuban jets shot down two unarmed exile planes, killing four, the embargo is codified into law: no president can lift it alone, and foreign companies 'trafficking' in confiscated American property can be sued in U.S. courts. Canada and Europe are furious.", "votes": {"dole": "yea", "moynihan": "nay", "bkerrey": "nay", "helms": "yea", "snowe": "yea"}, "notes": {}, "date": "March 5, 1996", "question": "On the Conference Report H.R. 927", "result": "Conference Report Agreed to", "yeas": 74, "nays": 22}]}, {"id": "read-my-lips", "title": "Read My Lips", "era": "101st Congress \u00b7 1989\u20131990", "intro": "George H.W. Bush begins with a cabinet rejection unprecedented in three decades, fights the flag wars of 1990 \u2014 and then, at Andrews Air Force Base, trades away the six most famous words he ever spoke.", "senators": [{"key": "nunn", "name": "Sam Nunn", "party": "D", "state": "GA", "blurb": "Chairman of Armed Services and the Democrats' Pentagon conscience: methodical, conservative, and unsparing when he concludes a man \u2014 any man \u2014 shouldn't sit atop the Defense Department.", "photo": "photos/N000171.jpg"}, {"key": "jwarner", "name": "John Warner", "party": "R", "state": "VA", "blurb": "Virginia's courtly Republican, Armed Services' ranking member and a former Navy secretary: a defender of the services, the president's prerogatives, and the Senate's good manners, in roughly that order.", "photo": "photos/W000154.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The former POW in his first Senate term, already the chamber's bluntest voice on military matters \u2014 and a fierce friend of John Tower, whose treatment he considers a disgrace.", "photo": "photos/M000303.jpg"}, {"key": "mitchell", "name": "George Mitchell", "party": "D", "state": "ME", "blurb": "The new Majority Leader: a former federal judge from Maine with a prosecutor's calm and a partisan's memory, happy to let Bush own every broken promise.", "photo": "photos/M000811.jpg"}, {"key": "kassebaum", "name": "Nancy Kassebaum", "party": "R", "state": "KS", "blurb": "The Kansas moderate, twelve years in: internationalist abroad, deficit-serious at home, and stubbornly unimpressed by loyalty tests from her own party's White House.", "photo": "photos/K000017.jpg"}], "bills": [{"name": "The Tower Nomination", "desc": "March 9, 1989. John Tower \u2014 four terms in this Senate, former Armed Services chairman \u2014 is Bush's choice for Secretary of Defense. The FBI file and the hearings dwell on drinking, women, and defense-contractor consulting fees. No cabinet nominee has been rejected since 1959, and never one of the Senate's own.", "votes": {"nunn": "nay", "jwarner": "yea", "mccain": "yea", "mitchell": "nay", "kassebaum": "nay"}, "notes": {}, "date": "March 9, 1989", "question": "On the Nomination PN129", "result": "Nomination Rejected", "yeas": 47, "nays": 53}, {"name": "The Flag Desecration Amendment", "desc": "June 26, 1990. The Supreme Court has twice ruled flag-burning protected speech \u2014 striking down Texas's law, then the federal statute Congress passed in response. This is the remaining option: a constitutional amendment authorizing flag-desecration bans. Two-thirds required, with the fall campaigns watching every nay.", "votes": {"nunn": "yea", "jwarner": "yea", "mccain": "yea", "mitchell": "nay", "kassebaum": "yea"}, "notes": {}, "date": "June 26, 1990", "question": "On the Joint Resolution S.J.Res. 332", "result": "Joint Resolution Defeated", "yeas": 58, "nays": 42}, {"name": "The 1990 Budget Deal", "desc": "October 27, 1990. The five-year, $490 billion deficit package from the Andrews summit: spending caps, pay-as-you-go rules \u2014 and higher income and gasoline taxes, eighteen months after 'read my lips: no new taxes.' Conservatives call it betrayal; the White House calls it governing.", "votes": {"nunn": "yea", "jwarner": "yea", "mccain": "nay", "mitchell": "yea", "kassebaum": "yea"}, "notes": {}, "date": "October 27, 1990", "question": "On the Conference Report H.R. 5835", "result": "Conference Report Agreed to", "yeas": 54, "nays": 45}]}, {"id": "filibuster-winter", "title": "The Filibuster Winter", "era": "117th Congress \u00b7 2021\u20132022", "intro": "Democrats hold the House, the Senate, and the White House \u2014 and watch their voting-rights agenda die at sixty votes, three times. Then they try to change the number itself.", "senators": [{"key": "manchin", "name": "Joe Manchin", "party": "D", "state": "WV", "blurb": "West Virginia's Democrat calls the filibuster the soul of the Senate and refuses to gut it \u2014 while insisting he wants a voting-rights deal, and writing his own compromise bill to prove it.", "photo": "photos/M001183.jpg"}, {"key": "sinema", "name": "Kyrsten Sinema", "party": "D", "state": "AZ", "blurb": "Arizona's first-term enigma delivers a floor speech defending the 60-vote threshold on the very day the President comes to the Hill to lobby against it. She backs the bills; the rules are another question.", "photo": "photos/S001191.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The minority leader with a floor-length view of Senate rules: he calls the elections bill a federal takeover and promises a 'scorched earth' chamber if Democrats touch the filibuster.", "photo": "photos/M000355.jpg"}, {"key": "merkley", "name": "Jeff Merkley", "party": "D", "state": "OR", "blurb": "Oregon's methodical progressive has spent a decade drafting filibuster-reform plans and is the elections bill's chief author \u2014 this is the moment he's been organizing toward his entire Senate career.", "photo": "photos/M001176.jpg"}, {"key": "warnock", "name": "Raphael Warnock", "party": "D", "state": "GA", "blurb": "The freshman pastor from Ebenezer Baptist frames voting rights as 'a moral issue' in the tradition of the church he leads \u2014 and argues democracy shouldn't die to preserve a Senate custom.", "photo": "photos/W000790.jpg"}], "bills": [{"name": "The For the People Act", "desc": "June 22, 2021. Cloture on the Democrats' 800-page democracy overhaul: national automatic and same-day registration, independent redistricting commissions, small-donor matching, dark-money disclosure. Every Republican calls it a power grab; the only suspense is whether all fifty Democrats will even agree to open debate. Sixty votes to advance.", "votes": {"manchin": "yea", "sinema": "yea", "mcconnell": "nay", "merkley": "yea", "warnock": "yea"}, "notes": {}, "date": "June 22, 2021", "question": "On Cloture on the Motion to Proceed S. 2093", "result": "Cloture on the Motion to Proceed Rejected", "yeas": 50, "nays": 50}, {"name": "The John Lewis Voting Rights Act", "desc": "November 3, 2021. A narrower bill restoring the Voting Rights Act's preclearance formula, struck down by the Supreme Court in 2013 \u2014 requiring states with recent violations to clear election changes with Washington again. Named for the late congressman who bled at Selma. Again sixty votes, and this time exactly one Republican is willing.", "votes": {"manchin": "yea", "sinema": "yea", "mcconnell": "nay", "merkley": "yea", "warnock": "yea"}, "notes": {}, "date": "November 3, 2021", "question": "On Cloture on the Motion to Proceed S. 4", "result": "Cloture on the Motion to Proceed Rejected", "yeas": 50, "nays": 49}, {"name": "The Filibuster Carve-Out", "desc": "January 19, 2022, 10:21 p.m. With the voting bill blocked again, Schumer moves to change the rules: a 'talking filibuster' exception letting elections legislation pass by simple majority. The chair rules the 60-vote threshold stands; this vote is the appeal. A Yea upholds the ruling and keeps the filibuster intact \u2014 a Nay blows the hole open. Fifty-two senators will settle it.", "votes": {"manchin": "yea", "sinema": "yea", "mcconnell": "yea", "merkley": "nay", "warnock": "nay"}, "notes": {}, "date": "January 19, 2022", "question": "On the Decision of the Chair H.R. 5746", "result": "Decision of Chair Sustained", "yeas": 52, "nays": 48}]}, {"id": "peace-dividend", "title": "The Peace Dividend", "era": "102nd Congress \u00b7 1992", "intro": "The Cold War is over, the economy is sour, and George Bush is behind in the polls. A Democratic Senate spends the autumn sending him popular bills \u2014 and daring him to keep vetoing them.", "senators": [{"key": "mitchell", "name": "George Mitchell", "party": "D", "state": "ME", "blurb": "The Majority Leader: a former federal judge from Maine with a prosecutor's patience and a genius for making the President veto popular things. He has scheduled the fall's override votes for maximum election-season discomfort.", "photo": "photos/M000811.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "The Republican leader, fighting a rearguard action to keep Bush's veto record perfect \u2014 35 vetoes, 35 sustained. With his troops drifting home to campaign, every override attempt is a fresh headcount.", "photo": "photos/D000401.jpg"}, {"key": "specter", "name": "Arlen Specter", "party": "R", "state": "PA", "blurb": "Pennsylvania's cranky moderate, five weeks from facing voters still angry over his grilling of Anita Hill. Labor-friendly by Republican standards, he has little appetite for defending unpopular vetoes just now.", "photo": "photos/S000709.jpg"}, {"key": "wofford", "name": "Harris Wofford", "party": "D", "state": "PA", "blurb": "The accidental senator: a former college president and civil-rights veteran who won a shock 1991 special election on national health insurance. His upset is the reason half of Washington thinks Bush can lose.", "photo": "photos/W000665.jpg"}, {"key": "kassebaum", "name": "Nancy Kassebaum", "party": "R", "state": "KS", "blurb": "A plainspoken Kansas Republican \u2014 internationalist abroad, skeptical of mandates on business at home. She makes up her own mind and announces it without drama.", "photo": "photos/K000017.jpg"}], "bills": [{"name": "The Family Leave Veto Fight", "desc": "September 24, 1992. Bush has vetoed the family-leave bill \u2014 twelve weeks of unpaid leave for a new baby or a sick relative at companies of fifty or more \u2014 calling it a costly mandate on business. Democrats schedule the override six weeks before the election. Two-thirds needed.", "votes": {"mitchell": "yea", "dole": "nay", "specter": "yea", "wofford": "yea", "kassebaum": "nay"}, "notes": {}, "date": "September 24, 1992", "question": "On Overriding the Veto S. 5", "result": "Veto Overridden", "yeas": 68, "nays": 31}, {"name": "The START Treaty", "desc": "October 1, 1992. The Strategic Arms Reduction Treaty, signed by Bush and Gorbachev before the country Gorbachev led ceased to exist. It cuts deployed strategic warheads by roughly a third \u2014 the first treaty to shrink the arsenals rather than cap them \u2014 with Russia, Ukraine, Belarus, and Kazakhstan now inheriting the Soviet side.", "votes": {"mitchell": "yea", "dole": "yea", "specter": "yea", "wofford": "yea", "kassebaum": "yea"}, "notes": {}, "date": "October 1, 1992", "question": "On Passage of the Bill Treaty Doc. 102-20", "result": "Bill Passed", "yeas": 93, "nays": 6}, {"name": "The Cable TV Act", "desc": "October 5, 1992. Cable rates have roughly tripled since deregulation, and this bill lets the FCC cap them. Bush vetoed it as re-regulation; the cable and broadcast lobbies are at war in the corridors. No Bush veto has ever been overridden \u2014 and the election is four weeks away.", "votes": {"mitchell": "yea", "dole": "nay", "specter": "yea", "wofford": "yea", "kassebaum": "yea"}, "notes": {}, "date": "October 5, 1992", "question": "On Overriding the Veto S. 12", "result": "Veto Overridden", "yeas": 74, "nays": 25}]}, {"id": "consumer-nation", "title": "Consumer Nation", "era": "111th Congress \u00b7 2009\u20132010", "intro": "Between the epic fights over health care and Wall Street, the 111th Congress quietly rewrites the rules of everyday American life: what a credit card can charge, whom a hate-crime law protects, and what makes it into the refrigerator.", "senators": [{"key": "dodd", "name": "Chris Dodd", "party": "D", "state": "CT", "blurb": "Chairman of the Banking Committee, thirty years in, his reputation singed by a sweetheart-mortgage flap and Connecticut polling that has him underwater. He is legislating like a man with nothing left to protect.", "photo": "photos/D000388.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "Wisconsin's maverick progressive, who reads every bill for civil-liberties fine print and has no fear of voting alone. Consumer protection is home turf; expansions of federal power over citizens are not.", "photo": "photos/F000061.jpg"}, {"key": "coburn", "name": "Tom Coburn", "party": "R", "state": "OK", "blurb": "The Senate's obstructionist-in-chief, blocking bills by the dozen over spending he deems wasteful. An obstetrician who attaches his pet amendments \u2014 loaded guns in national parks, most famously \u2014 to anything that moves.", "photo": "photos/C000560.jpg"}, {"key": "inhofe", "name": "Jim Inhofe", "party": "R", "state": "OK", "blurb": "Oklahoma's other conservative, a former insurance executive and the chamber's loudest climate skeptic. A reliable rule of thumb: if a bill grows a federal agency, he is against it.", "photo": "photos/I000024.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's methodical moderate and the ranking member overseeing food-safety reform. She co-writes half the bipartisan bills in the chamber and reads the fine print on the other half.", "photo": "photos/C001035.jpg"}], "bills": [{"name": "The Credit CARD Act", "desc": "May 19, 2009. New rules for the credit-card industry: no retroactive rate hikes on existing balances, 45 days' notice before raising rates, curbs on penalty fees, and limits on marketing to college students. Banks warn that free checking will die. Attached along the way, to consumer advocates' horror: an amendment allowing loaded guns in national parks.", "votes": {"dodd": "yea", "feingold": "yea", "coburn": "yea", "inhofe": "yea", "collins": "yea"}, "notes": {}, "date": "May 19, 2009", "question": "On Passage of the Bill H.R. 627", "result": "Bill Passed", "yeas": 90, "nays": 5}, {"name": "The Matthew Shepard Hate Crimes Act", "desc": "October 22, 2009. Federal hate-crimes law extended to cover sexual orientation and gender identity \u2014 eleven years after Matthew Shepard was beaten and left to die on a Wyoming fence. Democrats attached it to the $680 billion defense authorization, daring opponents to vote against troop funding to stop it.", "votes": {"dodd": "yea", "feingold": "nay", "coburn": "nay", "inhofe": "nay", "collins": "yea"}, "notes": {}, "date": "October 22, 2009", "question": "On the Conference Report H.R. 2647", "result": "Conference Report Agreed to", "yeas": 68, "nays": 29}, {"name": "The Food Safety Modernization Act", "desc": "November 30, 2010. After salmonella in the peanut butter and half a billion recalled eggs, the biggest overhaul of food-safety law since 1938: FDA power to order recalls, more frequent inspections, and safety standards for produce. A one-man blockade held it up for months over its $1.4 billion price tag.", "votes": {"dodd": "yea", "feingold": "yea", "coburn": "nay", "inhofe": "nay", "collins": "yea"}, "notes": {}, "date": "November 30, 2010", "question": "On Passage of the Bill S. 510", "result": "Bill Passed", "yeas": 73, "nays": 25}]}, {"id": "climate-wars", "title": "The Climate Wars", "era": "108th\u2013114th Congress \u00b7 2003\u20132015", "intro": "Twelve years of the Senate arguing with a thermometer: a cap-and-trade bill ahead of its time, a fight over Alaska's refuge, and a pipeline that becomes a national symbol.", "senators": [{"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The Republican who believes the science and says so: he co-authors the first real climate bill and holds hearings with glaciologists. But he's also a westerner who loves energy independence \u2014 the pipeline era will test which instinct runs deeper.", "photo": "photos/M000303.jpg"}, {"key": "murkowski", "name": "Lisa Murkowski", "party": "R", "state": "AK", "blurb": "Alaska's senator, later chairman of Energy. Oil fills a third of her state's payroll, and opening ANWR's coastal plain has been the family cause since her father held the seat. Climate talk, in her Senate, must coexist with drilling.", "photo": "photos/M001153.jpg"}, {"key": "cantwell", "name": "Maria Cantwell", "party": "D", "state": "WA", "blurb": "Washington's former tech executive, who treats the Arctic National Wildlife Refuge fight as her signature stand \u2014 she leads the floor defense against drilling and never misses an oil-market manipulation hearing.", "photo": "photos/C000127.jpg"}, {"key": "inhofe", "name": "Jim Inhofe", "party": "R", "state": "OK", "blurb": "Oklahoma's implacable skeptic, who calls man-made global warming 'the greatest hoax ever perpetrated on the American people' from the chairmanship of the Environment Committee. Oil and gas built his state; he intends to return the favor.", "photo": "photos/I000024.jpg"}, {"key": "wyden", "name": "Ron Wyden", "party": "D", "state": "OR", "blurb": "Oregon's cerebral progressive: salmon streams, wind farms, and a tax-code approach to everything. A reliable environmental vote who'd rather rewrite energy incentives than posture about them.", "photo": "photos/W000779.jpg"}], "bills": [{"name": "The Climate Stewardship Act", "desc": "October 30, 2003. McCain-Lieberman: the Senate's first real vote on capping greenhouse gases \u2014 emissions held to 2000 levels by 2010, with tradable allowances for power plants and factories. Opponents brandish studies on electricity prices; supporters just want it on the record that a bipartisan climate bill can exist.", "votes": {"mccain": "yea", "murkowski": "nay", "cantwell": "yea", "inhofe": "nay", "wyden": "yea"}, "notes": {}, "date": "October 30, 2003", "question": "On the Amendment S.Amdt. 2028 to S. 139 (Climate Stewardship Act of 2003)", "result": "Amendment Rejected", "yeas": 43, "nays": 55}, {"name": "Blocking Arctic Refuge Drilling", "desc": "March 16, 2005. Drilling advocates have tucked ANWR's coastal plain into the budget resolution, where no filibuster can reach it. The Cantwell amendment strikes the provision \u2014 a Yea protects the refuge, a Nay keeps drilling on track. After three decades of stalemate over 10 billion barrels and a caribou calving ground, the margin is razor thin.", "votes": {"mccain": "yea", "murkowski": "nay", "cantwell": "yea", "inhofe": "nay", "wyden": "yea"}, "notes": {}, "date": "March 16, 2005", "question": "On the Amendment S.Amdt. 168 to S.Con.Res. 18 (No short title on file)", "result": "Amendment Rejected", "yeas": 49, "nays": 51}, {"name": "The Keystone XL Pipeline", "desc": "January 29, 2015. The new Republican majority's Bill Number One: approving the 1,179-mile pipeline carrying Canadian oil-sands crude to Gulf refineries, six years into an environmental review Obama refuses to shortcut. Unions want the construction jobs; climate activists have made the route a line in the tar sand. A veto is promised.", "votes": {"mccain": "yea", "murkowski": "yea", "cantwell": "nay", "inhofe": "yea", "wyden": "nay"}, "notes": {}, "date": "January 29, 2015", "question": "On Passage of the Bill S. 1", "result": "Bill Passed", "yeas": 62, "nays": 36}]}, {"id": "the-canal", "title": "The Canal", "era": "95th Congress \u00b7 1978", "intro": "Jimmy Carter has signed treaties handing the Panama Canal to Panama by century's end, and ratification needs 67 votes. The New Right smells the defining cause of the decade. Every senator counts the mail.", "senators": [{"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "Majority Leader at last, the fiddle-playing parliamentarian from West Virginia. He came to the treaties a skeptic and now steers them personally, senator by senator, reservation by reservation \u2014 his leadership's first great test.", "photo": "photos/B001210.jpg"}, {"key": "hbaker", "name": "Howard Baker", "party": "R", "state": "TN", "blurb": "The Republican leader, gifted with the party's best temperament and worst timing: he wants to run for president in 1980, and 'the man who gave away the canal' is not the slogan his strategists had in mind. He read the treaties anyway.", "photo": "photos/B000063.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "The old standard-bearer: to him the canal is American soil, bought and paid for, and giving it up under pressure invites every adversary to push. His mail runs hot, and so does he.", "photo": "photos/G000267.jpg"}, {"key": "church", "name": "Frank Church", "party": "D", "state": "ID", "blurb": "Foreign Relations' liberal heavyweight, floor-managing ratification: he argues the canal is defensible only with Panamanian consent \u2014 and that clinging to a colonial enclave poisons the whole hemisphere. Idaho's phone lines disagree.", "photo": "photos/C000388.jpg"}, {"key": "hayakawa", "name": "S.I. Hayakawa", "party": "R", "state": "CA", "blurb": "California's freshman celebrity \u2014 the semanticist who faced down student radicals at San Francisco State in a tam-o'-shanter. He campaigned saying the canal was ours; scholars' second thoughts are, for him, an occupational habit.", "photo": "photos/H000384.jpg"}], "bills": [{"name": "The Canal Neutrality Treaty", "desc": "March 16, 1978. The first of the two Panama treaties: the canal's permanent neutrality, with the U.S. keeping the right to defend it forever. Weeks of debate over a 'DeConcini condition' on American intervention have inflamed Panama City. Ratification requires two-thirds \u2014 67 votes, with none to spare.", "votes": {"byrd": "yea", "hbaker": "yea", "goldwater": "nay", "church": "yea", "hayakawa": "yea"}, "notes": {}, "date": "March 16, 1978", "question": "On the Resolution of Ratification", "result": "Treaty Ratified", "yeas": 68, "nays": 32}, {"name": "The Panama Canal Treaty", "desc": "April 18, 1978. The main event: full transfer of the canal to Panama on December 31, 1999. Conservative groups have raised millions against it; senators who vote yes are promised primary opponents. Carter calls wavering members from the White House until the final hour. Again, 67 votes or death.", "votes": {"byrd": "yea", "hbaker": "yea", "goldwater": "nay", "church": "yea", "hayakawa": "yea"}, "notes": {}, "date": "April 18, 1978", "question": "On the Resolution of Ratification", "result": "Treaty Ratified", "yeas": 68, "nays": 32}, {"name": "The Natural Gas Compromise", "desc": "September 27, 1978. The heart of Carter's energy plan after 18 months of trench warfare: phased deregulation of new natural gas prices by 1985. Producers call it too slow, consumer champions call it a giveaway, and the conference report survives on a coalition nobody can quite explain.", "votes": {"byrd": "yea", "hbaker": "nay", "goldwater": "nay", "church": "yea", "hayakawa": "nay"}, "notes": {}, "date": "September 27, 1978", "question": "On the Conference Report on H.R. 5289", "result": "Conference Report Agreed to", "yeas": 57, "nays": 42}]}, {"id": "detroit", "title": "Detroit on the Brink", "era": "110th Congress \u00b7 2008", "intro": "The year the American economy comes apart in stages: rebate checks in winter, a housing rescue in summer \u2014 and by December, the Big Three automakers are in Washington begging for survival money.", "senators": [{"key": "corker", "name": "Bob Corker", "party": "R", "state": "TN", "blurb": "A freshman Republican and former Chattanooga mayor who made a fortune in construction. Tennessee's auto jobs are at nonunion foreign plants \u2014 and he has appointed himself lead negotiator on what Detroit must give up in exchange for help.", "photo": "photos/C001071.jpg"}, {"key": "clevin", "name": "Carl Levin", "party": "D", "state": "MI", "blurb": "Michigan's senior senator, three decades in and Detroit's chief defender in Washington. The bookish Armed Services chairman rarely raises his voice \u2014 except when someone suggests letting the auto industry fail.", "photo": "photos/L000261.jpg"}, {"key": "mcconnell", "name": "Mitch McConnell", "party": "R", "state": "KY", "blurb": "The Republican leader, balancing a lame-duck Bush White House's rescue requests against a conference in open revolt over bailouts. Kentucky, as it happens, assembles Fords in Louisville.", "photo": "photos/M000355.jpg"}, {"key": "stabenow", "name": "Debbie Stabenow", "party": "D", "state": "MI", "blurb": "Michigan's junior senator, a former state legislator who talks about manufacturing the way others talk about religion. One in ten Michigan jobs traces back to the auto industry, and the state's unemployment rate leads the nation.", "photo": "photos/S000770.jpg"}, {"key": "demint", "name": "Jim DeMint", "party": "R", "state": "SC", "blurb": "South Carolina's insurgent conservative, already plotting to fund primary challengers against squishy colleagues. His state recruited a nonunion BMW plant \u2014 and he regards every federal rescue of a failing company as a step toward socialism.", "photo": "photos/D000595.jpg"}], "bills": [{"name": "The 2008 Stimulus Checks", "desc": "February 7, 2008. With the housing slump curdling into something worse, Washington mails money: $600 rebate checks per taxpayer, $1,200 for couples, plus business write-offs \u2014 a $152 billion package agreed between Bush and Pelosi in record time. The Senate adds checks for seniors and disabled veterans and hurries it to the President's desk.", "votes": {"corker": "nay", "clevin": "yea", "mcconnell": "yea", "stabenow": "yea", "demint": "nay"}, "notes": {}, "date": "February 7, 2008", "question": "On Passage of the Bill H.R. 5140", "result": "Bill Passed", "yeas": 81, "nays": 16}, {"name": "The Housing Rescue", "desc": "July 26, 2008. Foreclosures are running at thousands a day. The Housing and Economic Recovery Act: a Treasury lifeline for teetering mortgage giants Fannie Mae and Freddie Mac, FHA refinancing for 400,000 underwater borrowers, and a first-time homebuyer credit. Treasury Secretary Paulson calls his new Fannie-and-Freddie authority a 'bazooka' he hopes never to fire.", "votes": {"corker": "nay", "clevin": "yea", "mcconnell": "yea", "stabenow": "yea", "demint": "nay"}, "notes": {}, "date": "July 26, 2008", "question": "On the Motion (Motion to Concur in the House Amendment to Senate Amendment to the House Amendments to the Senate Amendment to HR 3221)", "result": "Motion Agreed to", "yeas": 72, "nays": 13}, {"name": "The Auto Bailout", "desc": "December 11, 2008. GM and Chrysler say they are weeks from running out of cash. The House has passed $14 billion in bridge loans; in the Senate it needs 60 votes. Late-night talks over how fast union wages must fall to match Toyota's have just collapsed. If this fails, the question goes to the Treasury \u2014 or to bankruptcy court.", "votes": {"corker": "nay", "clevin": "yea", "mcconnell": "nay", "stabenow": "yea", "demint": "nay"}, "notes": {}, "date": "December 11, 2008", "question": "On the Cloture Motion H.R. 7005", "result": "Cloture Motion Rejected", "yeas": 52, "nays": 35}]}, {"id": "sixty-votes", "title": "Sixty Votes", "era": "111th Congress \u00b7 2009\u20132010", "intro": "Health-care reform will need every member of the Democratic caucus \u2014 all sixty \u2014 plus anyone else who can be persuaded. A year of holdouts, side deals, and 1 a.m. roll calls.", "senators": [{"key": "landrieu", "name": "Mary Landrieu", "party": "D", "state": "LA", "blurb": "Louisiana's Democrat, a dealmaker from an oil state that gave Obama 40 percent. She extracts a price for hard votes \u2014 critics have just branded her Medicaid provision the 'Louisiana Purchase' \u2014 and she never apologizes for it.", "photo": "photos/L000550.jpg"}, {"key": "lieberman", "name": "Joe Lieberman", "party": "D", "state": "CT", "blurb": "The independent from Connecticut, who campaigned for McCain last fall and keeps his committee chairmanship anyway. Insurance-industry country is his home turf, and he relishes being the sixtieth vote everyone must court \u2014 especially while threatening to withhold it.", "photo": "photos/L000304.jpg"}, {"key": "snowe", "name": "Olympia Snowe", "party": "R", "state": "ME", "blurb": "The Republican most likely to cross. She voted the health bill out of committee in October \u2014 'when history calls, history calls' \u2014 then spent two months warning she was being rushed past her comfort.", "photo": "photos/S000663.jpg"}, {"key": "franken", "name": "Al Franken", "party": "D", "state": "MN", "blurb": "Minnesota's freshman, seated in July after an eight-month recount \u2014 the arrival that made sixty possible. A comedy writer turned earnest policy student, keeping his head down and his sound bites rare.", "photo": "photos/F000457.jpg"}, {"key": "coburn", "name": "Tom Coburn", "party": "R", "state": "OK", "blurb": "Oklahoma's 'Dr. No,' a practicing physician who calls the health bill a government takeover and wields Senate procedure like a scalpel \u2014 he once forced the clerks to read a 767-page amendment aloud.", "photo": "photos/C000560.jpg"}], "bills": [{"name": "Breaking the Health-Care Filibuster", "desc": "December 21, 2009, 1:08 a.m., with a blizzard outside. The first of three cloture votes on the health-care bill \u2014 the one that decides everything. The last holdouts have traded their votes for concessions; Democrats need all 60 caucus members present and voting yes against a unanimous Republican front. There is no margin for anyone.", "votes": {"landrieu": "yea", "lieberman": "yea", "snowe": "nay", "franken": "yea", "coburn": "nay"}, "notes": {}, "date": "December 21, 2009", "question": "On the Cloture Motion S.Amdt. 3276 to S.Amdt. 2786 to H.R. 3590 (Service Members Home Ownership Tax Act of 2009)", "result": "Cloture Motion Agreed to", "yeas": 60, "nays": 40}, {"name": "The Reconciliation Fix", "desc": "March 25, 2010. Obamacare is already law; this companion bill patches it through reconciliation \u2014 closing the Medicare drug 'donut hole,' sweetening subsidies, stripping out the Nebraska deal, and overhauling student lending \u2014 needing only 51 votes. After a 41-hour amendment marathon, Republicans force one last gauntlet before it passes.", "votes": {"landrieu": "yea", "lieberman": "yea", "snowe": "nay", "franken": "yea", "coburn": "nay"}, "notes": {}, "date": "March 25, 2010", "question": "On Passage of the Bill H.R. 4872", "result": "Bill Passed", "yeas": 56, "nays": 43}, {"name": "Confirming Elena Kagan", "desc": "August 5, 2010. The Solicitor General \u2014 a former Harvard Law dean who has never been a judge \u2014 nominated to succeed John Paul Stevens. Republicans press her over military recruiters at Harvard and a thin paper trail; Democrats note she would be only the fourth woman ever to sit on the Court. A midterm-season referendum on the administration as much as the nominee.", "votes": {"landrieu": "yea", "lieberman": "yea", "snowe": "yea", "franken": "yea", "coburn": "nay"}, "notes": {}, "date": "August 5, 2010", "question": "On the Nomination PN1768", "result": "Nomination Confirmed", "yeas": 63, "nays": 37}]}, {"id": "scandal-season", "title": "Scandal Season", "era": "105th Congress \u00b7 1997\u20131998", "intro": "Peace, prosperity, and a scandal consuming the other end of Pennsylvania Avenue. While the country argues about the President's conduct, the Senate balances a budget, fights Big Tobacco, and spanks the IRS.", "senators": [{"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "Commerce's chairman, waging a crusade to make cigarettes ruinously expensive \u2014 to the horror of much of his own party. The maverick brand is polishing itself nicely ahead of 2000.", "photo": "photos/M000303.jpg"}, {"key": "lott", "name": "Trent Lott", "party": "R", "state": "MS", "blurb": "The Majority Leader: a Mississippi conservative with a whip's instinct for counting and a scheduler's power to kill. He decides what reaches the floor \u2014 and what quietly dies waiting.", "photo": "photos/L000447.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal lion, and a shrewder inside player than the oratory suggests: he attached children's health insurance to the budget deal and considers tobacco money the way to pay for more.", "photo": "photos/K000105.jpg"}, {"key": "ashcroft", "name": "John Ashcroft", "party": "R", "state": "MO", "blurb": "Missouri's religious conservative, testing a presidential run on the party's right. He reads most bipartisan deals as surrender documents \u2014 taxes too high, spending too generous, Washington too pleased with itself.", "photo": "photos/A000356.jpg"}, {"key": "wellstone", "name": "Paul Wellstone", "party": "D", "state": "MN", "blurb": "The happiest warrior of the left, plotting his own quixotic presidential tour. He votes his conscience on labor, health, and the little guy \u2014 and against anything he smells as a corporate favor.", "photo": "photos/W000288.jpg"}], "bills": [{"name": "The Balanced Budget Act", "desc": "July 31, 1997. A deal to balance the budget by 2002: $115 billion in Medicare savings, a new children's health program, and a companion bill of tax cuts. After a generation of red ink both parties want the credit \u2014 and each party's purists want no part of it.", "votes": {"mccain": "yea", "lott": "yea", "kennedy": "yea", "ashcroft": "nay", "wellstone": "nay"}, "notes": {}, "date": "July 31, 1997", "question": "On the Conference Report H.R. 2015", "result": "Conference Report Agreed to", "yeas": 85, "nays": 15}, {"name": "The McCain Tobacco Bill", "desc": "June 17, 1998. $516 billion from the industry over 25 years, $1.10 more a pack, FDA authority over nicotine, curbs on marketing to kids. The industry has answered with a $40 million ad blitz about big taxes and big government. Sixty votes to keep the bill alive \u2014 and leadership isn't helping.", "votes": {"mccain": "yea", "lott": "nay", "kennedy": "yea", "ashcroft": "nay", "wellstone": "yea"}, "notes": {}, "date": "June 17, 1998", "question": "On the Cloture Motion S. 1415", "result": "Cloture Motion Rejected", "yeas": 57, "nays": 42}, {"name": "IRS Restructuring and Reform", "desc": "July 9, 1998. After Finance Committee hearings filled with horror stories of abusive collections, a rebuilt IRS: an independent oversight board, a taxpayer advocate, and the burden of proof shifted to the government in tax court. An election-year vote almost nobody wants to explain opposing.", "votes": {"mccain": "yea", "lott": "yea", "kennedy": "yea", "ashcroft": "yea", "wellstone": "nay"}, "notes": {}, "date": "July 9, 1998", "question": "On the Conference Report H.R. 2676", "result": "Conference Report Agreed to", "yeas": 96, "nays": 2}]}, {"id": "equal-rights", "title": "The Equal Rights Spring", "era": "92nd Congress \u00b7 1972", "intro": "In one late-winter stretch the Senate takes up women's rights, school busing, and job discrimination \u2014 three arguments about equality, each drawing a different line through the chamber.", "senators": [{"key": "bayh", "name": "Birch Bayh", "party": "D", "state": "IN", "blurb": "The Hoosier constitutional handyman \u2014 author of two ratified amendments already and Senate champion of the equal rights amendment, which he has pushed through years of hearings.", "photo": "photos/B000254.jpg"}, {"key": "ervin", "name": "Sam Ervin", "party": "D", "state": "NC", "blurb": "North Carolina's country-lawyer constitutionalist, quick with Scripture and Shakespeare. He believes the Constitution already says what it needs to \u2014 and that federal judges and social engineers keep discovering things in it that aren't there.", "photo": "photos/E000211.jpg"}, {"key": "mcsmith", "name": "Margaret Chase Smith", "party": "R", "state": "ME", "blurb": "In her final year, as it turns out: 32 years in Congress, the chamber's senior Republican woman, still casting votes with the same flinty independence she showed Joe McCarthy.", "photo": "photos/S000590.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "The conscience of conservatism, suspicious of grand constitutional renovations and of Washington telling states how to run their schools \u2014 though he likes to say his libertarian streak cuts in unexpected directions.", "photo": "photos/G000267.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal standard-bearer now, rebuilding after Chappaquiddick: floor leader for civil rights causes and a reliable vote against anything that retreats from desegregation.", "photo": "photos/K000105.jpg"}], "bills": [{"name": "The Equal Rights Amendment", "desc": "March 22, 1972. 'Equality of rights under the law shall not be denied or abridged... on account of sex.' After 49 years of introduction and burial, the ERA reaches a final vote, every weakening amendment \u2014 on the draft, on protective labor laws \u2014 already beaten back. Ratification by 38 states awaits.", "votes": {"bayh": "yea", "ervin": "nay", "mcsmith": "yea", "goldwater": "nay", "kennedy": "yea"}, "notes": {}, "date": "March 22, 1972", "question": "On Passage of H.J. Res. 208", "result": "Resolution Passed", "yeas": 84, "nays": 8}, {"name": "Barring Court-Ordered Busing", "desc": "February 25, 1972. An amendment to the higher-education bill barring federal courts from ordering the busing of schoolchildren on the basis of race. Busing is the rawest issue in American politics this year \u2014 George Wallace is winning primaries on it \u2014 and Northern liberals are feeling the ground shift. A yea restricts the courts.", "votes": {"bayh": "nay", "ervin": "yea", "mcsmith": "yea", "goldwater": "yea", "kennedy": "nay"}, "notes": {"bayh": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Nay."}, "date": "February 25, 1972", "question": "On the Amendment to Bar Court-Ordered Busing", "result": "Amendment Agreed to", "yeas": 43, "nays": 40}, {"name": "Breaking the EEOC Filibuster", "desc": "February 22, 1972. Cloture on the Equal Employment Opportunity Act, which for the first time lets the EEOC take job-discrimination cases to court itself rather than merely conciliate. A Southern filibuster has held the bill for weeks; a yea ends the talking and moves the bill toward passage.", "votes": {"bayh": "yea", "ervin": "nay", "mcsmith": "yea", "goldwater": "yea", "kennedy": "yea"}, "notes": {}, "date": "February 22, 1972", "question": "On Cloture on S. 2515", "result": "Cloture Invoked", "yeas": 73, "nays": 21}]}, {"id": "iran-summer", "title": "The Iran Deal Summer", "era": "114th Congress \u00b7 2015", "intro": "A presidential campaign is starting, a nuclear deal is landing, and the Senate spends one summer arguing about surveillance, trade, and war \u2014 with coalitions that scramble every party line.", "senators": [{"key": "schumer", "name": "Chuck Schumer", "party": "D", "state": "NY", "blurb": "Brooklyn's happy warrior and heir apparent to lead Senate Democrats, with deep ties to Wall Street and to New York's Jewish community. On the nuclear deal, the White House needs him \u2014 and is not at all sure it has him.", "photo": "photos/S000148.jpg"}, {"key": "rpaul", "name": "Rand Paul", "party": "R", "state": "KY", "blurb": "Kentucky's libertarian, running for president on dismantling the surveillance state. He has just held the floor for ten and a half hours against the Patriot Act \u2014 and no reform bill is ever quite pure enough for him.", "photo": "photos/P000603.jpg"}, {"key": "warren", "name": "Elizabeth Warren", "party": "D", "state": "MA", "blurb": "Massachusetts's progressive champion, at war with the administration over trade \u2014 she says fast-track lets corporations write the rules in secret \u2014 while standing behind it on diplomacy with Iran.", "photo": "photos/W000817.jpg"}, {"key": "corker", "name": "Bob Corker", "party": "R", "state": "TN", "blurb": "Chairman of Foreign Relations, the dealmaker who wrote the law giving Congress this vote on the Iran agreement in the first place. Deeply skeptical of the deal; protective of the process that judges it.", "photo": "photos/C001071.jpg"}, {"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "Maine's moderate, a senior appropriator with a national-security bent: wary of the NSA's loudest critics and unpersuaded by the administration's Iran diplomacy. She reads every annex before deciding anything.", "photo": "photos/C001035.jpg"}], "bills": [{"name": "The USA FREEDOM Act", "desc": "June 2, 2015. The NSA's bulk collection of American phone records \u2014 revealed by Edward Snowden \u2014 lapsed at midnight two days ago after Rand Paul blocked an extension. The replacement leaves the records with phone companies, searchable case-by-case with a court order. Civil-liberties absolutists say it changes too little; the NSA's defenders say it blinds the watchmen.", "votes": {"schumer": "yea", "rpaul": "nay", "warren": "yea", "corker": "nay", "collins": "nay"}, "notes": {}, "date": "June 2, 2015", "question": "On Passage of the Bill H.R. 2048", "result": "Bill Passed", "yeas": 67, "nays": 32}, {"name": "Trade Promotion Authority", "desc": "June 24, 2015. Fast-track: for six years, trade agreements \u2014 starting with the 12-nation Trans-Pacific Partnership \u2014 get an up-or-down vote with no amendments and no filibuster. Obama has fought his own party for months to get here; organized labor is promising primary challenges for any Democrat who helps him.", "votes": {"schumer": "nay", "rpaul": "nay", "warren": "nay", "corker": "yea", "collins": "nay"}, "notes": {}, "date": "June 24, 2015", "question": "On the Motion (Motion to Concur in the House Amendment to the Senate Amendment to H.R. 2146)", "result": "Motion Agreed to", "yeas": 60, "nays": 38}, {"name": "Blocking the Iran Nuclear Deal", "desc": "September 10, 2015. A resolution disapproving the Iran nuclear agreement \u2014 sanctions relief in exchange for a decade of enrichment limits and inspections. Voting yea advances the resolution to kill the deal; voting nay filibusters it and lets the agreement stand. The White House has 42 senators pledged \u2014 exactly enough \u2014 after four Democrats defected. The pressure on both sides is enormous.", "votes": {"schumer": "yea", "rpaul": "yea", "warren": "nay", "corker": "yea", "collins": "yea"}, "notes": {}, "date": "September 10, 2015", "question": "On the Cloture Motion S.Amdt. 2640 to H.J.Res. 61 (Hire More Heroes Act of 2015)", "result": "Cloture Motion Rejected", "yeas": 58, "nays": 42}]}, {"id": "roberts-court", "title": "The Roberts Court", "era": "109th Congress \u00b7 2005\u20132006", "intro": "William Rehnquist is dead, Sandra Day O'Connor is retiring, and George W. Bush gets to redraw the Supreme Court in a single term \u2014 while the PATRIOT Act, born in six weeks of fear, comes due for permanent renewal.", "senators": [{"key": "obama", "name": "Barack Obama", "party": "D", "state": "IL", "blurb": "The freshman phenomenon and former constitutional-law lecturer, already swatting away presidential questions. Every judicial vote he casts is read as a signal of what he might become.", "photo": "photos/O000167.jpg"}, {"key": "leahy", "name": "Patrick Leahy", "party": "D", "state": "VT", "blurb": "Judiciary's top Democrat, a Vermont institutionalist who still believes qualified nominees deserve respect across party lines \u2014 even as his base demands total war over the Court.", "photo": "photos/L000174.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "Eighty-eight now, the Senate's living constitution. He judges nominees on deference to Congress and respect for the institution \u2014 categories that cut across party in ways that regularly embarrass the whip counts.", "photo": "photos/B001210.jpg"}, {"key": "chafee", "name": "Lincoln Chafee", "party": "R", "state": "RI", "blurb": "Rhode Island's endangered Republican moderate, facing a brutal 2006 in a deep-blue state. Every high-profile vote is a choice between his primary and his general.", "photo": "photos/C001040.jpg"}, {"key": "feingold", "name": "Russ Feingold", "party": "D", "state": "WI", "blurb": "The civil libertarian who cast the Senate's only vote against the PATRIOT Act in 2001 \u2014 and who insists on judging judges by their records, not by his party's talking points.", "photo": "photos/F000061.jpg"}], "bills": [{"name": "Confirming John Roberts", "desc": "September 29, 2005. Rehnquist's former clerk succeeds him as Chief Justice: fifty years old, the ABA's highest rating, and hearings so polished they left barely a scratch. Democrats must decide whether 'brilliant but conservative' is a reason to vote no \u2014 and they are genuinely split.", "votes": {"obama": "nay", "leahy": "yea", "byrd": "yea", "chafee": "yea", "feingold": "yea"}, "notes": {}, "date": "September 29, 2005", "question": "On the Nomination PN801", "result": "Nomination Confirmed", "yeas": 78, "nays": 22}, {"name": "Confirming Samuel Alito", "desc": "January 31, 2006. The stakes double: Alito would replace O'Connor, the Court's swing vote, not merely one conservative with another. A last-minute filibuster attempt has fizzled; now a simple majority decides the seat that decides abortion, affirmative action, and executive power.", "votes": {"obama": "nay", "leahy": "nay", "byrd": "yea", "chafee": "nay", "feingold": "nay"}, "notes": {}, "date": "January 31, 2006", "question": "On the Nomination PN1059", "result": "Nomination Confirmed", "yeas": 58, "nays": 42}, {"name": "Renewing the PATRIOT Act", "desc": "March 2, 2006. The 2001 law's expiring powers made permanent, with four-year sunsets on roving wiretaps and library-records demands and a handful of negotiated safeguards. After a winter standoff \u2014 and revelations of warrantless NSA wiretapping \u2014 most senators have decided the fixes are enough. A stubborn few have not.", "votes": {"obama": "yea", "leahy": "nay", "byrd": "nay", "chafee": "yea", "feingold": "nay"}, "notes": {}, "date": "March 2, 2006", "question": "On the Conference Report H.R. 3199", "result": "Conference Report Agreed to", "yeas": 89, "nays": 10}]}, {"id": "war-powers", "title": "The War Powers Autumn", "era": "93rd Congress \u00b7 1973", "intro": "Watergate is devouring the White House, the Middle East is at war, oil is a weapon, and a vice president has just resigned in disgrace. Congress decides it is time to take some power back.", "senators": [{"key": "church", "name": "Frank Church", "party": "D", "state": "ID", "blurb": "Idaho's orator-moralist, a Vietnam critic since 1965. He believes Congress has surrendered its war-making power to an imperial presidency \u2014 and that the surrender ends now. Wilderness and wild rivers are his other religion.", "photo": "photos/C000388.jpg"}, {"key": "javits", "name": "Jacob Javits", "party": "R", "state": "NY", "blurb": "The New York Republican polymath and principal author of the war powers legislation \u2014 a liberal internationalist determined to bind presidents of both parties to the Constitution's war clause.", "photo": "photos/J000064.jpg"}, {"key": "goldwater", "name": "Barry Goldwater", "party": "R", "state": "AZ", "blurb": "The right's constitutional purist, on the opposite side of this one: the commander-in-chief power, he argues, is not Congress's to fence in. Development of the West, oil included, needs no apology either.", "photo": "photos/G000267.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Democratic whip, a coal-and-industry Democrat who mistrusts executive overreach on institutional grounds \u2014 and reads the Constitution from a copy in his breast pocket.", "photo": "photos/B001210.jpg"}, {"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal lion in his prime: against the war machine, skeptical of Big Oil's shortcuts, and increasingly the man Democrats imagine on a national ticket.", "photo": "photos/K000105.jpg"}], "bills": [{"name": "The War Powers Resolution", "desc": "November 7, 1973. Nixon has vetoed the bill requiring presidents to consult Congress before sending forces into hostilities and to withdraw them within 60 days absent authorization. Days after the Saturday Night Massacre, a weakened White House watches Congress muster two-thirds. A yea overrides the veto.", "votes": {"church": "yea", "javits": "yea", "goldwater": "nay", "byrd": "yea", "kennedy": "yea"}, "notes": {"goldwater": "Position recorded by announcement or pairing rather than a floor vote \u2014 the Congressional Record counts it as a Nay."}, "date": "November 7, 1973", "question": "On Overriding the Veto of H.J. Res. 542", "result": "Veto Overridden", "yeas": 75, "nays": 18}, {"name": "Fast-Tracking the Alaska Pipeline", "desc": "July 17, 1973. The Gravel amendment declares the trans-Alaska oil pipeline compliant with environmental law and bars further court review \u2014 the environmental movement's nightmare precedent, energy hawks' answer to dependence on Arab crude. It passes by a single vote, months before the embargo makes it look prophetic.", "votes": {"church": "nay", "javits": "nay", "goldwater": "yea", "byrd": "yea", "kennedy": "nay"}, "notes": {}, "date": "July 17, 1973", "question": "On the Gravel Amendment to S. 1081", "result": "Amendment Agreed to", "yeas": 49, "nays": 48}, {"name": "Confirming Gerald Ford as Vice President", "desc": "November 27, 1973. Spiro Agnew has resigned and pleaded no contest to tax evasion; under the new 25th Amendment, Congress must confirm his successor. Nixon sends up the House Republican leader \u2014 genial, unspectacular, trusted \u2014 while everyone in the chamber quietly wonders whether they are choosing the next president.", "votes": {"church": "yea", "javits": "yea", "goldwater": "yea", "byrd": "yea", "kennedy": "yea"}, "notes": {}, "date": "November 27, 1973", "question": "On the Nomination of Gerald R. Ford", "result": "Nomination Confirmed", "yeas": 92, "nays": 3}]}, {"id": "advice-dissent", "title": "Advice & Dissent", "era": "107th\u2013115th Congress \u00b7 2001\u20132017", "intro": "Three cabinet fights, sixteen years apart: an attorney general, a defense secretary, an education secretary. The same five senators sit in judgment each time \u2014 watch what loyalty does.", "senators": [{"key": "collins", "name": "Susan Collins", "party": "R", "state": "ME", "blurb": "The Maine Republican holds an old-fashioned doctrine: presidents of either party deserve their cabinet absent disqualifying flaws. The interesting question is what she counts as disqualifying \u2014 and whether sixteen years of polarization moves her line.", "photo": "photos/C001035.jpg"}, {"key": "pmurray", "name": "Patty Murray", "party": "D", "state": "WA", "blurb": "Washington's 'mom in tennis shoes,' risen from school-board revolt to the Democratic leadership. Education is her home turf, abortion rights her bright line, and she has little patience for nominees on the wrong side of either.", "photo": "photos/M001111.jpg"}, {"key": "mccain", "name": "John McCain", "party": "R", "state": "AZ", "blurb": "The maverick across three eras: a partisan when the wound is fresh, a dealmaker when the institution needs it, and famously personal about who has \u2014 and hasn't \u2014 earned his respect. One of these nominees is an old friend who crossed him.", "photo": "photos/M000303.jpg"}, {"key": "schumer", "name": "Chuck Schumer", "party": "D", "state": "NY", "blurb": "Brooklyn's happiest warrior, climbing from freshman to Democratic leader across these years. He reads every confirmation as a power question first \u2014 and by 2017 he's whipping his caucus to fight nearly everything.", "photo": "photos/S000148.jpg"}, {"key": "inhofe", "name": "Jim Inhofe", "party": "R", "state": "OK", "blurb": "Oklahoma's flinty conservative, an Army veteran and commercial pilot who backs Republican presidents' picks as a matter of course \u2014 and treats Democratic outrage as a reason to dig in.", "photo": "photos/I000024.jpg"}], "bills": [{"name": "Confirming John Ashcroft", "desc": "February 1, 2001. George W. Bush's attorney general: a former Missouri senator and governor, a devout Pentecostal beloved by religious conservatives \u2014 who just lost his Senate seat to a dead man. Civil-rights groups mobilize over his record on desegregation and abortion; colleagues weigh how hard to fight a man they served beside.", "votes": {"collins": "yea", "pmurray": "nay", "mccain": "yea", "schumer": "nay", "inhofe": "yea"}, "notes": {}, "date": "February 1, 2001", "question": "On the Nomination PN107", "result": "Nomination Confirmed", "yeas": 58, "nays": 42}, {"name": "Confirming Chuck Hagel", "desc": "February 26, 2013. Obama crosses the aisle for his defense secretary: Chuck Hagel, twice-wounded Vietnam sergeant and former Republican senator \u2014 who broke with his party over the Iraq surge. His old GOP colleagues filibustered him for two weeks and savaged his 'Jewish lobby' remark and shaky hearing. Nothing tests old friendships like apostasy.", "votes": {"collins": "nay", "pmurray": "yea", "mccain": "nay", "schumer": "yea", "inhofe": "nay"}, "notes": {}, "date": "February 26, 2013", "question": "On the Nomination PN34", "result": "Nomination Confirmed", "yeas": 58, "nays": 41}, {"name": "Confirming Betsy DeVos", "desc": "February 7, 2017. Trump's education secretary: a Michigan billionaire philanthropist and school-choice crusader with no experience in public schools, whose hearing produced the 'grizzly bears' answer on guns in classrooms. Teachers' unions flood the phone lines. The tally stands at 50-50 \u2014 meaning the Vice President waits in the chair.", "votes": {"collins": "nay", "pmurray": "nay", "mccain": "yea", "schumer": "nay", "inhofe": "yea"}, "notes": {}, "date": "February 7, 2017", "question": "On the Nomination PN37", "result": "Nomination Confirmed", "yeas": 50, "nays": 50}]}, {"id": "malaise", "title": "Malaise", "era": "96th Congress \u00b7 1979", "intro": "Gas lines, 13% inflation, a president talking about a national crisis of confidence \u2014 and a Massachusetts senator measuring the Oval Office drapes. Washington's answer: create, rescue, and tax.", "senators": [{"key": "kennedy", "name": "Ted Kennedy", "party": "D", "state": "MA", "blurb": "The liberal heir apparent, polling ahead of his own president: by November he has announced against Carter. Big institutions \u2014 national health insurance, federal activism \u2014 remain articles of faith.", "photo": "photos/K000105.jpg"}, {"key": "dole", "name": "Bob Dole", "party": "R", "state": "KS", "blurb": "Kansas's flinty wit, back from the 1976 ticket and running for president himself: a farm-state conservative with a heart for food stamps and the disabled, and a bookkeeper's eye on every new federal outlay.", "photo": "photos/D000401.jpg"}, {"key": "byrd", "name": "Robert Byrd", "party": "D", "state": "WV", "blurb": "The Majority Leader, keeping a restive Democratic caucus moving through an ugly economy \u2014 loyal to the party's program, if not always to the man in the White House.", "photo": "photos/B001210.jpg"}, {"key": "lugar", "name": "Richard Lugar", "party": "R", "state": "IN", "blurb": "Indiana's methodical freshman, the former Indianapolis mayor known as Nixon's favorite: a fiscal conservative who does his homework and distrusts bailouts \u2014 though Indiana builds a lot of Chryslers.", "photo": "photos/L000504.jpg"}, {"key": "proxmire", "name": "William Proxmire", "party": "D", "state": "WI", "blurb": "Wisconsin's ascetic scourge of waste, inventor of the Golden Fleece Award, chairman of Banking \u2014 and sworn enemy of the proposition that Washington should rescue badly run companies.", "photo": "photos/P000553.jpg"}], "bills": [{"name": "The Department of Education", "desc": "April 30, 1979. Carter's payoff to the teachers who elected him, critics say; overdue recognition of a national priority, backers answer. The bill carves a cabinet Department of Education out of HEW. Conservatives warn of federal control of the classroom; the AFL-CIO's teachers are watching the roll call.", "votes": {"kennedy": "yea", "dole": "nay", "byrd": "yea", "lugar": "nay", "proxmire": "nay"}, "notes": {}, "date": "April 30, 1979", "question": "On Passage of S. 210", "result": "Bill Passed", "yeas": 72, "nays": 21}, {"name": "The Windfall Profits Tax", "desc": "December 17, 1979. Carter is decontrolling oil prices; this is the price of the price: an excise tax on the industry's resulting windfall, projected in the hundreds of billions, funding energy aid for the poor and synthetic fuels. Oil-state senators call it confiscation of an industry the country needs drilling.", "votes": {"kennedy": "yea", "dole": "yea", "byrd": "yea", "lugar": "nay", "proxmire": "yea"}, "notes": {}, "date": "December 17, 1979", "question": "On Passage of H.R. 3919", "result": "Bill Passed", "yeas": 74, "nays": 24}, {"name": "The Chrysler Bailout", "desc": "December 19, 1979. Chrysler is weeks from collapse; the bill guarantees $1.5 billion in loans, conditioned on union wage concessions. Unprecedented, says nearly everyone \u2014 the argument is whether that's the objection or the point. Half a million jobs ride on the answer.", "votes": {"kennedy": "yea", "dole": "yea", "byrd": "yea", "lugar": "yea", "proxmire": "nay"}, "notes": {}, "date": "December 19, 1979", "question": "On Passage of H.R. 5860", "result": "Bill Passed", "yeas": 53, "nays": 44}]}]};